#[cfg(feature = "live-exec")]
fn resident_entry_cycle_error_can_retry(error: &RuntimeError) -> bool {
    match error {
        RuntimeError::LiveMarketData { message } => {
            message.starts_with("Public WSS monitor ")
                || message.starts_with("public market data GET failed")
                || message.starts_with("public market data POST failed")
                || message.starts_with("OKX returned code=50011")
                || message == "top-of-book prices must be greater than zero"
        }
        RuntimeError::Module {
            module: "arb-venue-data",
            message,
        } => {
            message.contains("freshness.ingested_at")
                || message.contains(
                    "ingested timestamp must be greater than or equal to observed timestamp",
                )
        }
        RuntimeError::Module {
            module: "arb-runtime",
            message,
        } => message.starts_with("funding arb monitor row is not a candidate: "),
        _ => false,
    }
}

#[cfg(feature = "live-exec")]
fn resident_entry_cycle_error_can_isolate_venue(error: &RuntimeError) -> bool {
    match error {
        RuntimeError::UnsafeConfig { message } => {
            message.contains("invalid mutable execution request")
                || message.contains("target_leverage")
                || message.contains("cannot be applied to spot")
        }
        RuntimeError::Module {
            module: "arb-venue-exec",
            message,
        } => {
            message.contains("invalid mutable execution request")
                || message.contains("target_leverage")
        }
        _ => false,
    }
}

#[cfg(feature = "live-exec")]
fn resident_retryable_error_class(error: &RuntimeError) -> &'static str {
    if !resident_entry_cycle_error_can_retry(error) {
        return "non_retryable";
    }
    match error {
        RuntimeError::LiveMarketData { message } => {
            if message.starts_with("Public WSS monitor ") {
                "wss_monitor_unavailable"
            } else if message.starts_with("public market data GET failed")
                || message.starts_with("public market data POST failed")
            {
                "public_rest_unavailable"
            } else if message.starts_with("OKX returned code=50011") {
                "okx_rate_limit"
            } else if message == "top-of-book prices must be greater than zero" {
                "invalid_top_of_book"
            } else {
                "live_market_data"
            }
        }
        RuntimeError::Module {
            module: "arb-venue-data",
            message,
        } if message.contains("freshness.ingested_at")
            || message.contains(
                "ingested timestamp must be greater than or equal to observed timestamp",
            ) =>
        {
            "private_snapshot_timestamp_skew"
        }
        RuntimeError::Module {
            module: "arb-runtime",
            message,
        } if message.starts_with("funding arb monitor row is not a candidate: ") => {
            "stale_funding_arb_candidate"
        }
        _ => "non_retryable",
    }
}

#[cfg(feature = "live-exec")]
fn resident_retryable_error_backoff(streak: u32) -> Duration {
    let multiplier = 1_u64 << streak.saturating_sub(1).min(5);
    let millis = RESIDENT_RETRYABLE_ERROR_BACKOFF_BASE_MS
        .saturating_mul(multiplier)
        .min(RESIDENT_RETRYABLE_ERROR_BACKOFF_MAX_MS);
    Duration::from_millis(millis)
}

#[cfg(feature = "live-exec")]
fn funding_arb_private_readonly_error_is_unavailable(error: &RuntimeError) -> bool {
    match error {
        RuntimeError::LiveMarketData { .. } => true,
        RuntimeError::Module {
            module: "arb-signing",
            message,
        } => {
            message.starts_with("signing secret source is unavailable")
                || message.starts_with("signing timestamp source is unavailable")
        }
        _ => false,
    }
}

#[cfg(feature = "live-exec")]
fn validate_multi_venue_basis_resident_live_options(
    options: &MultiVenueBasisResidentLiveOptions,
) -> RuntimeResult<()> {
    if options.venues.is_empty() {
        return Err(RuntimeError::UnsafeConfig {
            message: "multi-venue resident live requires at least one venue".to_owned(),
        });
    }
    if options.poll_interval_secs == 0 {
        return Err(RuntimeError::UnsafeConfig {
            message: "multi-venue resident live poll interval must be greater than zero".to_owned(),
        });
    }
    if matches!(options.max_cycles, Some(0)) {
        return Err(RuntimeError::UnsafeConfig {
            message: "multi-venue resident live max cycles must be greater than zero".to_owned(),
        });
    }
    if options.execute_live && !options.acknowledge_basis_live_orders {
        return Err(RuntimeError::UnsafeConfig {
            message: "缺少 --i-understand-basis-live-orders，拒绝启动多交易所 basis 常驻实盘"
                .to_owned(),
        });
    }
    if options.execute_live && options.poll_interval_secs < 10 {
        return Err(RuntimeError::UnsafeConfig {
            message:
                "multi-venue resident live poll interval must be at least 10 seconds in live mode"
                    .to_owned(),
        });
    }
    if options.max_concurrent_positions == 0 {
        return Err(RuntimeError::UnsafeConfig {
            message: "multi-venue resident live max concurrent positions must be greater than zero"
                .to_owned(),
        });
    }
    let max_total = Decimal::from_str(&options.max_total_notional_usdt)?;
    if max_total.is_negative() || max_total.is_zero() {
        return Err(RuntimeError::UnsafeConfig {
            message: "multi-venue resident live max total notional must be greater than zero"
                .to_owned(),
        });
    }
    if let Some(bps) = options.auto_price_guard_bps {
        validate_basis_auto_price_guard_bps(bps)?;
    }
    for (venue, url) in &options.opportunity_urls {
        if !options.venues.contains(venue) {
            return Err(RuntimeError::UnsafeConfig {
                message: format!(
                    "{} opportunity URL was configured but the venue is not enabled",
                    venue.label()
                ),
            });
        }
        if url.trim().is_empty() {
            return Err(RuntimeError::UnsafeConfig {
                message: format!("{} opportunity URL must not be empty", venue.label()),
            });
        }
    }
    for venue in &options.venues {
        let symbol = multi_venue_basis_symbol(options, *venue);
        match venue {
            BasisLiveVenue::Binance | BasisLiveVenue::Bybit | BasisLiveVenue::Bitget => {
                let _ = normalize_cex_usdt_basis_symbol(&symbol, venue.label())?;
            }
            BasisLiveVenue::Okx => {
                let _ = normalize_okx_usdt_basis_symbol(&symbol)?;
            }
        }
        if options.execute_live
            && (!options.spot_wss_monitor_urls.contains_key(venue)
                || !options.perp_wss_monitor_urls.contains_key(venue))
        {
            return Err(RuntimeError::UnsafeConfig {
                message: format!(
                    "真实 {} basis 常驻实盘必须提供 spot/perp WSS monitor URL",
                    venue.label()
                ),
            });
        }
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn acquire_multi_venue_basis_resident_live_lock(
    output_root: &Path,
) -> RuntimeResult<MultiVenueBasisResidentLiveLock> {
    let path = output_root.join("multi_venue_resident_live.lock");
    let mut file = fs::OpenOptions::new()
        .write(true)
        .create_new(true)
        .open(&path)
        .map_err(|error| {
            if error.kind() == std::io::ErrorKind::AlreadyExists {
                RuntimeError::UnsafeConfig {
                    message: format!(
                        "multi-venue resident live lock already exists at {}; another runner may be active",
                        path.display()
                    ),
                }
            } else {
                RuntimeError::Io {
                    path: path.clone(),
                    message: error.to_string(),
                }
            }
        })?;
    file.write_all(format!("created_at={}\n", current_utc_timestamp_string()).as_bytes())
        .map_err(|error| RuntimeError::Io {
            path: path.clone(),
            message: error.to_string(),
        })?;
    Ok(MultiVenueBasisResidentLiveLock { path })
}

