#[cfg(feature = "live-exec")]
fn execute_basis_live_dispatch<S, U>(
    dispatch_plan: &ExecutionDispatchPlan,
    spot_adapter: &mut S,
    usdm_adapter: &mut U,
    context: BasisLiveDispatchContext<'_>,
) -> RuntimeResult<BasisLiveExecutionOutcome>
where
    S: SubmitOrder + CancelOrder + ConfirmOrderStatus,
    U: SubmitOrder + CancelOrder + ConfirmOrderStatus,
{
    let (spot, perp) = basis_planned_legs(dispatch_plan, context.spot_market, context.perp_market)?;
    let spot_context = context.order_context(context.spot_market);
    let perp_context = context.order_context(context.perp_market);
    let mut outcome = BasisLiveExecutionOutcome::default();

    let spot_receipt = match spot_adapter.submit_order(spot.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot leg submit failed before perp leg; no hedge leg was sent: {error}"
            ));
            return Ok(outcome);
        }
    };

    let spot_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        spot_adapter,
        spot,
        &spot_receipt,
        "spot-after-submit",
        spot_context.private_order_events,
        spot_context.market,
        spot_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome
                .confirmations
                .push(private_confirmation_from_update(&spot.plan_leg_id, &update));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot leg was accepted but private confirmation failed; perp leg skipped: {error}"
            ));
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-confirmation-failed",
                spot_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "spot order state is unknown after accepted REST receipt; manual reconciliation is required",
            );
            return Ok(outcome);
        }
    };

    match spot_update.status {
        OrderConfirmationStatus::Filled => {}
        OrderConfirmationStatus::PartiallyFilled => {
            let filled = spot_update.cumulative_filled_quantity;
            outcome.blocking_reasons.push(
                "spot leg partially filled before hedge; perp leg skipped and protection path engaged"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-partial-fill",
                spot_context,
                &mut outcome,
            )?;
            if let Some(quantity) = filled.filter(|value| quantity_is_positive(*value)) {
                attempt_spot_unwind(
                    spot_adapter,
                    spot,
                    quantity,
                    context.spot_unwind_limit_price,
                    "spot-partial-fill",
                    spot_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "spot leg was only acknowledged and not filled; perp leg skipped and spot cancel requested"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-not-filled",
                spot_context,
                &mut outcome,
            )?;
            return Ok(outcome);
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            if private_order_update_has_positive_fill(&spot_update) {
                outcome.blocking_reasons.push(format!(
                    "spot leg reached terminal status `{}` with a positive fill before hedge; perp leg skipped and spot unwind submitted",
                    spot_update.status.as_str()
                ));
                if let Some(quantity) = private_order_update_positive_fill_quantity(&spot_update) {
                    attempt_spot_unwind(
                        spot_adapter,
                        spot,
                        quantity,
                        context.spot_unwind_limit_price,
                        "spot-terminal-positive-fill",
                        spot_context,
                        &mut outcome,
                    )?;
                } else {
                    outcome.protection.record_residual_risk(
                        "spot terminal update included fill evidence but no parseable filled quantity; manual unwind is required",
                    );
                }
                return Ok(outcome);
            }
            outcome.blocking_reasons.push(format!(
                "spot leg reached terminal non-filled status `{}`; perp leg skipped",
                spot_update.status.as_str()
            ));
            return Ok(outcome);
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "spot leg status is unknown after accepted REST receipt; perp leg skipped"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-unknown",
                spot_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "spot order state is unknown; do not assume either leg is flat until private reconciliation completes",
            );
            return Ok(outcome);
        }
    }

    let spot_filled_quantity = spot_update
        .cumulative_filled_quantity
        .unwrap_or(spot.request.quantity);
    let perp_submit_result = usdm_adapter.submit_order(perp.request.clone());
    let perp_receipt = match perp_submit_result {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome
                .blocking_reasons
                .push(format!("perp hedge submit failed after spot fill: {error}"));
            if binance_error_is_unknown_external_state(&error) {
                outcome.protection.record_residual_risk(
                    "perp submit result is unknown after spot fill; automatic unwind is suppressed to avoid flipping exposure",
                );
            } else {
                attempt_spot_unwind(
                    spot_adapter,
                    spot,
                    spot_filled_quantity,
                    context.spot_unwind_limit_price,
                    "perp-submit-failed",
                    spot_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
    };

    let perp_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        usdm_adapter,
        perp,
        &perp_receipt,
        "perp-after-submit",
        perp_context.private_order_events,
        perp_context.market,
        perp_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome
                .confirmations
                .push(private_confirmation_from_update(&perp.plan_leg_id, &update));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "perp hedge was accepted but private confirmation failed: {error}"
            ));
            outcome.protection.record_residual_risk(
                "perp hedge state is unknown after accepted REST receipt; manual reconciliation is required before unwind",
            );
            return Ok(outcome);
        }
    };

    match perp_update.status {
        OrderConfirmationStatus::Filled => {
            if let Some(plan) = context.plan {
                outcome.execution_report =
                    Some(arb_execution::execution_report_from_private_confirmations(
                        arb_execution::PrivateExecutionReportInput::new(
                            plan,
                            context.generated_at,
                            &outcome.confirmations,
                        ),
                    )?);
            }
        }
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "perp hedge partially filled after spot fill; cancelling hedge remainder and unwinding unmatched spot quantity"
                    .to_owned(),
            );
            let cancel_update = attempt_cancel_live_order(
                usdm_adapter,
                perp,
                &perp_receipt,
                "perp-partial-fill",
                perp_context,
                &mut outcome,
            )?;
            if cancel_update.is_some() {
                let perp_filled = cancel_update
                    .and_then(|update| update.cumulative_filled_quantity)
                    .or(perp_update.cumulative_filled_quantity);
                if let Some(unmatched) = unmatched_spot_quantity(spot_filled_quantity, perp_filled)
                    .filter(|quantity| quantity_is_positive(*quantity))
                {
                    attempt_spot_unwind(
                        spot_adapter,
                        spot,
                        unmatched,
                        context.spot_unwind_limit_price,
                        "perp-partial-fill",
                        spot_context,
                        &mut outcome,
                    )?;
                }
            } else {
                outcome.protection.record_residual_risk(
                    "perp partial hedge remainder was not confirmed cancelled; automatic spot unwind is suppressed to avoid flipping exposure",
                );
            }
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "perp hedge was only acknowledged and not filled; cancelling hedge and unwinding spot"
                    .to_owned(),
            );
            let cancel_update = attempt_cancel_live_order(
                usdm_adapter,
                perp,
                &perp_receipt,
                "perp-not-filled",
                perp_context,
                &mut outcome,
            )?;
            match cancel_update.as_ref().map(|update| update.status) {
                Some(OrderConfirmationStatus::Filled) => {}
                Some(OrderConfirmationStatus::PartiallyFilled) => {
                    if let Some(unmatched) = unmatched_spot_quantity(
                        spot_filled_quantity,
                        cancel_update.and_then(|update| update.cumulative_filled_quantity),
                    )
                    .filter(|quantity| quantity_is_positive(*quantity))
                    {
                        attempt_spot_unwind(
                            spot_adapter,
                            spot,
                            unmatched,
                            context.spot_unwind_limit_price,
                            "perp-not-filled",
                            spot_context,
                            &mut outcome,
                        )?;
                    }
                }
                Some(
                    OrderConfirmationStatus::Cancelled
                    | OrderConfirmationStatus::Rejected
                    | OrderConfirmationStatus::Expired,
                ) => {
                    attempt_spot_unwind(
                        spot_adapter,
                        spot,
                        spot_filled_quantity,
                        context.spot_unwind_limit_price,
                        "perp-not-filled",
                        spot_context,
                        &mut outcome,
                    )?;
                }
                Some(OrderConfirmationStatus::Acknowledged | OrderConfirmationStatus::Unknown)
                | None => {
                    outcome.protection.record_residual_risk(
                        "perp hedge was not confirmed terminal after cancel attempt; automatic spot unwind is suppressed",
                    );
                }
            }
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            if private_order_update_has_positive_fill(&perp_update) {
                outcome.blocking_reasons.push(format!(
                    "perp hedge reached terminal status `{}` with a positive fill after spot fill; unwinding unmatched spot quantity and recording residual position risk",
                    perp_update.status.as_str()
                ));
                if let Some(perp_filled) = private_order_update_positive_fill_quantity(&perp_update)
                {
                    if let Some(unmatched) =
                        unmatched_spot_quantity(spot_filled_quantity, Some(perp_filled))
                            .filter(|quantity| quantity_is_positive(*quantity))
                    {
                        attempt_spot_unwind(
                            spot_adapter,
                            spot,
                            unmatched,
                            context.spot_unwind_limit_price,
                            "perp-terminal-positive-fill",
                            spot_context,
                            &mut outcome,
                        )?;
                    }
                    outcome.protection.record_residual_risk(
                        "perp hedge terminal update included fills; manual reconciliation is required before treating the pair as durable",
                    );
                } else {
                    outcome.protection.record_residual_risk(
                        "perp hedge terminal update included fill evidence but no parseable filled quantity; manual reconciliation is required",
                    );
                }
                return Ok(outcome);
            }
            outcome.blocking_reasons.push(format!(
                "perp hedge reached terminal non-filled status `{}` after spot fill; unwinding spot",
                perp_update.status.as_str()
            ));
            attempt_spot_unwind(
                spot_adapter,
                spot,
                spot_filled_quantity,
                context.spot_unwind_limit_price,
                "perp-terminal-unfilled",
                spot_context,
                &mut outcome,
            )?;
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "perp hedge status is unknown after spot fill; no automatic unwind submitted"
                    .to_owned(),
            );
            outcome.protection.record_residual_risk(
                "perp hedge state is unknown; automatic spot unwind is suppressed to avoid flipping exposure",
            );
        }
    }

    Ok(outcome)
}

#[cfg(feature = "live-exec")]
fn execute_funding_arb_live_canary(
    dispatch_plan: &ExecutionDispatchPlan,
    options: &FundingArbGuardedLiveCanaryOnceOptions,
    signing_policy: &SigningPolicy,
    context: FundingLiveCanaryContext<'_>,
) -> RuntimeResult<BasisLiveExecutionOutcome> {
    let planned_legs = funding_planned_legs(dispatch_plan)?;
    let first = planned_legs[0];
    let second = planned_legs[1];
    let (mut first_adapter, first_market) =
        build_funding_perp_live_adapter(first, options, signing_policy)?;
    let (mut second_adapter, second_market) =
        build_funding_perp_live_adapter(second, options, signing_policy)?;
    execute_funding_arb_live_canary_dispatch(
        dispatch_plan,
        &mut first_adapter,
        &mut second_adapter,
        first_market,
        second_market,
        context,
    )
}

#[cfg(feature = "live-exec")]
fn execute_funding_arb_live_canary_dispatch<F, S>(
    dispatch_plan: &ExecutionDispatchPlan,
    first_adapter: &mut F,
    second_adapter: &mut S,
    first_market: PrivateOrderMarket,
    second_market: PrivateOrderMarket,
    context: FundingLiveCanaryContext<'_>,
) -> RuntimeResult<BasisLiveExecutionOutcome>
where
    F: SubmitOrder + CancelOrder + ConfirmOrderStatus,
    S: SubmitOrder + CancelOrder + ConfirmOrderStatus,
{
    let planned_legs = funding_planned_legs(dispatch_plan)?;
    let first = planned_legs[0];
    let second = planned_legs[1];
    let first_context = context.order_context(first_market);
    let second_context = context.order_context(second_market);
    let mut outcome = BasisLiveExecutionOutcome::default();

    let (first_receipt, first_update) = match first_adapter.submit_order(first.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            let update = match confirm_planned_receipt_with_private_stream_or_order_query(
                first_adapter,
                first,
                &receipt,
                "first-perp-after-submit",
                first_context.private_order_events,
                first_context.market,
                first_context.order_query_event_prefix,
            ) {
                Ok(update) => {
                    outcome.confirmations.push(private_confirmation_from_update(
                        &first.plan_leg_id,
                        &update,
                    ));
                    update
                }
                Err(error) => {
                    outcome.blocking_reasons.push(format!(
                        "first funding perp leg was accepted but private confirmation failed; second leg skipped: {error}"
                    ));
                    let _ = attempt_cancel_live_order(
                        first_adapter,
                        first,
                        &receipt,
                        "first-confirmation-failed",
                        first_context,
                        &mut outcome,
                    )?;
                    outcome.protection.record_residual_risk(
                        "first funding perp order state is unknown after accepted REST receipt; manual reconciliation is required",
                    );
                    return Ok(outcome);
                }
            };
            (Some(receipt), update)
        }
        Err(error) => {
            if !venue_exec_error_is_unknown_external_state(&error) {
                outcome.blocking_reasons.push(format!(
                    "first funding perp leg submit failed before second leg; no hedge leg was sent: {error}"
                ));
                return Ok(outcome);
            }
            let update = match confirm_unknown_submit_with_client_order_id(
                first_adapter,
                first,
                "first-perp-submit-unknown",
                first_context,
            ) {
                Ok(update) => {
                    outcome.primary_submit_receipt_count += 1;
                    outcome.confirmations.push(private_confirmation_from_update(
                        &first.plan_leg_id,
                        &update,
                    ));
                    update
                }
                Err(confirm_error) => {
                    outcome.blocking_reasons.push(format!(
                        "first funding perp leg submit result is unknown before second leg; no hedge leg was sent: {error}; private reconciliation failed: {confirm_error}"
                    ));
                    outcome.protection.record_residual_risk(
                        "first funding perp submit result is unknown before any opposing leg; manual reconciliation is required",
                    );
                    return Ok(outcome);
                }
            };
            (None, update)
        }
    };
    let first_order_ref = match &first_receipt {
        Some(receipt) => order_ref_from_receipt_or_client(first, receipt)?,
        None => client_order_ref_from_planned(first)?,
    };

    match first_update.status {
        OrderConfirmationStatus::Filled => {}
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "first funding perp leg partially filled before hedge; cancelling remainder and submitting reduce-only unwind"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order_ref(
                first_adapter,
                first,
                first_order_ref.clone(),
                "first-partial-fill",
                first_context,
                &mut outcome,
            )?;
            if let Some(quantity) = first_update
                .cumulative_filled_quantity
                .filter(|quantity| quantity_is_positive(*quantity))
            {
                let unwind_filled = attempt_funding_reduce_only_unwind(
                    first_adapter,
                    first,
                    quantity,
                    "first-partial-fill",
                    first_context,
                    &mut outcome,
                )?;
                mark_flat_after_successful_funding_unwind(&mut outcome, unwind_filled);
            }
            return Ok(outcome);
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "first funding perp leg was only acknowledged and not filled; second leg skipped and first cancel requested"
                    .to_owned(),
            );
            let cancel_update = attempt_cancel_live_order_ref(
                first_adapter,
                first,
                first_order_ref.clone(),
                "first-not-filled",
                first_context,
                &mut outcome,
            )?;
            if let Some(cancel_update) = cancel_update.as_ref() {
                handle_first_funding_perp_cancel_update_after_ack(
                    first_adapter,
                    first,
                    cancel_update,
                    first_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            handle_first_funding_perp_terminal_update(
                first_adapter,
                first,
                &first_update,
                first_context,
                &mut outcome,
            )?;
            return Ok(outcome);
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "first funding perp leg status is unknown after submit reconciliation; second leg skipped"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order_ref(
                first_adapter,
                first,
                first_order_ref,
                "first-unknown",
                first_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "first funding perp order state is unknown; do not assume the pair is flat until private reconciliation completes",
            );
            return Ok(outcome);
        }
    }

    let first_filled_quantity = first_update
        .cumulative_filled_quantity
        .unwrap_or(first.request.quantity);
    let second_receipt = match second_adapter.submit_order(second.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "second funding perp leg submit failed after first leg fill: {error}"
            ));
            if venue_exec_error_is_unknown_external_state(&error) {
                outcome.protection.record_residual_risk(
                    "second funding perp submit result is unknown after first fill; automatic unwind is suppressed to avoid flipping exposure",
                );
            } else {
                let unwind_filled = attempt_funding_reduce_only_unwind(
                    first_adapter,
                    first,
                    first_filled_quantity,
                    "second-submit-failed",
                    first_context,
                    &mut outcome,
                )?;
                mark_flat_after_successful_funding_unwind(&mut outcome, unwind_filled);
            }
            return Ok(outcome);
        }
    };

    let second_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        second_adapter,
        second,
        &second_receipt,
        "second-perp-after-submit",
        second_context.private_order_events,
        second_context.market,
        second_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome.confirmations.push(private_confirmation_from_update(
                &second.plan_leg_id,
                &update,
            ));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "second funding perp leg was accepted but private confirmation failed: {error}"
            ));
            outcome.protection.record_residual_risk(
                "second funding perp order state is unknown after accepted REST receipt; manual reconciliation is required before unwind",
            );
            return Ok(outcome);
        }
    };

    match second_update.status {
        OrderConfirmationStatus::Filled => {
            if let Some(plan) = context.plan {
                outcome.execution_report =
                    Some(arb_execution::execution_report_from_private_confirmations(
                        arb_execution::PrivateExecutionReportInput::new(
                            plan,
                            context.generated_at,
                            &outcome.confirmations,
                        ),
                    )?);
            }
        }
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "second funding perp leg partially filled; cancelling remainder and recording residual position risk"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                second_adapter,
                second,
                &second_receipt,
                "second-partial-fill",
                second_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "funding arb canary has a partial second leg; manual reconciliation and hedge adjustment are required",
            );
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "second funding perp leg was only acknowledged; cancelling second leg and unwinding first leg"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                second_adapter,
                second,
                &second_receipt,
                "second-not-filled",
                second_context,
                &mut outcome,
            )?;
            let unwind_filled = attempt_funding_reduce_only_unwind(
                first_adapter,
                first,
                first_filled_quantity,
                "second-not-filled",
                first_context,
                &mut outcome,
            )?;
            mark_flat_after_successful_funding_unwind(&mut outcome, unwind_filled);
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            if private_order_update_has_positive_fill(&second_update) {
                handle_second_funding_perp_terminal_positive_fill(
                    SecondFundingPerpTerminalPositiveFillInput {
                        first_adapter,
                        second_adapter,
                        first,
                        second,
                        first_filled_quantity,
                        second_update: &second_update,
                        first_context,
                        second_context,
                        outcome: &mut outcome,
                    },
                )?;
                return Ok(outcome);
            }
            outcome.blocking_reasons.push(format!(
                "second funding perp leg reached terminal non-filled status `{}`; unwinding first leg",
                second_update.status.as_str()
            ));
            let unwind_filled = attempt_funding_reduce_only_unwind(
                first_adapter,
                first,
                first_filled_quantity,
                "second-terminal-unfilled",
                first_context,
                &mut outcome,
            )?;
            mark_flat_after_successful_funding_unwind(&mut outcome, unwind_filled);
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "second funding perp leg status is unknown; automatic first-leg unwind is suppressed"
                    .to_owned(),
            );
            outcome.protection.record_residual_risk(
                "second funding perp state is unknown; manual reconciliation is required before any unwind",
            );
        }
    }

    Ok(outcome)
}

#[cfg(feature = "live-exec")]
fn funding_planned_legs(
    dispatch_plan: &ExecutionDispatchPlan,
) -> RuntimeResult<[&PlannedSubmitOrder; 2]> {
    if dispatch_plan.requests.len() != 2 {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "funding arb canary requires exactly two dispatch requests, got {}",
                dispatch_plan.requests.len()
            ),
        });
    }
    let first = dispatch_plan.requests.first().expect("length checked");
    let second = dispatch_plan.requests.get(1).expect("length checked");
    let long_count = dispatch_plan
        .requests
        .iter()
        .filter(|planned| planned.basis_leg_role.as_deref() == Some("perp_long"))
        .count();
    let short_count = dispatch_plan
        .requests
        .iter()
        .filter(|planned| planned.basis_leg_role.as_deref() == Some("perp_short"))
        .count();
    if long_count != 1 || short_count != 1 {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "funding arb canary requires one perp_long and one perp_short request, got long={long_count}, short={short_count}"
            ),
        });
    }
    Ok([first, second])
}

#[cfg(feature = "live-exec")]
fn handle_first_funding_perp_cancel_update_after_ack<A>(
    adapter: &mut A,
    first: &PlannedSubmitOrder,
    cancel_update: &PrivateOrderUpdate,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<()>
where
    A: SubmitOrder + ConfirmOrderStatus,
{
    if private_order_update_has_positive_fill(cancel_update) {
        outcome.blocking_reasons.push(format!(
            "first funding perp cancel confirmation returned `{}` with a positive fill before hedge; second leg skipped and reduce-only unwind submitted",
            cancel_update.status.as_str()
        ));
        unwind_first_funding_perp_positive_fill(
            adapter,
            first,
            cancel_update,
            "first-cancel-positive-fill",
            context,
            outcome,
        )?;
        return Ok(());
    }
    if cancel_update_confirms_flat_without_fill(cancel_update)
        && outcome.protection.residual_risk.is_none()
    {
        outcome.flat_after_cancel = true;
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn handle_first_funding_perp_terminal_update<A>(
    adapter: &mut A,
    first: &PlannedSubmitOrder,
    first_update: &PrivateOrderUpdate,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<()>
where
    A: SubmitOrder + ConfirmOrderStatus,
{
    if private_order_update_has_positive_fill(first_update) {
        outcome.blocking_reasons.push(format!(
            "first funding perp leg reached terminal status `{}` with a positive fill before hedge; second leg skipped and reduce-only unwind submitted",
            first_update.status.as_str()
        ));
        unwind_first_funding_perp_positive_fill(
            adapter,
            first,
            first_update,
            "first-terminal-positive-fill",
            context,
            outcome,
        )?;
        return Ok(());
    }
    outcome.blocking_reasons.push(format!(
        "first funding perp leg reached terminal non-filled status `{}`; second leg skipped",
        first_update.status.as_str()
    ));
    if cancel_update_confirms_flat_without_fill(first_update)
        && outcome.protection.residual_risk.is_none()
    {
        outcome.flat_after_cancel = true;
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn unwind_first_funding_perp_positive_fill<A>(
    adapter: &mut A,
    first: &PlannedSubmitOrder,
    update: &PrivateOrderUpdate,
    reason: &str,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<()>
where
    A: SubmitOrder + ConfirmOrderStatus,
{
    let Some(quantity) = private_order_update_positive_fill_quantity(update) else {
        outcome.protection.record_residual_risk(format!(
            "first funding perp order `{}` has positive fill evidence but no parseable filled quantity; manual close is required",
            first.plan_leg_id
        ));
        return Ok(());
    };
    let unwind_filled =
        attempt_funding_reduce_only_unwind(adapter, first, quantity, reason, context, outcome)?;
    mark_flat_after_successful_funding_unwind(outcome, unwind_filled);
    Ok(())
}

#[cfg(feature = "live-exec")]
struct SecondFundingPerpTerminalPositiveFillInput<'a, F, S> {
    first_adapter: &'a mut F,
    second_adapter: &'a mut S,
    first: &'a PlannedSubmitOrder,
    second: &'a PlannedSubmitOrder,
    first_filled_quantity: Quantity,
    second_update: &'a PrivateOrderUpdate,
    first_context: BasisOrderConfirmContext<'a>,
    second_context: BasisOrderConfirmContext<'a>,
    outcome: &'a mut BasisLiveExecutionOutcome,
}

#[cfg(feature = "live-exec")]
fn handle_second_funding_perp_terminal_positive_fill<F, S>(
    input: SecondFundingPerpTerminalPositiveFillInput<'_, F, S>,
) -> RuntimeResult<()>
where
    F: SubmitOrder + ConfirmOrderStatus,
    S: SubmitOrder + ConfirmOrderStatus,
{
    let SecondFundingPerpTerminalPositiveFillInput {
        first_adapter,
        second_adapter,
        first,
        second,
        first_filled_quantity,
        second_update,
        first_context,
        second_context,
        outcome,
    } = input;
    outcome.blocking_reasons.push(format!(
        "second funding perp leg reached terminal status `{}` with a positive fill; submitting reduce-only unwind for both filled legs",
        second_update.status.as_str()
    ));
    let Some(second_filled_quantity) = private_order_update_positive_fill_quantity(second_update)
    else {
        outcome.protection.record_residual_risk(format!(
            "second funding perp order `{}` has positive fill evidence but no parseable filled quantity; manual close is required",
            second.plan_leg_id
        ));
        return Ok(());
    };
    let first_unwind_filled = attempt_funding_reduce_only_unwind(
        first_adapter,
        first,
        first_filled_quantity,
        "second-terminal-positive-fill-first",
        first_context,
        outcome,
    )?;
    let second_unwind_filled = attempt_funding_reduce_only_unwind(
        second_adapter,
        second,
        second_filled_quantity,
        "second-terminal-positive-fill-second",
        second_context,
        outcome,
    )?;
    if first_unwind_filled && second_unwind_filled && outcome.protection.residual_risk.is_none() {
        outcome.flat_after_cancel = true;
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn mark_flat_after_successful_funding_unwind(
    outcome: &mut BasisLiveExecutionOutcome,
    unwind_filled: bool,
) {
    if unwind_filled && outcome.protection.residual_risk.is_none() {
        outcome.flat_after_cancel = true;
    }
}

