/// 运行跨交易所 funding arb 专用 observer。
///
/// 中文说明：该 observer 只读取本机 basis monitor 的公开 JSON 快照，将六个 venue
/// 的 perp funding 数据聚合成跨所 pair 机会。缺报价、缺盘口数量或上游状态未知时
/// 都按非候选处理，并在 `source_status`/`reason` 中保留原因。
pub fn run_funding_arb_monitor(options: FundingArbMonitorOptions) -> RuntimeResult<()> {
    validate_funding_arb_monitor_options(&options)?;
    let state = Arc::new(RwLock::new(FundingArbMonitorSnapshot::empty(&options)));
    if !options.once {
        let context = Arc::new(FundingArbDashboardContext {
            execution_reports_path: options.execution_reports_path.clone(),
            resident_events_path: options.resident_events_path.clone(),
            opportunity_history_path: options.opportunity_history_path.clone(),
            exchange_pnl_config_path: options.exchange_pnl_config_path.clone(),
            exchange_pnl_hyperliquid_user: options.exchange_pnl_hyperliquid_user.clone(),
            exchange_pnl_hyperliquid_source: options.exchange_pnl_hyperliquid_source.clone(),
            exchange_pnl_hyperliquid_vault_address: options
                .exchange_pnl_hyperliquid_vault_address
                .clone(),
            exchange_pnl_hyperliquid_expires_after_ms: options
                .exchange_pnl_hyperliquid_expires_after_ms,
            exchange_pnl_hyperliquid_asset_ids: options.exchange_pnl_hyperliquid_asset_ids.clone(),
            exchange_pnl_aster_user: options.exchange_pnl_aster_user.clone(),
            exchange_pnl_aster_signer: options.exchange_pnl_aster_signer.clone(),
            exchange_pnl_aster_signer_cmd_env: options.exchange_pnl_aster_signer_cmd_env.clone(),
        });
        start_funding_arb_http_api(&options.bind_addr, state.clone(), context)?;
        println!(
            "funding-arb-monitor: api=http://{} poll_interval_secs={} min_net_funding_bps={} mutable_execution_started=false",
            options.bind_addr, options.poll_interval_secs, options.min_net_funding_bps
            );
    }

    let mut direct_source_cache = FundingArbDirectSourceCache::default();
    loop {
        match fetch_funding_arb_monitor_snapshot_with_cache(&options, &mut direct_source_cache) {
            Ok(snapshot) => {
                if let Some(dir) = &options.output_dir {
                    write_funding_arb_monitor_snapshot(dir, &snapshot)?;
                }
                *state.write().expect("monitor state lock poisoned") = snapshot;
            }
            Err(error) => {
                if options.once {
                    return Err(error);
                }
                let mut snapshot = state.write().expect("monitor state lock poisoned");
                snapshot.status = "degraded".to_owned();
                snapshot.last_error = Some(error.to_string());
                snapshot.updated_at = current_utc_timestamp()
                    .map(|timestamp| timestamp.to_string())
                    .unwrap_or_else(|_| "unknown".to_owned());
            }
        }

        if options.once {
            break;
        }
        thread::sleep(Duration::from_secs(options.poll_interval_secs));
    }
    Ok(())
}

