fn validate_funding_arb_monitor_options(options: &FundingArbMonitorOptions) -> RuntimeResult<()> {
    if options.poll_interval_secs == 0 {
        return Err(cli_arg_error("poll interval must be greater than zero"));
    }
    if options.sources.len() < 2 {
        return Err(cli_arg_error(
            "funding-arb-monitor requires at least two venue sources",
        ));
    }
    let notional = MonitorDecimal::parse("notional_usd", &options.notional_usd)?;
    if notional.raw <= 0 {
        return Err(cli_arg_error(
            "funding-arb-monitor notional_usd must be greater than zero",
        ));
    }
    let taker_fee_bps = MonitorDecimal::parse("taker_fee_bps", &options.taker_fee_bps)?;
    if taker_fee_bps.raw < 0
        || options.slippage_buffer_bps < 0
        || options.max_entry_price_divergence_bps < 0
        || options.min_net_funding_bps < 0
    {
        return Err(cli_arg_error(
            "funding-arb-monitor bps values must be non-negative",
        ));
    }
    if options.funding_carry_modes.is_empty() {
        return Err(cli_arg_error(
            "funding-arb-monitor requires at least one funding carry mode",
        ));
    }
    let mut normalized_modes = BTreeSet::new();
    for mode in &options.funding_carry_modes {
        let Some(normalized) = normalize_funding_carry_mode(mode) else {
            return Err(cli_arg_error(format!(
                "unsupported funding carry mode `{mode}`; supported modes are spot_perp, perp_perp, perp_perp_staggered",
            )));
        };
        normalized_modes.insert(normalized);
    }
    if !normalized_modes.contains(FUNDING_CARRY_MODE_PERP_PERP)
        && !normalized_modes.contains(FUNDING_CARRY_MODE_PERP_PERP_STAGGERED)
    {
        return Err(cli_arg_error(
            "funding-arb-monitor needs perp_perp or perp_perp_staggered; spot_perp is served by basis monitors",
        ));
    }
    if options
        .execution_reports_path
        .as_ref()
        .is_some_and(|path| path.as_os_str().is_empty())
        || options
            .resident_events_path
            .as_ref()
            .is_some_and(|path| path.as_os_str().is_empty())
        || options
            .opportunity_history_path
            .as_ref()
            .is_some_and(|path| path.as_os_str().is_empty())
        || options
            .exchange_pnl_config_path
            .as_ref()
            .is_some_and(|path| path.as_os_str().is_empty())
    {
        return Err(cli_arg_error(
            "funding-arb-monitor path options cannot be empty",
        ));
    }
    let mut seen = BTreeSet::new();
    for source in &options.sources {
        let family = normalize_venue_family(&source.venue_family);
        if arb_venue_capability_profile(&family).is_none() {
            return Err(cli_arg_error(format!(
                "unsupported funding-arb-monitor venue `{}`",
                source.venue_family
            )));
        }
        if !seen.insert(family) {
            return Err(cli_arg_error("duplicate funding-arb-monitor venue source"));
        }
        if source.status_url.trim().is_empty() {
            return Err(cli_arg_error(
                "funding-arb-monitor source URL cannot be empty",
            ));
        }
    }
    Ok(())
}

fn validate_basis_monitor_values(
    poll_interval_secs: u64,
    min_abs_funding_rate: &str,
    notional_usd: &str,
) -> RuntimeResult<()> {
    if poll_interval_secs == 0 {
        return Err(cli_arg_error("poll interval must be greater than zero"));
    }
    MonitorDecimal::parse("min_abs_funding_rate", min_abs_funding_rate)?;
    MonitorDecimal::parse("notional_usd", notional_usd)?;
    Ok(())
}

fn validate_basis_monitor_fee_values(
    spot_taker_fee_bps: &str,
    perp_taker_fee_bps: &str,
) -> RuntimeResult<()> {
    let spot_fee = MonitorDecimal::parse("spot_taker_fee_bps", spot_taker_fee_bps)?;
    let perp_fee = MonitorDecimal::parse("perp_taker_fee_bps", perp_taker_fee_bps)?;
    if spot_fee.raw < 0 || perp_fee.raw < 0 {
        return Err(cli_arg_error(
            "basis monitor fee bps values must be non-negative",
        ));
    }
    Ok(())
}

fn runtime_non_negative_u64_env(env_name: &'static str, default_value: u64) -> RuntimeResult<u64> {
    let Ok(raw) = std::env::var(env_name) else {
        return Ok(default_value);
    };
    parse_runtime_non_negative_u64(env_name, raw.trim())
}

fn parse_runtime_non_negative_u64(env_name: &'static str, raw: &str) -> RuntimeResult<u64> {
    raw.trim()
        .parse::<u64>()
        .map_err(|_| RuntimeError::UnsafeConfig {
            message: format!("{env_name} must be a non-negative integer"),
        })
}

fn runtime_positive_usize_env(
    env_name: &'static str,
    default_value: usize,
) -> RuntimeResult<usize> {
    let Ok(raw) = std::env::var(env_name) else {
        return Ok(default_value);
    };
    parse_runtime_positive_usize(env_name, raw.trim())
}

fn parse_runtime_positive_usize(env_name: &'static str, raw: &str) -> RuntimeResult<usize> {
    let value = raw
        .trim()
        .parse::<usize>()
        .map_err(|_| RuntimeError::UnsafeConfig {
            message: format!("{env_name} must be a positive integer"),
        })?;
    if value == 0 {
        return Err(RuntimeError::UnsafeConfig {
            message: format!("{env_name} must be a positive integer"),
        });
    }
    Ok(value)
}

fn runtime_bool_env(env_name: &'static str, default_value: bool) -> RuntimeResult<bool> {
    let Ok(raw) = std::env::var(env_name) else {
        return Ok(default_value);
    };
    match raw.trim().to_ascii_lowercase().as_str() {
        "1" | "true" | "yes" | "on" => Ok(true),
        "0" | "false" | "no" | "off" => Ok(false),
        _ => Err(RuntimeError::UnsafeConfig {
            message: format!("{env_name} must be 0/1 or true/false"),
        }),
    }
}

