#[allow(clippy::too_many_arguments)]
fn build_aster_basis_monitor_snapshot_from_optional_spot_json_with_depth(
    spot_json: Option<&str>,
    perp_json: &str,
    premium_json: &str,
    funding_info_json: Option<&str>,
    options: &AsterBasisMonitorOptions,
    spot_depths: &BTreeMap<String, PublicOrderBookDepth>,
    perp_depths: &BTreeMap<String, PublicOrderBookDepth>,
    mut warnings: Vec<String>,
) -> RuntimeResult<AsterBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = match spot_json {
        Some(spot_json) => parse_book_ticker_rows(spot_json, "aster spot")?
            .into_iter()
            .map(|row| (row.symbol.clone(), row))
            .collect::<BTreeMap<_, _>>(),
        None => BTreeMap::new(),
    };
    let perp_books = parse_book_ticker_rows(perp_json, "aster perp")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let premiums = parse_premium_index_rows(premium_json)?;
    let funding_intervals = funding_info_json
        .map(|json| parse_funding_interval_info_map(json, "aster futures fundingInfo"))
        .unwrap_or_else(|| Ok(BTreeMap::new()))?;
    let perp_wss_quotes = match options.perp_wss_monitor_url.as_deref() {
        Some(url) => match fetch_public_wss_monitor_quote_map_for_basis(
            url,
            "/api/aster-wss-book-ticker",
            AsterPublicWssMarket::UsdtFutures.as_str(),
        ) {
            Ok(quotes) => Some(quotes),
            Err(error) => {
                warnings.push(format!(
                    "Aster perp WSS monitor unavailable; using REST perp top-of-book fallback: {error}"
                ));
                None
            }
        },
        None => None,
    };

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;
    let mut missing_wss_quote_count = 0_usize;
    let mut unusable_wss_quote_count = 0_usize;

    for premium in premiums {
        if !premium.symbol.ends_with("USDT") || premium.symbol.starts_with("TEST") {
            continue;
        }
        let funding_rate = MonitorDecimal::parse("lastFundingRate", &premium.last_funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            filtered_funding_count += 1;
            continue;
        }

        let spot = spot_books.get(&premium.symbol);
        let perp_wss_row = match perp_wss_quotes.as_ref() {
            Some(wss_quotes) => match wss_quotes.quotes.get(&premium.symbol) {
                Some(quote) => {
                    match public_wss_quote_to_monitor_book_ticker_row(
                        quote,
                        &wss_quotes.monitor_ref,
                        &premium.symbol,
                        AsterPublicWssMarket::UsdtFutures.venue_id(),
                        &format!("inst:ASTER:{}:USDT-FUTURES", premium.symbol),
                        wss_quotes.fetched_at,
                    ) {
                        Ok(row) => Some(row),
                        Err(_) => {
                            unusable_wss_quote_count += 1;
                            None
                        }
                    }
                }
                None => {
                    missing_wss_quote_count += 1;
                    None
                }
            },
            None => None,
        };
        let perp = perp_wss_row
            .as_ref()
            .or_else(|| perp_books.get(&premium.symbol));
        let (source_status, reason) = match (spot, perp) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_ASTER_SPOT_BOOK_TICKER".to_owned()),
                )
            }
            (Some(_), None) => {
                missing_perp_count += 1;
                (
                    "missing_perp".to_owned(),
                    Some("MISSING_ASTER_PERP_BOOK_TICKER".to_owned()),
                )
            }
            (None, None) => {
                missing_spot_count += 1;
                missing_perp_count += 1;
                (
                    "missing_spot_and_perp".to_owned(),
                    Some("MISSING_ASTER_SPOT_AND_PERP_BOOK_TICKER".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal: Option<SpotPerpBasisSignal> = match (spot, perp) {
            (Some(_), Some(_)) => {
                // Aster spot-perp basis is observed for market health only; executable dry-run
                // profiles are not enabled, while perp/funding fields must stay usable by funding arb.
                signal_error = Some("ASTER_SPOT_PERP_BASIS_DRY_RUN_NOT_SUPPORTED".to_owned());
                None
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);
        let funding_interval_hours = funding_interval_hours_for_symbol(
            "aster",
            &premium.symbol,
            premium.funding_interval_hours.clone(),
            &funding_intervals,
        )?;

        rows.push(AsterBasisMarketRow {
            symbol: premium.symbol,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            spot_bid_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.symbol)
                        .map(|depth| depth.bid_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.bid_price, &row.bid_qty)
                        })
                })
                .unwrap_or_default(),
            spot_ask_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.symbol)
                        .map(|depth| depth.ask_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.ask_price, &row.ask_qty)
                        })
                })
                .unwrap_or_default(),
            perp_bid: perp.map(|row| row.bid_price.clone()),
            perp_ask: perp.map(|row| row.ask_price.clone()),
            perp_bid_qty: perp.map(|row| row.bid_qty.clone()),
            perp_ask_qty: perp.map(|row| row.ask_qty.clone()),
            perp_bid_depth: perp
                .map(|row| {
                    perp_depths
                        .get(&row.symbol)
                        .map(|depth| depth.bid_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.bid_price, &row.bid_qty)
                        })
                })
                .unwrap_or_default(),
            perp_ask_depth: perp
                .map(|row| {
                    perp_depths
                        .get(&row.symbol)
                        .map(|depth| depth.ask_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.ask_price, &row.ask_qty)
                        })
                })
                .unwrap_or_default(),
            mark_price: premium.mark_price,
            index_price: premium.index_price,
            last_funding_rate: premium.last_funding_rate,
            funding_interval_hours,
            next_funding_time_ms: premium.next_funding_time_ms,
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();
    if missing_wss_quote_count > 0 {
        warnings.push(format!(
            "Aster perp WSS monitor lacked quotes for {missing_wss_quote_count} symbols; used REST fallback where available"
        ));
    }
    if unusable_wss_quote_count > 0 {
        warnings.push(format!(
            "Aster perp WSS monitor had {unusable_wss_quote_count} unusable quote rows; used REST fallback where available"
        ));
    }

    Ok(AsterBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: (!warnings.is_empty()).then(|| warnings.join("; ")),
        rows,
    })
}

fn aster_basis_monitor_depth_symbols(
    spot_json: Option<&str>,
    perp_json: &str,
    premium_json: &str,
    options: &AsterBasisMonitorOptions,
) -> RuntimeResult<BTreeSet<String>> {
    aster_basis_monitor_depth_symbols_with_limit(
        spot_json,
        perp_json,
        premium_json,
        options,
        BASIS_MONITOR_DEPTH_SYMBOL_LIMIT,
    )
}

fn aster_basis_monitor_depth_symbols_with_limit(
    spot_json: Option<&str>,
    perp_json: &str,
    premium_json: &str,
    options: &AsterBasisMonitorOptions,
    limit: usize,
) -> RuntimeResult<BTreeSet<String>> {
    let Some(spot_json) = spot_json else {
        return Ok(BTreeSet::new());
    };
    if limit == 0 {
        return Ok(BTreeSet::new());
    }
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_book_ticker_rows(spot_json, "aster spot")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let perp_books = parse_book_ticker_rows(perp_json, "aster perp")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let mut scored_symbols = Vec::new();
    for premium in parse_premium_index_rows(premium_json)? {
        if !premium.symbol.ends_with("USDT") || premium.symbol.starts_with("TEST") {
            continue;
        }
        let Some(spot) = spot_books.get(&premium.symbol) else {
            continue;
        };
        let Some(perp) = perp_books.get(&premium.symbol) else {
            continue;
        };
        let funding_rate = MonitorDecimal::parse("lastFundingRate", &premium.last_funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            continue;
        }
        let Ok(signal) = evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
            symbol: premium.symbol.clone(),
            spot_best_bid: spot.bid_price.clone(),
            spot_best_ask: spot.ask_price.clone(),
            spot_ask_size: Some(spot.ask_qty.clone()),
            spot_ask_depth: spot.ask_depth.clone(),
            perp_best_bid: perp.bid_price.clone(),
            perp_best_ask: perp.ask_price.clone(),
            perp_bid_size: Some(perp.bid_qty.clone()),
            perp_bid_depth: perp.bid_depth.clone(),
            last_funding_rate: premium.last_funding_rate,
            notional_usd: options.notional_usd.clone(),
            spot_taker_fee_bps: options.spot_taker_fee_bps.clone(),
            perp_taker_fee_bps: options.perp_taker_fee_bps.clone(),
            slippage_buffer_bps: options.slippage_buffer_bps,
            min_net_bps: options.min_net_bps,
        }) else {
            continue;
        };
        if !basis_monitor_signal_should_fetch_depth(&signal, options.min_net_bps) {
            continue;
        }
        scored_symbols.push((
            signal_bps_sort_key(&signal.expected_profit_bps),
            signal_bps_sort_key(&signal.net_bps),
            funding_rate.raw.checked_abs().unwrap_or(i128::MAX),
            premium.symbol,
        ));
    }
    Ok(top_scored_basis_depth_symbols(scored_symbols, limit))
}

fn fetch_bybit_basis_monitor_snapshot_with_cache(
    options: &BybitBasisMonitorOptions,
    instrument_cache: &mut BybitLinearInstrumentPageCache,
) -> RuntimeResult<BybitBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&bybit_spot_tickers_url())?;
    let linear_json = fetch_public_json_with_curl(&bybit_linear_tickers_url())?;
    let instrument_pages = fetch_bybit_linear_instrument_pages_cached(instrument_cache)?;
    let parsed = parse_bybit_basis_monitor_inputs(&spot_json, &linear_json, &instrument_pages)?;
    let depth_symbols = bybit_basis_monitor_depth_symbols_from_parsed(&parsed, options)?;
    let spot_depths =
        fetch_public_order_book_depth_map(PublicOrderBookDepthVenue::BybitSpot, &depth_symbols);
    let linear_depths =
        fetch_public_order_book_depth_map(PublicOrderBookDepthVenue::BybitLinear, &depth_symbols);
    let warnings = spot_depths
        .warnings
        .into_iter()
        .chain(linear_depths.warnings)
        .collect::<Vec<_>>();
    build_bybit_basis_monitor_snapshot_from_parsed_with_depth(
        &parsed,
        options,
        &spot_depths.depths,
        &linear_depths.depths,
        warnings,
    )
}

fn parse_bybit_basis_monitor_inputs(
    spot_json: &str,
    linear_json: &str,
    instrument_pages: &[String],
) -> RuntimeResult<BybitBasisMonitorParsedInputs> {
    let instrument_metadata = parse_bybit_linear_perpetual_instrument_metadata(instrument_pages)?;
    Ok(BybitBasisMonitorParsedInputs {
        spot_books: parse_bybit_spot_ticker_rows(spot_json)?
            .into_iter()
            .map(|row| (row.symbol.clone(), row))
            .collect(),
        linear_tickers: parse_bybit_linear_ticker_rows(linear_json)?
            .into_iter()
            .map(|row| (row.symbol.clone(), row))
            .collect(),
        linear_symbols: instrument_metadata.symbols,
        linear_funding_intervals: instrument_metadata.funding_intervals,
    })
}

fn fetch_bybit_linear_instrument_pages() -> RuntimeResult<Vec<String>> {
    let mut pages = Vec::new();
    let mut cursor = None::<String>;
    let mut seen_cursors = BTreeSet::new();
    loop {
        let url = bybit_linear_instruments_info_url(cursor.as_deref());
        let json = fetch_public_json_with_curl(&url)?;
        let next_cursor = bybit_response_next_page_cursor(&json, "bybit linear instruments")?;
        pages.push(json);
        let Some(next_cursor) = next_cursor.filter(|value| !value.trim().is_empty()) else {
            break;
        };
        if !seen_cursors.insert(next_cursor.clone()) {
            return Err(RuntimeError::LiveMarketData {
                message: format!("Bybit instruments pagination repeated cursor `{next_cursor}`"),
            });
        }
        cursor = Some(next_cursor);
    }
    Ok(pages)
}

fn fetch_bybit_linear_instrument_pages_cached(
    cache: &mut BybitLinearInstrumentPageCache,
) -> RuntimeResult<Vec<String>> {
    let ttl = bybit_linear_instrument_cache_ttl()?;
    let now = Instant::now();
    if ttl > Duration::ZERO {
        if let Some(fetched_at) = cache.fetched_at {
            if now.duration_since(fetched_at) < ttl && !cache.pages.is_empty() {
                return Ok(cache.pages.clone());
            }
        }
    }

    let pages = fetch_bybit_linear_instrument_pages()?;
    if ttl > Duration::ZERO && !pages.is_empty() {
        cache.fetched_at = Some(now);
        cache.pages = pages.clone();
    }
    Ok(pages)
}

