fn build_bybit_basis_monitor_snapshot_from_parsed_with_depth(
    parsed: &BybitBasisMonitorParsedInputs,
    options: &BybitBasisMonitorOptions,
    spot_depths: &BTreeMap<String, PublicOrderBookDepth>,
    linear_depths: &BTreeMap<String, PublicOrderBookDepth>,
    warnings: Vec<String>,
) -> RuntimeResult<BybitBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for symbol in &parsed.linear_symbols {
        let linear = parsed.linear_tickers.get(symbol);
        if let Some(linear) = linear {
            let funding_rate = MonitorDecimal::parse("fundingRate", &linear.last_funding_rate)?;
            if funding_rate.abs_less_than(min_abs_funding_rate) {
                filtered_funding_count += 1;
                continue;
            }
        }

        let spot = parsed.spot_books.get(symbol);
        let (mut source_status, reason) = match (spot, linear) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_SPOT_TICKER".to_owned()),
                )
            }
            (Some(_), None) => {
                missing_perp_count += 1;
                (
                    "missing_perp".to_owned(),
                    Some("MISSING_LINEAR_PERP_TICKER".to_owned()),
                )
            }
            (None, None) => {
                missing_spot_count += 1;
                missing_perp_count += 1;
                (
                    "missing_spot_and_perp".to_owned(),
                    Some("MISSING_SPOT_AND_LINEAR_PERP_TICKER".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, linear) {
            (Some(spot), Some(linear)) => {
                let spot_ask_depth = spot_depths
                    .get(symbol)
                    .map(|depth| depth.ask_depth.clone())
                    .unwrap_or_else(|| {
                        signal_depth_from_top_strings(&spot.ask_price, &spot.ask_qty)
                    });
                let perp_bid_depth = linear_depths
                    .get(symbol)
                    .map(|depth| depth.bid_depth.clone())
                    .unwrap_or_else(|| {
                        signal_depth_from_top_strings(&linear.bid_price, &linear.bid_qty)
                    });
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: symbol.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    spot_ask_depth,
                    perp_best_bid: linear.bid_price.clone(),
                    perp_best_ask: linear.ask_price.clone(),
                    perp_bid_size: Some(linear.bid_qty.clone()),
                    perp_bid_depth,
                    last_funding_rate: linear.last_funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps.clone(),
                    perp_taker_fee_bps: options.perp_taker_fee_bps.clone(),
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(BybitBasisMarketRow {
            symbol: symbol.clone(),
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            spot_bid_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.symbol)
                        .map(|depth| depth.bid_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.bid_price, &row.bid_qty)
                        })
                })
                .unwrap_or_default(),
            spot_ask_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.symbol)
                        .map(|depth| depth.ask_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.ask_price, &row.ask_qty)
                        })
                })
                .unwrap_or_default(),
            perp_bid: linear.map(|row| row.bid_price.clone()),
            perp_ask: linear.map(|row| row.ask_price.clone()),
            perp_bid_qty: linear.map(|row| row.bid_qty.clone()),
            perp_ask_qty: linear.map(|row| row.ask_qty.clone()),
            perp_bid_depth: linear
                .map(|row| {
                    linear_depths
                        .get(&row.symbol)
                        .map(|depth| depth.bid_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.bid_price, &row.bid_qty)
                        })
                })
                .unwrap_or_default(),
            perp_ask_depth: linear
                .map(|row| {
                    linear_depths
                        .get(&row.symbol)
                        .map(|depth| depth.ask_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.ask_price, &row.ask_qty)
                        })
                })
                .unwrap_or_default(),
            mark_price: linear.map(|row| row.mark_price.clone()).unwrap_or_default(),
            index_price: linear
                .map(|row| row.index_price.clone())
                .unwrap_or_default(),
            last_funding_rate: linear
                .map(|row| row.last_funding_rate.clone())
                .unwrap_or_default(),
            funding_interval_hours: funding_interval_hours_for_symbol(
                "bybit",
                symbol,
                linear.and_then(|row| row.funding_interval_hours.clone()),
                &parsed.linear_funding_intervals,
            )?,
            next_funding_time_ms: linear
                .map(|row| row.next_funding_time_ms.clone())
                .unwrap_or_default(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(BybitBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: (!warnings.is_empty()).then(|| warnings.join("; ")),
        rows,
    })
}

fn bybit_basis_monitor_depth_symbols_from_parsed(
    parsed: &BybitBasisMonitorParsedInputs,
    options: &BybitBasisMonitorOptions,
) -> RuntimeResult<BTreeSet<String>> {
    bybit_basis_monitor_depth_symbols_from_parsed_with_limit(
        parsed,
        options,
        BASIS_MONITOR_DEPTH_SYMBOL_LIMIT,
    )
}

fn bybit_basis_monitor_depth_symbols_from_parsed_with_limit(
    parsed: &BybitBasisMonitorParsedInputs,
    options: &BybitBasisMonitorOptions,
    limit: usize,
) -> RuntimeResult<BTreeSet<String>> {
    if limit == 0 {
        return Ok(BTreeSet::new());
    }
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let mut scored_symbols = Vec::new();
    for symbol in &parsed.linear_symbols {
        let Some(spot) = parsed.spot_books.get(symbol) else {
            continue;
        };
        let Some(linear) = parsed.linear_tickers.get(symbol) else {
            continue;
        };
        let funding_rate = MonitorDecimal::parse("fundingRate", &linear.last_funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            continue;
        }
        let Ok(signal) = evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
            symbol: symbol.clone(),
            spot_best_bid: spot.bid_price.clone(),
            spot_best_ask: spot.ask_price.clone(),
            spot_ask_size: Some(spot.ask_qty.clone()),
            spot_ask_depth: spot.ask_depth.clone(),
            perp_best_bid: linear.bid_price.clone(),
            perp_best_ask: linear.ask_price.clone(),
            perp_bid_size: Some(linear.bid_qty.clone()),
            perp_bid_depth: linear.bid_depth.clone(),
            last_funding_rate: linear.last_funding_rate.clone(),
            notional_usd: options.notional_usd.clone(),
            spot_taker_fee_bps: options.spot_taker_fee_bps.clone(),
            perp_taker_fee_bps: options.perp_taker_fee_bps.clone(),
            slippage_buffer_bps: options.slippage_buffer_bps,
            min_net_bps: options.min_net_bps,
        }) else {
            continue;
        };
        if !basis_monitor_signal_should_fetch_depth(&signal, options.min_net_bps) {
            continue;
        }
        scored_symbols.push((
            signal_bps_sort_key(&signal.expected_profit_bps),
            signal_bps_sort_key(&signal.net_bps),
            funding_rate.raw.checked_abs().unwrap_or(i128::MAX),
            symbol.clone(),
        ));
    }
    Ok(top_scored_basis_depth_symbols(scored_symbols, limit))
}

fn fetch_okx_basis_monitor_snapshot_with_cache(
    options: &OkxBasisMonitorOptions,
    cache: &mut OkxBasisMonitorCache,
) -> RuntimeResult<OkxBasisMonitorSnapshot> {
    let timing_log = okx_basis_timing_log_enabled()?;
    let cycle_start = Instant::now();

    let spot_start = Instant::now();
    let spot_json = fetch_public_json_with_curl(&okx_tickers_url("SPOT"))?;
    let spot_ms = spot_start.elapsed().as_millis();

    let swap_start = Instant::now();
    let swap_json = fetch_public_json_with_curl(&okx_tickers_url("SWAP"))?;
    let swap_ms = swap_start.elapsed().as_millis();

    let mark_start = Instant::now();
    let mark_json = fetch_public_json_with_curl(&okx_mark_price_url())?;
    let mark_ms = mark_start.elapsed().as_millis();

    let index_start = Instant::now();
    let index_json = fetch_public_json_with_curl(&okx_index_tickers_url())?;
    let index_ms = index_start.elapsed().as_millis();

    let swap_rows = parse_okx_ticker_rows(&swap_json, "okx swap tickers")?;

    let funding_start = Instant::now();
    let funding_pages =
        fetch_okx_usdt_swap_funding_rate_pages_cached(&swap_rows, &mut cache.funding_rates)?;
    let funding_ms = funding_start.elapsed().as_millis();

    let parse_start = Instant::now();
    let parsed = parse_okx_basis_monitor_inputs_from_swap_rows(
        &spot_json,
        swap_rows,
        &mark_json,
        &index_json,
        &funding_pages.pages,
    )?;
    let parse_ms = parse_start.elapsed().as_millis();

    let depth_symbols = okx_basis_monitor_depth_symbols_from_parsed(&parsed, options)?;
    let depth_ttl = okx_depth_cache_ttl()?;
    let depth_concurrency = okx_depth_fetch_concurrency()?;
    let depth_start = Instant::now();
    let spot_depths = fetch_public_order_book_depth_map_cached(
        PublicOrderBookDepthVenue::Okx,
        &depth_symbols.spot,
        &mut cache.spot_depths,
        depth_ttl,
        depth_concurrency,
    );
    let swap_depths = fetch_public_order_book_depth_map_cached(
        PublicOrderBookDepthVenue::Okx,
        &depth_symbols.swap,
        &mut cache.swap_depths,
        depth_ttl,
        depth_concurrency,
    );
    let depth_ms = depth_start.elapsed().as_millis();
    let depth_cached_count = spot_depths.cached_count + swap_depths.cached_count;
    let depth_refreshed_count = spot_depths.refreshed_count + swap_depths.refreshed_count;
    let depth_symbol_count = depth_symbols.spot.len() + depth_symbols.swap.len();
    let depth_warnings = spot_depths
        .warnings
        .into_iter()
        .chain(swap_depths.warnings)
        .collect::<Vec<_>>();

    let build_start = Instant::now();
    let mut snapshot = build_okx_basis_monitor_snapshot_from_parsed_with_depth(
        &parsed,
        options,
        &spot_depths.depths,
        &swap_depths.depths,
        depth_warnings,
    )?;
    let build_ms = build_start.elapsed().as_millis();
    if !funding_pages.warnings.is_empty() {
        snapshot.last_error = Some(
            snapshot
                .last_error
                .into_iter()
                .chain([funding_pages.warnings.join("; ")])
                .collect::<Vec<_>>()
                .join("; "),
        );
    }
    if timing_log {
        println!(
            "okx_basis_cycle total_ms={} spot_ms={} swap_ms={} mark_ms={} index_ms={} funding_ms={} parse_ms={} depth_ms={} build_ms={} funding_requested={} funding_refreshed={} funding_cached={} depth_symbols={} depth_refreshed={} depth_cached={} rows={} candidates={}",
            cycle_start.elapsed().as_millis(),
            spot_ms,
            swap_ms,
            mark_ms,
            index_ms,
            funding_ms,
            parse_ms,
            depth_ms,
            build_ms,
            funding_pages.requested_count,
            funding_pages.refreshed_count,
            funding_pages.cached_count,
            depth_symbol_count,
            depth_refreshed_count,
            depth_cached_count,
            snapshot.total_rows,
            snapshot.candidate_count
        );
    }
    Ok(snapshot)
}

