fn build_okx_basis_monitor_snapshot_from_parsed_with_depth(
    parsed: &OkxBasisMonitorParsedInputs,
    options: &OkxBasisMonitorOptions,
    spot_depths: &BTreeMap<String, PublicOrderBookDepth>,
    swap_depths: &BTreeMap<String, PublicOrderBookDepth>,
    warnings: Vec<String>,
) -> RuntimeResult<OkxBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for (swap_inst_id, swap) in &parsed.swap_tickers {
        let Some(spot_inst_id) = okx_spot_inst_id_from_swap(swap_inst_id) else {
            continue;
        };
        let funding = parsed.funding_rates.get(swap_inst_id);
        if let Some(funding) = funding {
            let funding_rate = MonitorDecimal::parse("fundingRate", &funding.funding_rate)?;
            if funding_rate.abs_less_than(min_abs_funding_rate) {
                filtered_funding_count += 1;
                continue;
            }
        }

        let spot = parsed.spot_books.get(&spot_inst_id);
        let mark = parsed.mark_prices.get(swap_inst_id);
        let index = parsed.index_prices.get(&spot_inst_id);
        let (mut source_status, reason) = match (spot, funding) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_SPOT_TICKER".to_owned()),
                )
            }
            (Some(_), None) => (
                "missing_funding".to_owned(),
                Some("MISSING_FUNDING_RATE".to_owned()),
            ),
            (None, None) => {
                missing_spot_count += 1;
                (
                    "missing_spot_and_funding".to_owned(),
                    Some("MISSING_SPOT_AND_FUNDING_RATE".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, funding) {
            (Some(spot), Some(funding)) => {
                let spot_ask_depth = spot_depths
                    .get(&spot_inst_id)
                    .map(|depth| depth.ask_depth.clone())
                    .unwrap_or_else(|| {
                        signal_depth_from_top_strings(&spot.ask_price, &spot.ask_qty)
                    });
                let perp_bid_depth = swap_depths
                    .get(swap_inst_id)
                    .map(|depth| depth.bid_depth.clone())
                    .unwrap_or_else(|| {
                        signal_depth_from_top_strings(&swap.bid_price, &swap.bid_qty)
                    });
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: spot_inst_id.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    spot_ask_depth,
                    perp_best_bid: swap.bid_price.clone(),
                    perp_best_ask: swap.ask_price.clone(),
                    perp_bid_size: Some(swap.bid_qty.clone()),
                    perp_bid_depth,
                    last_funding_rate: funding.funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps.clone(),
                    perp_taker_fee_bps: options.perp_taker_fee_bps.clone(),
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(OkxBasisMarketRow {
            symbol: spot_inst_id,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            spot_bid_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.inst_id)
                        .map(|depth| depth.bid_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.bid_price, &row.bid_qty)
                        })
                })
                .unwrap_or_default(),
            spot_ask_depth: spot
                .map(|row| {
                    spot_depths
                        .get(&row.inst_id)
                        .map(|depth| depth.ask_depth.clone())
                        .unwrap_or_else(|| {
                            signal_depth_from_top_strings(&row.ask_price, &row.ask_qty)
                        })
                })
                .unwrap_or_default(),
            perp_bid: Some(swap.bid_price.clone()),
            perp_ask: Some(swap.ask_price.clone()),
            perp_bid_qty: Some(swap.bid_qty.clone()),
            perp_ask_qty: Some(swap.ask_qty.clone()),
            perp_bid_depth: swap_depths
                .get(swap_inst_id)
                .map(|depth| depth.bid_depth.clone())
                .unwrap_or_else(|| signal_depth_from_top_strings(&swap.bid_price, &swap.bid_qty)),
            perp_ask_depth: swap_depths
                .get(swap_inst_id)
                .map(|depth| depth.ask_depth.clone())
                .unwrap_or_else(|| signal_depth_from_top_strings(&swap.ask_price, &swap.ask_qty)),
            mark_price: mark.map(|row| row.mark_price.clone()).unwrap_or_default(),
            index_price: index.map(|row| row.index_price.clone()).unwrap_or_default(),
            last_funding_rate: funding
                .map(|row| row.funding_rate.clone())
                .unwrap_or_default(),
            funding_interval_hours: funding_interval_hours_or_default(
                "okx",
                funding.and_then(|row| row.funding_interval_hours.clone()),
            )?,
            next_funding_time_ms: funding
                .map(|row| row.next_funding_time_ms.clone())
                .unwrap_or_default(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    if rows.is_empty() && !parsed.spot_books.is_empty() {
        missing_perp_count = parsed
            .spot_books
            .keys()
            .filter(|spot_inst_id| spot_inst_id.ends_with("-USDT"))
            .count();
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(OkxBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: (!warnings.is_empty()).then(|| warnings.join("; ")),
        rows,
    })
}

fn okx_basis_monitor_depth_symbols_from_parsed(
    parsed: &OkxBasisMonitorParsedInputs,
    options: &OkxBasisMonitorOptions,
) -> RuntimeResult<OkxBasisMonitorDepthSymbols> {
    okx_basis_monitor_depth_symbols_from_parsed_with_limit(
        parsed,
        options,
        BASIS_MONITOR_DEPTH_SYMBOL_LIMIT,
    )
}

fn okx_basis_monitor_depth_symbols_from_parsed_with_limit(
    parsed: &OkxBasisMonitorParsedInputs,
    options: &OkxBasisMonitorOptions,
    limit: usize,
) -> RuntimeResult<OkxBasisMonitorDepthSymbols> {
    if limit == 0 {
        return Ok(OkxBasisMonitorDepthSymbols {
            spot: BTreeSet::new(),
            swap: BTreeSet::new(),
        });
    }
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let mut scored_symbols = Vec::new();
    for (swap_inst_id, swap) in &parsed.swap_tickers {
        let Some(spot_inst_id) = okx_spot_inst_id_from_swap(swap_inst_id) else {
            continue;
        };
        let Some(spot) = parsed.spot_books.get(&spot_inst_id) else {
            continue;
        };
        let Some(funding) = parsed.funding_rates.get(swap_inst_id) else {
            continue;
        };
        let funding_rate = MonitorDecimal::parse("fundingRate", &funding.funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            continue;
        }
        let Ok(signal) = evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
            symbol: spot_inst_id.clone(),
            spot_best_bid: spot.bid_price.clone(),
            spot_best_ask: spot.ask_price.clone(),
            spot_ask_size: Some(spot.ask_qty.clone()),
            spot_ask_depth: spot.ask_depth.clone(),
            perp_best_bid: swap.bid_price.clone(),
            perp_best_ask: swap.ask_price.clone(),
            perp_bid_size: Some(swap.bid_qty.clone()),
            perp_bid_depth: swap.bid_depth.clone(),
            last_funding_rate: funding.funding_rate.clone(),
            notional_usd: options.notional_usd.clone(),
            spot_taker_fee_bps: options.spot_taker_fee_bps.clone(),
            perp_taker_fee_bps: options.perp_taker_fee_bps.clone(),
            slippage_buffer_bps: options.slippage_buffer_bps,
            min_net_bps: options.min_net_bps,
        }) else {
            continue;
        };
        if !basis_monitor_signal_should_fetch_depth(&signal, options.min_net_bps) {
            continue;
        }
        scored_symbols.push((
            signal_bps_sort_key(&signal.expected_profit_bps),
            signal_bps_sort_key(&signal.net_bps),
            funding_rate.raw.checked_abs().unwrap_or(i128::MAX),
            spot_inst_id,
            swap_inst_id.clone(),
        ));
    }
    scored_symbols.sort_by(|left, right| {
        right
            .0
            .cmp(&left.0)
            .then_with(|| right.1.cmp(&left.1))
            .then_with(|| right.2.cmp(&left.2))
            .then_with(|| left.3.cmp(&right.3))
            .then_with(|| left.4.cmp(&right.4))
    });
    let mut spot = BTreeSet::new();
    let mut swap = BTreeSet::new();
    for (_, _, _, spot_inst_id, swap_inst_id) in scored_symbols.into_iter().take(limit) {
        spot.insert(spot_inst_id);
        swap.insert(swap_inst_id);
    }
    Ok(OkxBasisMonitorDepthSymbols { spot, swap })
}

fn fetch_bitget_basis_monitor_snapshot(
    options: &BitgetBasisMonitorOptions,
) -> RuntimeResult<BitgetBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&bitget_spot_tickers_url())?;
    let futures_json = fetch_public_json_with_curl(&bitget_usdt_futures_tickers_url())?;
    let funding_json = fetch_public_json_with_curl(&bitget_usdt_futures_funding_rate_url())?;
    let parsed = parse_bitget_basis_monitor_inputs(&spot_json, &futures_json, &funding_json)?;
    let depth_symbols = bitget_basis_monitor_depth_symbols_from_parsed(&parsed, options)?;
    let spot_depths =
        fetch_public_order_book_depth_map(PublicOrderBookDepthVenue::BitgetSpot, &depth_symbols);
    let futures_depths = fetch_public_order_book_depth_map(
        PublicOrderBookDepthVenue::BitgetUsdtFutures,
        &depth_symbols,
    );
    let warnings = spot_depths
        .warnings
        .into_iter()
        .chain(futures_depths.warnings)
        .collect::<Vec<_>>();
    build_bitget_basis_monitor_snapshot_from_parsed_with_depth(
        &parsed,
        options,
        &spot_depths.depths,
        &futures_depths.depths,
        warnings,
    )
}

fn parse_bitget_basis_monitor_inputs(
    spot_json: &str,
    futures_json: &str,
    funding_json: &str,
) -> RuntimeResult<BitgetBasisMonitorParsedInputs> {
    Ok(BitgetBasisMonitorParsedInputs {
        spot_books: parse_bitget_spot_ticker_rows(spot_json)?
            .into_iter()
            .map(|row| (row.symbol.clone(), row))
            .collect(),
        futures_tickers: parse_bitget_usdt_futures_ticker_rows(futures_json)?,
        funding_rates: parse_bitget_funding_rate_rows(funding_json)?
            .into_iter()
            .map(|row| (row.symbol.clone(), row))
            .collect(),
    })
}

