fn build_hyperliquid_basis_monitor_snapshot_from_optional_spot_json_with_depth(
    spot_json: Option<&str>,
    perp_json: &str,
    options: &HyperliquidBasisMonitorOptions,
    perp_depths: &BTreeMap<String, PublicOrderBookDepth>,
    mut warnings: Vec<String>,
) -> RuntimeResult<HyperliquidBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = match spot_json {
        Some(spot_json) => parse_hyperliquid_spot_context_rows(spot_json)?
            .into_iter()
            .map(|row| (row.coin.clone(), row))
            .collect::<BTreeMap<_, _>>(),
        None => BTreeMap::new(),
    };
    let perp_contexts = parse_hyperliquid_perp_context_rows(perp_json)?;
    let perp_wss_quotes = match options.perp_wss_monitor_url.as_deref() {
        Some(url) => match fetch_public_wss_monitor_quote_map_for_basis(
            url,
            "/api/hyperliquid-wss-book-ticker",
            HyperliquidPublicWssMarket::Perp.as_str(),
        ) {
            Ok(quotes) => Some(quotes),
            Err(error) => {
                warnings.push(format!(
                    "Hyperliquid perp WSS monitor unavailable; using REST perp context fallback: {error}"
                ));
                None
            }
        },
        None => None,
    };

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let missing_perp_count = 0_usize;
    let mut missing_wss_quote_count = 0_usize;
    let mut unusable_wss_quote_count = 0_usize;

    for perp in perp_contexts {
        let funding_rate = MonitorDecimal::parse("funding", &perp.funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            filtered_funding_count += 1;
            continue;
        }

        let spot = spot_books.get(&perp.coin);
        let perp_wss_row = match perp_wss_quotes.as_ref() {
            Some(wss_quotes) => {
                let display_symbol = funding_display_symbol(&perp.coin);
                match wss_quotes
                    .quotes
                    .get(&perp.coin)
                    .or_else(|| wss_quotes.quotes.get(&display_symbol))
                {
                    Some(quote) => {
                        let expected_instrument_id =
                            format!("inst:HYPERLIQUID:{display_symbol}:PERP");
                        match public_wss_quote_to_monitor_book_ticker_row(
                            quote,
                            &wss_quotes.monitor_ref,
                            &quote.symbol,
                            HyperliquidPublicWssMarket::Perp.venue_id(),
                            &expected_instrument_id,
                            wss_quotes.fetched_at,
                        ) {
                            Ok(row) => Some(row),
                            Err(_) => {
                                unusable_wss_quote_count += 1;
                                None
                            }
                        }
                    }
                    None => {
                        missing_wss_quote_count += 1;
                        None
                    }
                }
            }
            None => None,
        };
        let perp_depth = perp_depths.get(&perp.coin);
        let depth_bid = perp_depth.and_then(|depth| depth.bid_depth.first());
        let depth_ask = perp_depth.and_then(|depth| depth.ask_depth.first());
        let has_perp_top_size =
            perp_wss_row.is_some() || (depth_bid.is_some() && depth_ask.is_some());
        let (mut source_status, reason) = match spot {
            Some(_) => ("complete".to_owned(), None),
            None => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_HYPERLIQUID_USDC_SPOT_CONTEXT".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal: Option<SpotPerpBasisSignal> = match spot {
            Some(_) => {
                if !has_perp_top_size {
                    source_status = "missing_top_of_book_size".to_owned();
                    signal_error = Some("MISSING_HYPERLIQUID_TOP_OF_BOOK_SIZE".to_owned());
                } else {
                    signal_error =
                        Some("HYPERLIQUID_SPOT_PERP_BASIS_DRY_RUN_NOT_SUPPORTED".to_owned());
                }
                None
            }
            None => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(HyperliquidBasisMarketRow {
            symbol: perp.coin,
            spot_bid: spot.map(|row| row.price.clone()),
            spot_ask: spot.map(|row| row.price.clone()),
            spot_bid_qty: None,
            spot_ask_qty: None,
            spot_bid_depth: Vec::new(),
            spot_ask_depth: Vec::new(),
            perp_bid: perp_wss_row
                .as_ref()
                .map(|row| row.bid_price.clone())
                .or_else(|| depth_bid.map(|level| level.price.clone()))
                .or_else(|| Some(perp.price.clone())),
            perp_ask: perp_wss_row
                .as_ref()
                .map(|row| row.ask_price.clone())
                .or_else(|| depth_ask.map(|level| level.price.clone()))
                .or_else(|| Some(perp.price.clone())),
            perp_bid_qty: perp_wss_row
                .as_ref()
                .map(|row| row.bid_qty.clone())
                .or_else(|| depth_bid.map(|level| level.size.clone())),
            perp_ask_qty: perp_wss_row
                .as_ref()
                .map(|row| row.ask_qty.clone())
                .or_else(|| depth_ask.map(|level| level.size.clone())),
            perp_bid_depth: perp_wss_row
                .as_ref()
                .map(|row| {
                    signal_depth_or_top_strings(&row.bid_depth, &row.bid_price, &row.bid_qty)
                })
                .or_else(|| perp_depth.map(|depth| depth.bid_depth.clone()))
                .unwrap_or_default(),
            perp_ask_depth: perp_wss_row
                .as_ref()
                .map(|row| {
                    signal_depth_or_top_strings(&row.ask_depth, &row.ask_price, &row.ask_qty)
                })
                .or_else(|| perp_depth.map(|depth| depth.ask_depth.clone()))
                .unwrap_or_default(),
            mark_price: perp.mark_price,
            index_price: perp.oracle_price,
            last_funding_rate: perp.funding_rate,
            funding_interval_hours: funding_interval_hours_string_for_venue("hyperliquid")?,
            next_funding_time_ms: String::new(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();
    if missing_wss_quote_count > 0 {
        warnings.push(format!(
            "Hyperliquid perp WSS monitor lacked quotes for {missing_wss_quote_count} symbols; used REST fallback where available"
        ));
    }
    if unusable_wss_quote_count > 0 {
        warnings.push(format!(
            "Hyperliquid perp WSS monitor had {unusable_wss_quote_count} unusable quote rows; used REST fallback where available"
        ));
    }

    Ok(HyperliquidBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: (!warnings.is_empty()).then(|| warnings.join("; ")),
        rows,
    })
}

#[cfg(feature = "live-exec")]
fn fetch_funding_arb_monitor_snapshot(
    options: &FundingArbMonitorOptions,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let mut cache = FundingArbDirectSourceCache::default();
    fetch_funding_arb_monitor_snapshot_with_cache(options, &mut cache)
}

fn fetch_funding_arb_monitor_snapshot_with_cache(
    options: &FundingArbMonitorOptions,
    direct_source_cache: &mut FundingArbDirectSourceCache,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let snapshot = if funding_arb_direct_public_sources_enabled()? {
        fetch_funding_arb_direct_public_snapshot(options, direct_source_cache)?
    } else {
        fetch_funding_arb_basis_status_snapshot(options)?
    };
    Ok(apply_funding_arb_depth_backfill(
        snapshot,
        options,
        &mut direct_source_cache.depth_backfill,
    ))
}

fn fetch_funding_arb_basis_status_snapshot(
    options: &FundingArbMonitorOptions,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let mut snapshots = Vec::new();
    let mut source_errors = Vec::new();
    for source in &options.sources {
        match fetch_public_json_with_curl(&source.status_url)
            .and_then(|json| parse_funding_arb_basis_status_snapshot(&json, source))
        {
            Ok(snapshot) => snapshots.push(snapshot),
            Err(error) => source_errors.push(format!("{}: {error}", source.venue_family)),
        }
    }

    if snapshots.len() < 2 {
        return Err(RuntimeError::LiveMarketData {
            message: format!(
                "funding arb observer requires at least two healthy source snapshots; errors={}",
                source_errors.join("; ")
            ),
        });
    }
    build_funding_arb_monitor_snapshot_from_sources(snapshots, source_errors, options)
}

fn fetch_funding_arb_direct_public_snapshot(
    options: &FundingArbMonitorOptions,
    cache: &mut FundingArbDirectSourceCache,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let mut snapshots = Vec::new();
    let mut source_errors = Vec::new();
    for source in &options.sources {
        match fetch_funding_arb_direct_public_venue_snapshot(source, cache) {
            Ok(snapshot) => snapshots.push(snapshot),
            Err(error) => source_errors.push(format!("{}: {error}", source.venue_family)),
        }
    }

    if snapshots.len() < 2 {
        return Err(RuntimeError::LiveMarketData {
            message: format!(
                "funding arb direct observer requires at least two healthy public source snapshots; errors={}",
                source_errors.join("; ")
            ),
        });
    }
    build_funding_arb_monitor_snapshot_from_sources(snapshots, source_errors, options)
}

fn fetch_funding_arb_direct_public_venue_snapshot(
    source: &FundingArbVenueSource,
    cache: &mut FundingArbDirectSourceCache,
) -> RuntimeResult<FundingArbVenueSnapshot> {
    match normalize_venue_family(&source.venue_family).as_str() {
        "binance" => fetch_binance_funding_arb_public_venue_snapshot(),
        "bybit" => fetch_bybit_funding_arb_public_venue_snapshot(cache),
        "okx" => fetch_okx_funding_arb_public_venue_snapshot(cache),
        "bitget" => fetch_bitget_funding_arb_public_venue_snapshot(),
        "aster" => fetch_aster_funding_arb_public_venue_snapshot(),
        "hyperliquid" => fetch_hyperliquid_funding_arb_public_venue_snapshot(),
        other => Err(RuntimeError::LiveMarketData {
            message: format!("unsupported funding arb direct public source `{other}`"),
        }),
    }
}

fn fetch_binance_funding_arb_public_venue_snapshot() -> RuntimeResult<FundingArbVenueSnapshot> {
    let book_json = fetch_public_json_with_curl(&binance_usdm_book_ticker_all_url())?;
    let premium_json = fetch_public_json_with_curl(&binance_usdm_premium_index_all_url())?;
    let funding_info_json = fetch_public_json_with_curl(&binance_usdm_funding_info_url())?;
    let funding_intervals =
        parse_funding_interval_info_map(&funding_info_json, "binance usdm fundingInfo")?;
    let books = parse_book_ticker_rows(&book_json, "binance usdm bookTicker")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let rows = parse_premium_index_rows(&premium_json)?
        .into_iter()
        .filter(|row| row.symbol.ends_with("USDT") && !row.last_funding_rate.trim().is_empty())
        .filter_map(|premium| {
            let book = books.get(&premium.symbol)?;
            let funding_interval_hours = funding_interval_hours_for_symbol(
                "binance",
                &premium.symbol,
                premium.funding_interval_hours.clone(),
                &funding_intervals,
            )
            .ok()?;
            Some(funding_arb_market_from_top_of_book(
                "binance",
                premium.symbol,
                book.bid_price.clone(),
                book.bid_qty.clone(),
                book.ask_price.clone(),
                book.ask_qty.clone(),
                premium.mark_price,
                premium.index_price,
                premium.last_funding_rate,
                funding_interval_hours,
                Some(premium.next_funding_time_ms),
            ))
        })
        .collect::<Vec<_>>();
    Ok(FundingArbVenueSnapshot {
        status: "healthy".to_owned(),
        rows,
    })
}

