const OKX_DEPTH_FETCH_CONCURRENCY_DEFAULT: usize = 6;
const OKX_DEPTH_CACHE_TTL_DEFAULT_SECS: u64 = 10;
const BASIS_MONITOR_DEPTH_SYMBOL_LIMIT: usize = 12;
