#[cfg(feature = "live-exec")]
fn append_text_line_to_file(path: PathBuf, line: &str) -> RuntimeResult<()> {
    let compacted_line = compact_repeated_pipe_segments(line);
    rotate_append_jsonl_for_pending_line(&path, compacted_line.len().saturating_add(1))?;
    let mut file = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&path)
        .map_err(|error| RuntimeError::Io {
            path: path.clone(),
            message: error.to_string(),
        })?;
    file.write_all(compacted_line.as_bytes())
        .and_then(|_| file.write_all(b"\n"))
        .map_err(|error| RuntimeError::Io {
            path,
            message: error.to_string(),
        })
}

#[cfg(feature = "live-exec")]
fn touch_runtime_file(path: &Path) -> RuntimeResult<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| RuntimeError::Io {
            path: parent.to_path_buf(),
            message: error.to_string(),
        })?;
    }
    fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map(|_| ())
        .map_err(|error| RuntimeError::Io {
            path: path.to_path_buf(),
            message: error.to_string(),
        })
}

