fn opportunity_recorder_log_timestamp() -> String {
    current_utc_timestamp_string()
}

#[cfg(feature = "live-exec")]
fn current_unix_secs_runtime() -> RuntimeResult<u64> {
    let duration = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map_err(|error| RuntimeError::LiveMarketData {
            message: format!("system time is before Unix epoch: {error}"),
        })?;
    Ok(duration.as_secs())
}

fn current_utc_timestamp() -> RuntimeResult<UtcTimestamp> {
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map_err(|error| RuntimeError::LiveMarketData {
            message: format!("system time is before Unix epoch: {error}"),
        })?;
    let seconds = i64::try_from(now.as_secs()).map_err(|_| RuntimeError::LiveMarketData {
        message: "current Unix timestamp does not fit i64".to_owned(),
    })?;
    Ok(UtcTimestamp::from_unix_parts(seconds, now.subsec_nanos())?)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct MonitorDecimal {
    raw: i128,
}

fn monitor_decimal_gcd_abs_i128(value: i128, positive: i128) -> i128 {
    let mut left = value.unsigned_abs();
    let mut right = positive.unsigned_abs();
    while right != 0 {
        let remainder = left % right;
        left = right;
        right = remainder;
    }
    i128::try_from(left).expect("monitor decimal gcd fits i128")
}

impl MonitorDecimal {
    const SCALE_DIGITS: usize = 18;

    fn parse(field: &'static str, value: &str) -> RuntimeResult<Self> {
        let value = value.trim();
        if value.is_empty() {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` cannot be empty"),
            });
        }
        let negative = value.starts_with('-');
        let unsigned = value.strip_prefix('-').unwrap_or(value);
        if unsigned.is_empty() || unsigned.starts_with('.') || unsigned.ends_with('.') {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` is malformed: `{value}`"),
            });
        }
        let mut raw = 0_i128;
        let mut dot_seen = false;
        let mut digits_seen = false;
        let mut fraction_digits = 0_usize;
        for byte in unsigned.bytes() {
            match byte {
                b'0'..=b'9' => {
                    digits_seen = true;
                    if dot_seen {
                        if fraction_digits == Self::SCALE_DIGITS {
                            return Err(RuntimeError::LiveMarketData {
                                message: format!(
                                    "decimal field `{field}` exceeds {} fractional digits",
                                    Self::SCALE_DIGITS
                                ),
                            });
                        }
                        fraction_digits += 1;
                    }
                    raw = raw
                        .checked_mul(10)
                        .and_then(|scaled| scaled.checked_add(i128::from(byte - b'0')))
                        .ok_or_else(|| RuntimeError::LiveMarketData {
                            message: format!("decimal field `{field}` overflowed"),
                        })?;
                }
                b'.' if !dot_seen => dot_seen = true,
                _ => {
                    return Err(RuntimeError::LiveMarketData {
                        message: format!("decimal field `{field}` is malformed: `{value}`"),
                    });
                }
            }
        }
        if !digits_seen {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` has no digits"),
            });
        }
        for _ in fraction_digits..Self::SCALE_DIGITS {
            raw = raw
                .checked_mul(10)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("decimal field `{field}` overflowed"),
                })?;
        }
        if negative {
            raw = raw
                .checked_neg()
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("decimal field `{field}` overflowed"),
                })?;
        }
        Ok(Self { raw })
    }

    fn abs_less_than(self, other: Self) -> bool {
        self.raw.unsigned_abs() < other.raw.unsigned_abs()
    }

    fn abs_lte(self, other: Self) -> bool {
        self.raw.unsigned_abs() <= other.raw.unsigned_abs()
    }

    fn checked_add(self, other: Self, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_add(other.raw)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_sub(self, other: Self, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_sub(other.raw)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_mul_i128(self, value: i128, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_mul(value)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_mul_decimal(self, value: Self, context: &'static str) -> RuntimeResult<Self> {
        let mut left = self.raw;
        let mut right = value.raw;
        let mut divisor = 10_i128.pow(Self::SCALE_DIGITS as u32);
        let left_gcd = monitor_decimal_gcd_abs_i128(left, divisor);
        left /= left_gcd;
        divisor /= left_gcd;
        let right_gcd = monitor_decimal_gcd_abs_i128(right, divisor);
        right /= right_gcd;
        divisor /= right_gcd;
        Ok(Self {
            raw: left
                .checked_mul(right)
                .and_then(|raw| raw.checked_div(divisor))
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_div_i128(self, value: i128, context: &'static str) -> RuntimeResult<Self> {
        if value == 0 {
            return Err(RuntimeError::LiveMarketData {
                message: format!("{context} divided by zero"),
            });
        }
        Ok(Self {
            raw: self
                .raw
                .checked_div(value)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn format_trimmed(self) -> String {
        let negative = self.raw < 0;
        let raw = self.raw.unsigned_abs();
        let scale = 10_u128.pow(Self::SCALE_DIGITS as u32);
        let whole = raw / scale;
        let mut fraction = format!("{:018}", raw % scale);
        while fraction.ends_with('0') {
            fraction.pop();
        }
        let sign = if negative { "-" } else { "" };
        if fraction.is_empty() {
            format!("{sign}{whole}")
        } else {
            format!("{sign}{whole}.{fraction}")
        }
    }

    fn format_trimmed_with_scale(self, scale_digits: usize) -> String {
        if scale_digits >= Self::SCALE_DIGITS {
            return self.format_trimmed();
        }
        let negative = self.raw < 0;
        let raw = self.raw.unsigned_abs();
        let drop_digits = Self::SCALE_DIGITS - scale_digits;
        let divisor = 10_u128.pow(drop_digits as u32);
        let raw = raw / divisor;
        let scale = 10_u128.pow(scale_digits as u32);
        let whole = raw / scale;
        let mut fraction = if scale_digits == 0 {
            String::new()
        } else {
            format!("{:0width$}", raw % scale, width = scale_digits)
        };
        while fraction.ends_with('0') {
            fraction.pop();
        }
        let sign = if negative { "-" } else { "" };
        if fraction.is_empty() {
            format!("{sign}{whole}")
        } else {
            format!("{sign}{whole}.{fraction}")
        }
    }
}

#[cfg(feature = "live-exec")]
fn monitor_bps_floor_i128(field: &'static str, value: &str) -> RuntimeResult<i128> {
    monitor_bps_i128(field, value, false)
}

#[cfg(feature = "live-exec")]
fn monitor_bps_ceil_i128(field: &'static str, value: &str) -> RuntimeResult<i128> {
    monitor_bps_i128(field, value, true)
}

#[cfg(feature = "live-exec")]
fn monitor_bps_i128(field: &'static str, value: &str, ceil: bool) -> RuntimeResult<i128> {
    let decimal = MonitorDecimal::parse(field, value)?;
    let scale = 10_i128.pow(MonitorDecimal::SCALE_DIGITS as u32);
    let quotient = decimal.raw / scale;
    let remainder = decimal.raw % scale;
    if remainder == 0 {
        return Ok(quotient);
    }
    if ceil {
        if decimal.raw > 0 {
            quotient
                .checked_add(1)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("decimal field `{field}` overflowed while rounding up"),
                })
        } else {
            Ok(quotient)
        }
    } else if decimal.raw < 0 {
        quotient
            .checked_sub(1)
            .ok_or_else(|| RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` overflowed while rounding down"),
            })
    } else {
        Ok(quotient)
    }
}

const STRATEGY_FIXED_DECIMAL_SCALE_DIGITS: usize = 8;

fn strategy_fixed_decimal_text(value: &str) -> String {
    MonitorDecimal::parse("strategy_fixed_decimal", value)
        .map(|decimal| decimal.format_trimmed_with_scale(STRATEGY_FIXED_DECIMAL_SCALE_DIGITS))
        .unwrap_or_else(|_| value.trim().to_owned())
}

