#[cfg(feature = "live-exec")]
fn parse_hyperliquid_perp_quantity_step_from_meta_and_contexts(
    input: &str,
    symbol: &str,
) -> RuntimeResult<Quantity> {
    let target = normalize_hyperliquid_perp_asset_symbol(symbol)?;
    let items = hyperliquid_meta_and_context_items(input, "hyperliquid perp quantity step")?;
    let meta_fields = parse_json_object_value_slices(items.meta)?;
    let universe_value =
        meta_fields
            .get("universe")
            .ok_or_else(|| RuntimeError::LiveMarketData {
                message: "hyperliquid perp quantity step response is missing meta.universe"
                    .to_owned(),
            })?;
    for universe_object in json_object_slices(universe_value)? {
        let fields = parse_json_object_value_slices(universe_object)?;
        if optional_json_bool(&fields, "isDelisted", "hyperliquid perp meta")?.unwrap_or(false) {
            continue;
        }
        let coin = required_json_value_string(&fields, "name", "hyperliquid perp meta")?;
        if !coin.eq_ignore_ascii_case(&target) {
            continue;
        }
        let size_decimals =
            required_json_value_string(&fields, "szDecimals", "hyperliquid perp meta")?
                .parse::<u32>()
                .map_err(|_| RuntimeError::LiveMarketData {
                    message: format!("Hyperliquid szDecimals for `{coin}` is not an integer"),
                })?;
        return hyperliquid_quantity_step_from_size_decimals(size_decimals);
    }
    Err(RuntimeError::LiveMarketData {
        message: format!(
            "Hyperliquid public meta did not contain active perp size decimals for `{target}`"
        ),
    })
}

#[cfg(feature = "live-exec")]
fn hyperliquid_quantity_step_from_size_decimals(size_decimals: u32) -> RuntimeResult<Quantity> {
    if size_decimals > 18 {
        return Err(RuntimeError::LiveMarketData {
            message: format!("Hyperliquid szDecimals {size_decimals} exceeds supported scale 18"),
        });
    }
    let step = if size_decimals == 0 {
        "1".to_owned()
    } else {
        format!(
            "0.{}1",
            "0".repeat(size_decimals.saturating_sub(1) as usize)
        )
    };
    parse_positive_quantity_rule("Hyperliquid szDecimals quantity step", &step)
}

#[cfg(feature = "live-exec")]
fn parse_positive_quantity_rule(field: &'static str, value: &str) -> RuntimeResult<Quantity> {
    let quantity = Quantity::from_str(value).map_err(|error| RuntimeError::LiveMarketData {
        message: format!("{field} `{value}` is not a valid quantity: {error}"),
    })?;
    if quantity.atoms() <= 0 {
        return Err(RuntimeError::LiveMarketData {
            message: format!("{field} `{value}` must be greater than zero"),
        });
    }
    Ok(quantity)
}

#[cfg(feature = "live-exec")]
fn parse_positive_price_rule(field: &'static str, value: &str) -> RuntimeResult<Price> {
    let price = Price::from_str(value).map_err(|error| RuntimeError::LiveMarketData {
        message: format!("{field} `{value}` is not a valid price: {error}"),
    })?;
    if price.atoms() <= 0 {
        return Err(RuntimeError::LiveMarketData {
            message: format!("{field} `{value}` must be greater than zero"),
        });
    }
    Ok(price)
}

fn required_first_bitget_ticker_value_string(
    fields: &BTreeMap<String, &str>,
    field_names: &[&'static str],
    source: &'static str,
) -> RuntimeResult<String> {
    for field in field_names {
        if let Some(value) = fields.get(*field) {
            return bitget_ticker_value_to_string(value, field, source);
        }
    }
    Err(RuntimeError::LiveMarketData {
        message: format!(
            "{source} object is missing all fields [{}]",
            field_names.join(", ")
        ),
    })
}

fn bitget_ticker_value_to_string(
    value: &str,
    field: &'static str,
    source: &'static str,
) -> RuntimeResult<String> {
    bitget_ticker_value_to_string_at_depth(value, field, source, 0)
}

fn bitget_ticker_value_to_string_at_depth(
    value: &str,
    field: &'static str,
    source: &'static str,
    depth: usize,
) -> RuntimeResult<String> {
    let trimmed = value.trim();
    if !trimmed.starts_with('[') {
        if trimmed == "null" && is_bitget_size_field(field) {
            return Ok("0".to_owned());
        }
        return json_value_to_string(trimmed, field, source);
    }
    if depth >= 4 {
        return Err(RuntimeError::LiveMarketData {
            message: format!("{source} field `{field}` JSON array nesting is too deep"),
        });
    }
    let values = json_array_value_slices(trimmed)?;
    if values.is_empty() && is_bitget_size_field(field) {
        return Ok("0".to_owned());
    }
    if values.len() == 1 {
        return bitget_ticker_value_to_string_at_depth(values[0], field, source, depth + 1);
    }
    Err(RuntimeError::LiveMarketData {
        message: format!("{source} field `{field}` is an ambiguous JSON array"),
    })
}

fn is_bitget_size_field(field: &str) -> bool {
    matches!(
        field,
        "bidSz" | "bidSize" | "bidQty" | "askSz" | "askSize" | "askQty"
    )
}

fn bitget_response_data_object_slices<'a>(
    input: &'a str,
    source: &'static str,
) -> RuntimeResult<Vec<&'a str>> {
    let top_fields = parse_json_object_value_slices(input)?;
    let code = required_json_value_string(&top_fields, "code", source)?;
    if code != "00000" {
        let msg = optional_json_value_string(&top_fields, "msg", source)?
            .unwrap_or_else(|| "unknown".to_owned());
        return Err(RuntimeError::LiveMarketData {
            message: format!("{source} returned code={code}, msg={msg}"),
        });
    }
    let data = top_fields
        .get("data")
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: format!("{source} response is missing data"),
        })?;
    json_object_slices(data)
}

