#[cfg(feature = "live-exec")]
fn funding_arb_exchange_history_record_json(
    leg: &FundingArbPositionLegState,
    source: &str,
    record_type: &str,
    row: &str,
) -> RuntimeResult<String> {
    let fields = parse_json_object_value_slices(row)?;
    let delta_fields = funding_arb_exchange_history_optional_delta_fields(&fields)?;
    let delta_fields_ref = delta_fields.as_ref();
    let symbol = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["symbol", "instId", "coin", "instrument", "market", "coinId"],
        "exchange history row",
    )?
    .unwrap_or_default();
    let instrument_id = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["instId", "instrument", "market", "symbol"],
        "exchange history row",
    )?;
    let exchange_record_id = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "id", "billId", "tradeId", "execId", "orderId", "ordId", "tranId", "incomeId", "hash",
            "tid",
        ],
        "exchange history row",
    )?;
    let order_id = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "orderId",
            "ordId",
            "clOrdId",
            "clientOrderId",
            "order_id",
            "client_order_id",
        ],
        "exchange history row",
    )?;
    let trade_id = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["tradeId", "execId", "fillId", "billId", "id", "tid"],
        "exchange history row",
    )?;
    let side = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["side", "posSide", "positionSide", "direction"],
        "exchange history row",
    )?;
    let business_type = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["businessType", "bizType", "type", "subType", "category"],
        "exchange history row",
    )?;
    let income_type = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &["incomeType", "income_type", "type"],
        "exchange history row",
    )?;
    let currency = funding_arb_exchange_history_string_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "asset",
            "ccy",
            "currency",
            "marginCoin",
            "feeCcy",
            "commissionAsset",
            "coin",
        ],
        "exchange history row",
    )?;
    let event_time_ms = funding_arb_exchange_pnl_row_time_ms(&fields)?;
    let amount_like = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "income", "amount", "balChg", "cashFlow", "change", "usdc", "sz", "qty",
        ],
    )?;
    let quantity = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "qty",
            "quantity",
            "execQty",
            "cumExecQty",
            "cumQty",
            "fillSz",
            "fillQty",
            "sz",
            "size",
            "vol",
            "closedSize",
            "closeSize",
            "baseVolume",
        ],
    )?;
    let price = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "price",
            "execPrice",
            "fillPx",
            "fillPrice",
            "px",
            "avgPrice",
            "avgPx",
            "priceAvg",
            "avgEntryPrice",
            "avgExitPrice",
        ],
    )?;
    let notional_usd = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "notional",
            "execValue",
            "cumExecValue",
            "value",
            "quoteQty",
            "quoteVolume",
            "fillNotionalUsd",
            "fillQuoteSz",
            "closedValue",
        ],
    )?;
    let kind = income_type
        .as_deref()
        .or(business_type.as_deref())
        .unwrap_or("");
    let explicit_pnl_usd = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "closedPnl",
            "execPnl",
            "fillPnl",
            "realizedPnl",
            "realisedPnl",
            "realizedPL",
            "totalPL",
            "pnl",
            "profit",
            "netProfit",
            "closeProfit",
        ],
    )?;
    let pnl_usd = explicit_pnl_usd.or_else(|| {
        kind.eq_ignore_ascii_case("REALIZED_PNL")
            .then_some(amount_like)
            .flatten()
    });
    let explicit_fee_usd = funding_arb_exchange_history_decimal_from_field_sets(
        &fields,
        delta_fields_ref,
        &[
            "fee",
            "execFee",
            "openFee",
            "closeFee",
            "totalFee",
            "commission",
            "fillFee",
            "cumExecFee",
        ],
    )?;
    let fee_usd = explicit_fee_usd.or_else(|| {
        kind.eq_ignore_ascii_case("COMMISSION")
            .then_some(amount_like)
            .flatten()
    });
    let kind_lower = kind.to_ascii_lowercase();
    let funding_pnl_usd = if kind_lower.contains("fund")
        || kind_lower.contains("settlement")
        || kind_lower.contains("settle")
        || kind_lower == "8"
    {
        amount_like
    } else {
        None
    };
    let amount_usd = amount_like;
    Ok(format!(
        "{{\"accountId\":{},\"amountUsd\":{},\"businessType\":{},\"currency\":{},\"eventTimeMs\":{},\"exchangeRecordId\":{},\"feeUsd\":{},\"fundingPnlUsd\":{},\"incomeType\":{},\"instrumentId\":{},\"notionalUsd\":{},\"orderId\":{},\"pnlUsd\":{},\"price\":{},\"quantity\":{},\"rawPayload\":{},\"recordSource\":{},\"recordType\":{},\"side\":{},\"symbol\":{},\"tradeId\":{},\"venueFamily\":{},\"venueId\":{}}}",
        json_string(&leg.account_id),
        funding_arb_exchange_history_decimal_json(amount_usd),
        funding_arb_exchange_history_string_json(business_type),
        funding_arb_exchange_history_string_json(currency),
        event_time_ms
            .map(|value| value.to_string())
            .unwrap_or_else(|| "null".to_owned()),
        funding_arb_exchange_history_string_json(exchange_record_id),
        funding_arb_exchange_history_decimal_json(fee_usd),
        funding_arb_exchange_history_decimal_json(funding_pnl_usd),
        funding_arb_exchange_history_string_json(income_type),
        funding_arb_exchange_history_string_json(instrument_id),
        funding_arb_exchange_history_decimal_json(notional_usd),
        funding_arb_exchange_history_string_json(order_id),
        funding_arb_exchange_history_decimal_json(pnl_usd),
        funding_arb_exchange_history_decimal_json(price),
        funding_arb_exchange_history_decimal_json(quantity),
        row.trim(),
        json_string(source),
        json_string(record_type),
        funding_arb_exchange_history_string_json(side),
        json_string(&symbol),
        funding_arb_exchange_history_string_json(trade_id),
        json_string(&leg.venue_family),
        json_string(&leg.venue_id),
    ))
}

