#[cfg(feature = "live-exec")]
fn load_funding_arb_unknown_position_recovery_records(
    output_root: &Path,
) -> RuntimeResult<Vec<FundingArbUnknownPositionRecovery>> {
    let path = output_root.join("funding_arb_resident_positions.jsonl");
    if !path.exists() {
        return Ok(Vec::new());
    }

    let mut latest: BTreeMap<String, Option<FundingArbUnknownPositionRecovery>> = BTreeMap::new();
    let mut last_known: BTreeMap<String, FundingArbUnknownPositionRecovery> = BTreeMap::new();
    let contents = read_utf8(&path)?;
    for line in contents.lines().filter(|line| !line.trim().is_empty()) {
        let fields = parse_json_object_value_slices(line)?;
        let event_type =
            required_json_value_string(&fields, "event_type", "funding arb unknown recovery")?;
        let Some(position_id) =
            optional_json_value_string(&fields, "position_id", "funding arb unknown recovery")?
        else {
            continue;
        };
        match event_type.as_str() {
            "position_opened" => {
                if let Some(known) =
                    funding_arb_unknown_recovery_record_from_fields(&fields, position_id.clone())?
                {
                    last_known.insert(position_id.clone(), known);
                }
                latest.insert(position_id, None);
            }
            "position_unknown" => {
                let Some(cycle_dir) = optional_json_value_string(
                    &fields,
                    "cycle_dir",
                    "funding arb unknown recovery",
                )?
                else {
                    latest.insert(position_id, None);
                    continue;
                };
                let recovery = funding_arb_unknown_recovery_record_with_fallback(
                    &fields,
                    position_id.clone(),
                    PathBuf::from(cycle_dir),
                    last_known.get(&position_id),
                )?;
                latest.insert(position_id, Some(recovery));
            }
            "position_closed" => {
                latest.insert(position_id, None);
            }
            _ => {}
        }
    }

    Ok(latest.into_values().flatten().collect())
}

#[cfg(feature = "live-exec")]
fn load_funding_arb_flat_cancelled_orphan_recovery_records(
    output_root: &Path,
) -> RuntimeResult<Vec<FundingArbUnknownPositionRecovery>> {
    let path = output_root.join("funding_arb_resident_positions.jsonl");
    if !path.exists() {
        return Ok(Vec::new());
    }

    let mut latest_by_pair: BTreeMap<String, Option<FundingArbUnknownPositionRecovery>> =
        BTreeMap::new();
    let contents = read_utf8(&path)?;
    for line in contents.lines().filter(|line| !line.trim().is_empty()) {
        let fields = parse_json_object_value_slices(line)?;
        let event_type = required_json_value_string(
            &fields,
            "event_type",
            "funding arb flat-cancelled orphan recovery",
        )?;
        let position_id = optional_json_value_string(
            &fields,
            "position_id",
            "funding arb flat-cancelled orphan recovery",
        )?;
        let pair_id = optional_json_value_string(
            &fields,
            "pair_id",
            "funding arb flat-cancelled orphan recovery",
        )?;
        match event_type.as_str() {
            "position_flat_cancelled" => {
                let Some(position_id) = position_id else {
                    continue;
                };
                let Some(recovery) = funding_arb_flat_cancelled_orphan_recovery_record_from_fields(
                    &fields,
                    position_id,
                )?
                else {
                    continue;
                };
                latest_by_pair.insert(recovery.pair_id.clone(), Some(recovery));
            }
            "position_opened" | "position_unknown" | "position_closed" => {
                if let Some(pair_id) = pair_id {
                    latest_by_pair.insert(pair_id, None);
                } else if let Some(position_id) = position_id {
                    for latest in latest_by_pair.values_mut() {
                        if latest
                            .as_ref()
                            .is_some_and(|recovery| recovery.position_id == position_id)
                        {
                            *latest = None;
                        }
                    }
                }
            }
            _ => {}
        }
    }

    Ok(latest_by_pair.into_values().flatten().collect())
}

#[cfg(feature = "live-exec")]
fn load_funding_arb_closed_orphan_recovery_records(
    output_root: &Path,
) -> RuntimeResult<Vec<FundingArbUnknownPositionRecovery>> {
    let path = output_root.join("funding_arb_resident_positions.jsonl");
    if !path.exists() {
        return Ok(Vec::new());
    }

    let mut latest_by_position: BTreeMap<String, Option<FundingArbUnknownPositionRecovery>> =
        BTreeMap::new();
    let contents = read_utf8(&path)?;
    for line in contents.lines().filter(|line| !line.trim().is_empty()) {
        let fields = parse_json_object_value_slices(line)?;
        let event_type = required_json_value_string(
            &fields,
            "event_type",
            "funding arb closed orphan recovery",
        )?;
        let Some(position_id) = optional_json_value_string(
            &fields,
            "position_id",
            "funding arb closed orphan recovery",
        )?
        else {
            continue;
        };
        match event_type.as_str() {
            "position_closed" => {
                if funding_arb_closed_orphan_recovery_terminal_marker(&fields)? {
                    latest_by_position.insert(position_id, None);
                    continue;
                }
                let Some(recovery) =
                    funding_arb_closed_orphan_recovery_record_from_fields(&fields, position_id)?
                else {
                    continue;
                };
                latest_by_position.insert(recovery.position_id.clone(), Some(recovery));
            }
            "position_opened" | "position_unknown" | "position_flat_cancelled" => {
                latest_by_position.insert(position_id, None);
            }
            _ => {}
        }
    }

    Ok(latest_by_position.into_values().flatten().collect())
}

#[cfg(feature = "live-exec")]
fn funding_arb_unknown_recovery_snapshot_path(
    unknown: &FundingArbUnknownPositionRecovery,
) -> PathBuf {
    unknown.cycle_dir.join("funding_arb_monitor_snapshot.json")
}

#[cfg(feature = "live-exec")]
fn funding_arb_recovery_snapshot_artifact_available(snapshot_path: &Path) -> RuntimeResult<bool> {
    match fs::metadata(snapshot_path) {
        Ok(metadata) => Ok(metadata.is_file()),
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(false),
        Err(error) => Err(RuntimeError::Io {
            path: snapshot_path.to_path_buf(),
            message: error.to_string(),
        }),
    }
}

#[cfg(feature = "live-exec")]
fn funding_arb_flat_cancelled_orphan_recovery_record_from_fields(
    fields: &BTreeMap<String, &str>,
    position_id: String,
) -> RuntimeResult<Option<FundingArbUnknownPositionRecovery>> {
    let Some(cycle_dir) = optional_json_value_string(
        fields,
        "cycle_dir",
        "funding arb flat-cancelled orphan recovery",
    )?
    else {
        return Ok(None);
    };
    let Some(pair_id) = optional_json_value_string(
        fields,
        "pair_id",
        "funding arb flat-cancelled orphan recovery",
    )?
    .filter(|value| value != "unknown") else {
        return Ok(None);
    };
    let Some(symbol) = optional_json_value_string(
        fields,
        "symbol",
        "funding arb flat-cancelled orphan recovery",
    )?
    .filter(|value| value != "unknown") else {
        return Ok(None);
    };
    let notional_usdt = funding_arb_flat_cancelled_orphan_recovery_notional(fields)?;
    Ok(Some(FundingArbUnknownPositionRecovery {
        position_id,
        pair_id,
        symbol,
        cycle_dir: PathBuf::from(cycle_dir),
        notional_usdt,
        opened_at: optional_json_value_string(
            fields,
            "opened_at",
            "funding arb flat-cancelled orphan recovery",
        )?,
        closed_at: optional_json_value_string(
            fields,
            "closed_at",
            "funding arb flat-cancelled orphan recovery",
        )?,
    }))
}

#[cfg(feature = "live-exec")]
fn funding_arb_closed_orphan_recovery_terminal_marker(
    fields: &BTreeMap<String, &str>,
) -> RuntimeResult<bool> {
    if optional_json_value_string(fields, "source", "funding arb closed orphan recovery")?
        .is_some_and(|source| source == "closed-orphan-recovery")
    {
        return Ok(true);
    }
    Ok(fields
        .get("post_close_private_verified_flat")
        .is_some_and(|value| value.trim() == "true"))
}

#[cfg(feature = "live-exec")]
fn funding_arb_closed_orphan_recovery_record_from_fields(
    fields: &BTreeMap<String, &str>,
    position_id: String,
) -> RuntimeResult<Option<FundingArbUnknownPositionRecovery>> {
    let decision =
        optional_json_value_string(fields, "decision", "funding arb closed orphan recovery")?
            .unwrap_or_default();
    if !matches!(decision.as_str(), "close" | "emergency_de_risk") {
        return Ok(None);
    }
    let submitted_receipt_count = optional_json_usize_field(
        fields,
        "submitted_receipt_count",
        "funding arb closed orphan recovery",
    )?;
    let private_confirmation_count = optional_json_usize_field(
        fields,
        "private_confirmation_count",
        "funding arb closed orphan recovery",
    )?;
    if submitted_receipt_count == 0 && private_confirmation_count == 0 {
        return Ok(None);
    }
    funding_arb_flat_cancelled_orphan_recovery_record_from_fields(fields, position_id)
}

#[cfg(feature = "live-exec")]
fn optional_json_usize_field(
    fields: &BTreeMap<String, &str>,
    field: &'static str,
    source: &'static str,
) -> RuntimeResult<usize> {
    let Some(raw) = fields.get(field) else {
        return Ok(0);
    };
    let value = raw.trim().trim_matches('"');
    if value.is_empty() || value == "null" {
        return Ok(0);
    }
    value
        .parse::<usize>()
        .map_err(|error| RuntimeError::Module {
            module: "arb-runtime",
            message: format!("{source} `{field}` must be a non-negative integer: {error}"),
        })
}

#[cfg(feature = "live-exec")]
fn funding_arb_flat_cancelled_orphan_recovery_notional(
    fields: &BTreeMap<String, &str>,
) -> RuntimeResult<String> {
    let Some(raw) = optional_json_value_string(
        fields,
        "notional_usdt",
        "funding arb flat-cancelled orphan recovery",
    )?
    else {
        return Ok("unknown".to_owned());
    };
    let trimmed = raw.trim();
    if trimmed.is_empty() || trimmed == "unknown" {
        return Ok("unknown".to_owned());
    }
    let parsed = MonitorDecimal::parse("funding arb flat-cancelled notional_usdt", trimmed)?;
    if parsed.raw == 0 {
        Ok("unknown".to_owned())
    } else {
        Ok(raw)
    }
}

#[cfg(feature = "live-exec")]
fn funding_arb_unknown_recovery_record_from_fields(
    fields: &BTreeMap<String, &str>,
    position_id: String,
) -> RuntimeResult<Option<FundingArbUnknownPositionRecovery>> {
    let Some(cycle_dir) =
        optional_json_value_string(fields, "cycle_dir", "funding arb unknown recovery")?
    else {
        return Ok(None);
    };
    Ok(Some(funding_arb_unknown_recovery_record_with_fallback(
        fields,
        position_id,
        PathBuf::from(cycle_dir),
        None,
    )?))
}

#[cfg(feature = "live-exec")]
fn funding_arb_unknown_recovery_record_with_fallback(
    fields: &BTreeMap<String, &str>,
    position_id: String,
    cycle_dir: PathBuf,
    fallback: Option<&FundingArbUnknownPositionRecovery>,
) -> RuntimeResult<FundingArbUnknownPositionRecovery> {
    Ok(FundingArbUnknownPositionRecovery {
        pair_id: optional_json_value_string(fields, "pair_id", "funding arb unknown recovery")?
            .or_else(|| fallback.map(|known| known.pair_id.clone()))
            .unwrap_or_else(|| "unknown".to_owned()),
        symbol: optional_json_value_string(fields, "symbol", "funding arb unknown recovery")?
            .or_else(|| fallback.map(|known| known.symbol.clone()))
            .unwrap_or_else(|| "unknown".to_owned()),
        notional_usdt: optional_json_value_string(
            fields,
            "notional_usdt",
            "funding arb unknown recovery",
        )?
        .or_else(|| fallback.map(|known| known.notional_usdt.clone()))
        .unwrap_or_else(|| "unknown".to_owned()),
        opened_at: optional_json_value_string(fields, "opened_at", "funding arb unknown recovery")?
            .or_else(|| fallback.and_then(|known| known.opened_at.clone())),
        closed_at: optional_json_value_string(fields, "closed_at", "funding arb unknown recovery")?
            .or_else(|| fallback.and_then(|known| known.closed_at.clone())),
        position_id,
        cycle_dir,
    })
}

#[cfg(feature = "live-exec")]
fn write_funding_arb_unknown_recovery_position_state(
    options: &FundingArbResidentLiveOptions,
    unknown: &FundingArbUnknownPositionRecovery,
    output_dir: &Path,
) -> RuntimeResult<FundingArbUnknownRecoveryPositionStateOutcome> {
    let (snapshot_path, row, state) =
        build_funding_arb_unknown_recovery_position_state_template(options, unknown)?;
    let private = run_funding_arb_private_readonly_snapshot_once(
        FundingArbPrivateReadonlySnapshotOnceOptions {
            config_path: options.config_path.clone(),
            snapshot_path,
            pair_id: unknown.pair_id.clone(),
            output_dir: Some(output_dir.join("private-readonly")),
            funding_settlement_raw_snapshot_path: options
                .funding_settlement_raw_snapshot_path
                .clone(),
            hyperliquid_user: options.hyperliquid_user.clone(),
            aster_user: options.aster_user.clone(),
            aster_signer: options.aster_signer.clone(),
            aster_signer_cmd_env: options.aster_signer_cmd_env.clone(),
        },
    )?;
    let position_raw_json = read_utf8(&private.position_raw_snapshot_path)?;
    let position_raw = parse_funding_private_raw_snapshot_json(
        &position_raw_json,
        "funding arb unknown recovery private position raw snapshot",
    )?;
    let position_snapshot =
        funding_private_position_snapshot_from_raw_snapshot(&row, &position_raw)?;
    write_funding_arb_unknown_recovery_position_state_from_private_snapshot(
        output_dir,
        &row,
        state,
        &position_snapshot,
    )
}

#[cfg(feature = "live-exec")]
fn build_funding_arb_unknown_recovery_position_state_template(
    options: &FundingArbResidentLiveOptions,
    unknown: &FundingArbUnknownPositionRecovery,
) -> RuntimeResult<(PathBuf, FundingArbMarketRow, FundingArbPositionState)> {
    let snapshot_path = funding_arb_unknown_recovery_snapshot_path(unknown);
    let snapshot_json = read_utf8(&snapshot_path)?;
    let snapshot = parse_funding_arb_monitor_snapshot_json(&snapshot_json)?;
    let row = snapshot
        .rows
        .iter()
        .find(|row| row.pair_id == unknown.pair_id)
        .cloned()
        .ok_or_else(|| RuntimeError::Module {
            module: "arb-runtime",
            message: format!(
                "unknown position recovery snapshot does not contain pair_id `{}`",
                unknown.pair_id
            ),
        })?;
    let spec = funding_arb_pipeline_spec_from_monitor_row(
        &row,
        &funding_arb_resident_dry_run_options(
            options,
            snapshot_path.clone(),
            unknown.pair_id.clone(),
            None,
        ),
    )?;
    let opened_at_value = unknown.opened_at.as_deref().unwrap_or(&snapshot.updated_at);
    let opened_at =
        UtcTimestamp::from_str(opened_at_value).map_err(|error| RuntimeError::Module {
            module: "arb-runtime",
            message: format!("unknown position recovery snapshot updated_at is invalid: {error}"),
        })?;
    let notional_usd = funding_arb_recovery_notional_usdt(options, unknown);
    let state = FundingArbPositionState {
        pair_id: unknown.pair_id.clone(),
        symbol: unknown.symbol.clone(),
        plan_hash: None,
        notional_usd: notional_usd.clone(),
        entry_net_funding_bps: funding_arb_row_net_funding_bps(&row),
        target_funding_time_ms: funding_arb_row_target_funding_time_ms(&row),
        target_gross_funding_spread_bps: funding_arb_row_gross_funding_spread_bps(&row),
        target_expected_gross_funding_usd: funding_arb_target_expected_gross_funding_usd(
            &row,
            &notional_usd,
        )?,
        target_expected_net_funding_usd: row.expected_funding_usd.clone(),
        exit_risk_last_expected_funding_usd: row.expected_funding_usd.clone(),
        exit_risk_decline_streak_start_expected_funding_usd: row.expected_funding_usd.clone(),
        exit_risk_expected_funding_decline_cycles: 0,
        exit_risk_negative_net_funding_cycles: 0,
        opened_at: opened_at.to_string(),
        private_order_events_dir: options
            .private_order_events_dir
            .as_ref()
            .map(|path| path.display().to_string()),
        leg_a: funding_arb_recovery_position_leg_state(
            &row,
            &spec.strategy_config.venues.venue_a,
            "venue_a",
        )?,
        leg_b: funding_arb_recovery_position_leg_state(
            &row,
            &spec.strategy_config.venues.venue_b,
            "venue_b",
        )?,
    };
    Ok((snapshot_path, row, state))
}

#[cfg(feature = "live-exec")]
fn write_funding_arb_unknown_recovery_position_state_from_private_snapshot(
    output_dir: &Path,
    row: &FundingArbMarketRow,
    mut state: FundingArbPositionState,
    position_snapshot: &FundingPrivatePositionSnapshot,
) -> RuntimeResult<FundingArbUnknownRecoveryPositionStateOutcome> {
    funding_arb_align_unknown_recovery_state_to_private_positions(
        &mut state,
        row,
        position_snapshot,
    )?;
    if !funding_arb_position_state_has_nonzero_quantity(&state)? {
        return Ok(FundingArbUnknownRecoveryPositionStateOutcome::Flat {
            reason: "unknown recovery private snapshot has no non-zero legs; no reduce-only exit required"
                .to_owned(),
        });
    }
    let position_state_path = write_funding_arb_position_state(output_dir, &state)?;
    Ok(FundingArbUnknownRecoveryPositionStateOutcome::Open {
        position_state_path,
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_recovery_notional_usdt(
    options: &FundingArbResidentLiveOptions,
    unknown: &FundingArbUnknownPositionRecovery,
) -> String {
    let notional = unknown.notional_usdt.trim();
    if notional.is_empty() || notional == "unknown" {
        options.notional_usd.clone()
    } else {
        unknown.notional_usdt.clone()
    }
}

#[cfg(feature = "live-exec")]
fn funding_arb_recovery_position_leg_state(
    row: &FundingArbMarketRow,
    leg: &CrossExchangeFundingLegConfig,
    row_leg: &'static str,
) -> RuntimeResult<FundingArbPositionLegState> {
    let venue_id = VenueId::new(&leg.venue_id)?;
    let venue_family = funding_arb_venue_family_from_venue_id(&venue_id)?;
    let long_family = row
        .long_venue_family
        .as_deref()
        .ok_or_else(|| RuntimeError::Module {
            module: "arb-runtime",
            message: "unknown position recovery row lacks long venue family".to_owned(),
        })?;
    let short_family = row
        .short_venue_family
        .as_deref()
        .ok_or_else(|| RuntimeError::Module {
            module: "arb-runtime",
            message: "unknown position recovery row lacks short venue family".to_owned(),
        })?;
    let side = if normalize_venue_family(&venue_family) == normalize_venue_family(long_family) {
        OrderSide::Buy
    } else if normalize_venue_family(&venue_family) == normalize_venue_family(short_family) {
        OrderSide::Sell
    } else {
        return Err(RuntimeError::Module {
            module: "arb-runtime",
            message: format!(
                "unknown position recovery venue `{venue_family}` is neither long `{long_family}` nor short `{short_family}`"
            ),
        });
    };
    let entry_limit_price = match (row_leg, side) {
        ("venue_a", OrderSide::Buy) => row.venue_a_ask.clone(),
        ("venue_a", OrderSide::Sell) => row.venue_a_bid.clone(),
        ("venue_b", OrderSide::Buy) => row.venue_b_ask.clone(),
        ("venue_b", OrderSide::Sell) => row.venue_b_bid.clone(),
        _ => {
            return Err(RuntimeError::Module {
                module: "arb-runtime",
                message: format!("unknown position recovery has invalid row leg `{row_leg}`"),
            })
        }
    };
    Ok(FundingArbPositionLegState {
        role: if side == OrderSide::Buy {
            "funding_perp_long".to_owned()
        } else {
            "funding_perp_short".to_owned()
        },
        venue_family,
        venue_id: leg.venue_id.clone(),
        account_id: leg.account_id.clone(),
        instrument_id: leg.instrument_id.clone(),
        side,
        quantity: "0".to_owned(),
        entry_limit_price,
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_position_state_has_nonzero_quantity(
    state: &FundingArbPositionState,
) -> RuntimeResult<bool> {
    Ok(funding_arb_position_leg_quantity_is_nonzero(&state.leg_a)?
        || funding_arb_position_leg_quantity_is_nonzero(&state.leg_b)?)
}

#[cfg(feature = "live-exec")]
fn funding_arb_position_leg_quantity_is_nonzero(
    leg: &FundingArbPositionLegState,
) -> RuntimeResult<bool> {
    Ok(MonitorDecimal::parse("funding arb position leg quantity", &leg.quantity)?.raw != 0)
}

#[cfg(feature = "live-exec")]
fn funding_arb_resident_entry_capacity(
    options: &FundingArbResidentLiveOptions,
    output_root: &Path,
) -> RuntimeResult<ResidentEntryCapacity> {
    if !options.execute_live {
        return Ok(ResidentEntryCapacity::Allowed);
    }
    let registry = load_funding_arb_resident_position_registry(output_root)?;
    if registry.unknown_position_count() > 0 {
        return Ok(ResidentEntryCapacity::Blocked(
            "unknown funding arb resident position exists; new entries are blocked".to_owned(),
        ));
    }
    let max_total = Decimal::from_str(&options.max_total_notional_usdt)?;
    let next_notional = Decimal::from_str(&options.notional_usd)?;
    let after_next = registry
        .total_active_notional()?
        .checked_add(next_notional)?;
    if after_next > max_total {
        return Ok(ResidentEntryCapacity::Blocked(format!(
            "funding carry max total notional would be exceeded: after_next={} max={}",
            after_next, max_total
        )));
    }
    Ok(ResidentEntryCapacity::Allowed)
}

