#[cfg(feature = "live-exec")]
fn funding_arb_exit_cycle_blocked_before_dispatch(
    state: &FundingArbPositionState,
    output_dir: &Path,
    reason_code: &str,
    blocking_reason: String,
) -> RuntimeResult<FundingArbExitCycleReport> {
    let report = FundingArbExitCycleReport {
        pair_id: state.pair_id.clone(),
        symbol: state.symbol.clone(),
        decision: "blocked".to_owned(),
        reason_codes: vec![reason_code.to_owned()],
        runtime_risk: FundingArbExitRuntimeRiskSummary::not_checked(),
        financial_risk: FundingArbExitFinancialRiskSummary::not_checked(),
        partial_close: false,
        requested_close_quantity: None,
        funding_settlement_status: "NotChecked".to_owned(),
        private_position_status: "Unknown".to_owned(),
        dispatch_attempted: false,
        submitted_receipt_count: 0,
        private_confirmation_count: 0,
        exchange_pnl: FundingArbExchangePnlSummary::not_checked(
            "退出周期在提交平仓前被阻断，未执行交易所后台 PnL 同步。",
        ),
        residual_risk: Some(blocking_reason.clone()),
        blocking_reasons: vec![blocking_reason],
        output_dir: Some(output_dir.to_path_buf()),
    };
    write_funding_arb_exit_cycle_artifacts(output_dir, &report, &[], &[])?;
    Ok(report)
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_emergency_de_risk_slippage_bps(configured_slippage_bps: i128) -> i128 {
    configured_slippage_bps.max(FUNDING_ARB_EXIT_EMERGENCY_DE_RISK_SLIPPAGE_BPS)
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_rollover_allowed(
    row: &FundingArbMarketRow,
    state: &FundingArbPositionState,
    min_net_funding_bps: i128,
) -> bool {
    row.source_status == "complete"
        && funding_arb_position_direction_matches_row(row, state)
        && funding_arb_row_target_funding_time_ms(row).is_some()
        && funding_arb_row_net_funding_bps_meets_min(row, min_net_funding_bps)
}

#[cfg(feature = "live-exec")]
fn funding_arb_position_direction_matches_row(
    row: &FundingArbMarketRow,
    state: &FundingArbPositionState,
) -> bool {
    let Some(row_long) = row
        .long_venue_family
        .as_ref()
        .map(|value| normalize_venue_family(value))
    else {
        return false;
    };
    let Some(row_short) = row
        .short_venue_family
        .as_ref()
        .map(|value| normalize_venue_family(value))
    else {
        return false;
    };
    let Some(position_long) = funding_arb_position_leg_family_by_direction(state, "long") else {
        return false;
    };
    let Some(position_short) = funding_arb_position_leg_family_by_direction(state, "short") else {
        return false;
    };
    row_long == position_long && row_short == position_short
}

#[cfg(feature = "live-exec")]
fn funding_arb_position_leg_family_by_direction(
    state: &FundingArbPositionState,
    direction: &str,
) -> Option<String> {
    [&state.leg_a, &state.leg_b]
        .into_iter()
        .find(|leg| {
            let role = leg.role.to_ascii_lowercase();
            role.contains(direction)
                || (direction == "long" && leg.side == OrderSide::Buy)
                || (direction == "short" && leg.side == OrderSide::Sell)
        })
        .map(|leg| normalize_venue_family(&leg.venue_family))
}

#[cfg(feature = "live-exec")]
fn funding_arb_rollover_position_state_target(
    state: &mut FundingArbPositionState,
    row: &FundingArbMarketRow,
) -> RuntimeResult<()> {
    state.target_funding_time_ms = funding_arb_row_target_funding_time_ms(row);
    state.target_gross_funding_spread_bps = funding_arb_row_gross_funding_spread_bps(row);
    state.target_expected_gross_funding_usd =
        funding_arb_target_expected_gross_funding_usd(row, &state.notional_usd)?;
    state.target_expected_net_funding_usd = row.expected_funding_usd.clone();
    Ok(())
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Eq, PartialEq)]
struct FundingArbExitPositionSignal {
    expected_funding_usd: MonitorDecimal,
    expected_return_bps: MonitorDecimal,
    net_funding_bps: MonitorDecimal,
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Copy)]
struct FundingArbRowVenueFields<'a> {
    family: &'a str,
    bid: &'a str,
    ask: &'a str,
    bid_qty: &'a str,
    ask_qty: &'a str,
    bid_depth: &'a [SignalDepthLevel],
    ask_depth: &'a [SignalDepthLevel],
    funding_rate: &'a str,
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_financial_risk_summary(
    row: &FundingArbMarketRow,
    state: &mut FundingArbPositionState,
    options: &FundingArbResidentLiveOptions,
    observed_at: &str,
) -> RuntimeResult<FundingArbExitFinancialRiskSummary> {
    let signal = funding_arb_exit_current_position_signal(row, state, options)?;
    let notional = MonitorDecimal::parse("funding_arb_exit.notional_usd", &state.notional_usd)?;
    let double_notional =
        notional.checked_mul_i128(2, "funding arb exit double-leg notional calculation")?;
    if double_notional.raw <= 0 {
        return Err(RuntimeError::LiveMarketData {
            message: "funding arb exit double-leg notional must be greater than zero".to_owned(),
        });
    }
    let previous_expected = state
        .exit_risk_last_expected_funding_usd
        .as_deref()
        .map(|value| MonitorDecimal::parse("funding_arb_exit.last_expected_funding_usd", value))
        .transpose()?;
    let previous_decline_cycles = state.exit_risk_expected_funding_decline_cycles;
    let previous_decline_start = state
        .exit_risk_decline_streak_start_expected_funding_usd
        .as_deref()
        .map(|value| {
            MonitorDecimal::parse(
                "funding_arb_exit.decline_streak_start_expected_funding_usd",
                value,
            )
        })
        .transpose()?;

    let (decline_cycles, decline_start) = if let Some(previous) = previous_expected {
        if signal.expected_funding_usd.raw < previous.raw {
            (
                previous_decline_cycles.saturating_add(1),
                previous_decline_start.unwrap_or(previous),
            )
        } else {
            (0, signal.expected_funding_usd)
        }
    } else {
        (0, signal.expected_funding_usd)
    };
    let negative_net_funding_cycles = if signal.net_funding_bps.raw < 0 {
        state
            .exit_risk_negative_net_funding_cycles
            .saturating_add(1)
    } else {
        0
    };
    let decline_usd = decline_start.checked_sub(
        signal.expected_funding_usd,
        "funding arb exit expected funding decline USD calculation",
    )?;
    let expected_funding_decline_bps = if decline_usd.raw > 0 {
        Some(monitor_decimal_ratio_bps(
            decline_usd.raw,
            double_notional.raw,
            "funding arb exit expected funding decline bps",
        )?)
    } else {
        None
    };
    let ms_to_target_funding = funding_arb_exit_ms_to_target_funding(state, observed_at)?;

    state.exit_risk_last_expected_funding_usd = Some(signal.expected_funding_usd.format_trimmed());
    state.exit_risk_decline_streak_start_expected_funding_usd =
        Some(decline_start.format_trimmed());
    state.exit_risk_expected_funding_decline_cycles = decline_cycles;
    state.exit_risk_negative_net_funding_cycles = negative_net_funding_cycles;

    let hard_loss_bps = funding_arb_exit_bps_threshold(
        FUNDING_ARB_EXIT_EXPECTED_RETURN_HARD_LOSS_BPS,
        "funding arb exit hard loss threshold",
    )?;
    let severe_loss_bps = funding_arb_exit_bps_threshold(
        FUNDING_ARB_EXIT_EXPECTED_RETURN_SEVERE_LOSS_BPS,
        "funding arb exit severe loss threshold",
    )?;
    let early_loss_bps = funding_arb_exit_bps_threshold(
        FUNDING_ARB_EXIT_EARLY_WINDOW_NEGATIVE_RETURN_BPS,
        "funding arb exit early window threshold",
    )?;
    let decline_limit_bps = funding_arb_exit_bps_threshold(
        FUNDING_ARB_EXIT_EXPECTED_FUNDING_DECLINE_BPS,
        "funding arb exit expected funding decline threshold",
    )?;

    let severe_loss_triggered = signal.expected_return_bps.raw <= severe_loss_bps.raw;
    let hard_loss_triggered = signal.expected_return_bps.raw <= hard_loss_bps.raw;
    let negative_streak_triggered = signal.net_funding_bps.raw < 0
        && negative_net_funding_cycles >= FUNDING_ARB_EXIT_NEGATIVE_NET_FUNDING_STREAK_CYCLES;
    let decline_streak_triggered = decline_cycles
        >= FUNDING_ARB_EXIT_EXPECTED_FUNDING_DECLINE_STREAK_CYCLES
        && expected_funding_decline_bps.is_some_and(|bps| bps.raw >= decline_limit_bps.raw);
    let early_window_triggered = ms_to_target_funding.is_some_and(|ms| {
        ms > FUNDING_ARB_EXIT_EARLY_WINDOW_MS
            && signal.expected_return_bps.raw <= early_loss_bps.raw
    });
    let near_settlement_window = ms_to_target_funding
        .is_some_and(|ms| (0..=FUNDING_ARB_EXIT_NEAR_SETTLEMENT_SOFT_SUPPRESS_MS).contains(&ms));

    let mut reason_codes = Vec::new();
    let mut reasons = Vec::new();
    let mut warning_codes = Vec::new();
    let mut warnings = Vec::new();
    if severe_loss_triggered {
        funding_arb_push_unique_reason_code(&mut reason_codes, "expected_return_severe_loss_limit");
        reasons.push(format!(
            "expected return {} bps is at or below severe loss limit {} bps",
            signal.expected_return_bps.format_trimmed(),
            FUNDING_ARB_EXIT_EXPECTED_RETURN_SEVERE_LOSS_BPS
        ));
    } else if near_settlement_window {
        if hard_loss_triggered
            || negative_streak_triggered
            || decline_streak_triggered
            || early_window_triggered
        {
            funding_arb_push_unique_reason_code(
                &mut warning_codes,
                "near_funding_settlement_soft_exit_suppressed",
            );
            warnings.push(format!(
                "soft financial exit is suppressed within {} ms of target funding; expected_return_bps={}",
                FUNDING_ARB_EXIT_NEAR_SETTLEMENT_SOFT_SUPPRESS_MS,
                signal.expected_return_bps.format_trimmed()
            ));
        }
    } else {
        if hard_loss_triggered {
            funding_arb_push_unique_reason_code(&mut reason_codes, "expected_return_loss_limit");
            reasons.push(format!(
                "expected return {} bps is at or below hard loss limit {} bps",
                signal.expected_return_bps.format_trimmed(),
                FUNDING_ARB_EXIT_EXPECTED_RETURN_HARD_LOSS_BPS
            ));
        }
        if negative_streak_triggered {
            funding_arb_push_unique_reason_code(&mut reason_codes, "negative_net_funding_streak");
            reasons.push(format!(
                "net funding bps {} has been negative for {} consecutive exit cycles",
                signal.net_funding_bps.format_trimmed(),
                negative_net_funding_cycles
            ));
        }
        if decline_streak_triggered {
            funding_arb_push_unique_reason_code(
                &mut reason_codes,
                "expected_funding_decline_streak",
            );
            reasons.push(format!(
                "expected funding has declined for {} consecutive exit cycles by {} bps",
                decline_cycles,
                expected_funding_decline_bps
                    .map(MonitorDecimal::format_trimmed)
                    .unwrap_or_else(|| "0".to_owned())
            ));
        }
        if early_window_triggered {
            funding_arb_push_unique_reason_code(
                &mut reason_codes,
                "pre_settlement_negative_expected_return",
            );
            reasons.push(format!(
                "target funding is more than {} ms away and expected return {} bps is at or below {} bps",
                FUNDING_ARB_EXIT_EARLY_WINDOW_MS,
                signal.expected_return_bps.format_trimmed(),
                FUNDING_ARB_EXIT_EARLY_WINDOW_NEGATIVE_RETURN_BPS
            ));
        }
    }

    Ok(FundingArbExitFinancialRiskSummary {
        status: if !reason_codes.is_empty() {
            "Triggered"
        } else if !warning_codes.is_empty() {
            "Warning"
        } else {
            "Matched"
        }
        .to_owned(),
        reason_codes,
        reason: (!reasons.is_empty()).then(|| reasons.join("; ")),
        warning_codes,
        warning: (!warnings.is_empty()).then(|| warnings.join("; ")),
        expected_funding_usd: Some(signal.expected_funding_usd.format_trimmed()),
        expected_return_bps: Some(signal.expected_return_bps.format_trimmed()),
        net_funding_bps: Some(signal.net_funding_bps.format_trimmed()),
        expected_funding_decline_bps: expected_funding_decline_bps
            .map(MonitorDecimal::format_trimmed),
        expected_funding_decline_cycles: decline_cycles,
        negative_net_funding_cycles,
        ms_to_target_funding,
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_current_position_signal(
    row: &FundingArbMarketRow,
    state: &FundingArbPositionState,
    options: &FundingArbResidentLiveOptions,
) -> RuntimeResult<FundingArbExitPositionSignal> {
    let long_family =
        funding_arb_position_leg_family_by_direction(state, "long").ok_or_else(|| {
            RuntimeError::LiveMarketData {
                message: "funding arb exit cannot determine active long venue family".to_owned(),
            }
        })?;
    let short_family =
        funding_arb_position_leg_family_by_direction(state, "short").ok_or_else(|| {
            RuntimeError::LiveMarketData {
                message: "funding arb exit cannot determine active short venue family".to_owned(),
            }
        })?;
    let long = funding_arb_row_venue_fields(row, &long_family)?;
    let short = funding_arb_row_venue_fields(row, &short_family)?;
    let signal = evaluate_cross_exchange_funding_arb_signal(&CrossExchangeFundingArbSignalInput {
        symbol: row.symbol.clone(),
        long_venue_id: long.family.to_owned(),
        short_venue_id: short.family.to_owned(),
        long_best_bid: long.bid.to_owned(),
        long_best_ask: long.ask.to_owned(),
        long_ask_size: Some(long.ask_qty.to_owned()),
        long_ask_depth: long.ask_depth.to_vec(),
        short_best_bid: short.bid.to_owned(),
        short_best_ask: short.ask.to_owned(),
        short_bid_size: Some(short.bid_qty.to_owned()),
        short_bid_depth: short.bid_depth.to_vec(),
        long_funding_rate: long.funding_rate.to_owned(),
        short_funding_rate: short.funding_rate.to_owned(),
        funding_interval_hours: "8".to_owned(),
        notional_usd: state.notional_usd.clone(),
        long_taker_fee_bps: funding_arb_perp_taker_fee_bps_for_venue_family(
            long.family,
            &options.taker_fee_bps,
        ),
        short_taker_fee_bps: funding_arb_perp_taker_fee_bps_for_venue_family(
            short.family,
            &options.taker_fee_bps,
        ),
        slippage_buffer_bps: options.slippage_buffer_bps,
        max_entry_price_divergence_bps: options.max_entry_price_divergence_bps,
        min_net_funding_bps: options.min_net_funding_bps,
    })
    .map_err(|message| RuntimeError::LiveMarketData { message })?;
    let expected_funding_usd = MonitorDecimal::parse(
        "funding_arb_exit.current_expected_funding_usd",
        &signal.expected_funding_usd,
    )?;
    let notional = MonitorDecimal::parse(
        "funding_arb_exit.position_notional_usd",
        &state.notional_usd,
    )?;
    let double_notional = notional.checked_mul_i128(
        2,
        "funding arb exit current signal double-leg notional calculation",
    )?;
    let expected_return_bps = monitor_decimal_ratio_bps(
        expected_funding_usd.raw,
        double_notional.raw,
        "funding arb exit current expected return bps",
    )?;
    let net_funding_bps = MonitorDecimal::parse(
        "funding_arb_exit.current_net_funding_bps",
        &signal.net_funding_bps,
    )?;
    Ok(FundingArbExitPositionSignal {
        expected_funding_usd,
        expected_return_bps,
        net_funding_bps,
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_row_venue_fields<'a>(
    row: &'a FundingArbMarketRow,
    family: &str,
) -> RuntimeResult<FundingArbRowVenueFields<'a>> {
    let normalized = normalize_venue_family(family);
    if normalize_venue_family(&row.venue_a_family) == normalized {
        return Ok(FundingArbRowVenueFields {
            family: &row.venue_a_family,
            bid: &row.venue_a_bid,
            ask: &row.venue_a_ask,
            bid_qty: &row.venue_a_bid_qty,
            ask_qty: &row.venue_a_ask_qty,
            bid_depth: &row.venue_a_bid_depth,
            ask_depth: &row.venue_a_ask_depth,
            funding_rate: &row.venue_a_funding_rate,
        });
    }
    if normalize_venue_family(&row.venue_b_family) == normalized {
        return Ok(FundingArbRowVenueFields {
            family: &row.venue_b_family,
            bid: &row.venue_b_bid,
            ask: &row.venue_b_ask,
            bid_qty: &row.venue_b_bid_qty,
            ask_qty: &row.venue_b_ask_qty,
            bid_depth: &row.venue_b_bid_depth,
            ask_depth: &row.venue_b_ask_depth,
            funding_rate: &row.venue_b_funding_rate,
        });
    }
    Err(RuntimeError::LiveMarketData {
        message: format!(
            "funding arb exit active venue family `{family}` is missing from current market row"
        ),
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_ms_to_target_funding(
    state: &FundingArbPositionState,
    observed_at: &str,
) -> RuntimeResult<Option<i128>> {
    let Some(target_ms) = state.target_funding_time_ms else {
        return Ok(None);
    };
    let observed = UtcTimestamp::from_str(observed_at).map_err(|error| RuntimeError::Module {
        module: "arb-runtime",
        message: format!("funding arb exit observed_at is invalid: {error}"),
    })?;
    Ok(Some(
        i128::from(target_ms)
            .checked_sub(runtime_timestamp_millis(observed)?)
            .ok_or_else(|| RuntimeError::LiveMarketData {
                message: "funding arb exit ms_to_target_funding calculation overflowed".to_owned(),
            })?,
    ))
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_bps_threshold(
    value: i128,
    context: &'static str,
) -> RuntimeResult<MonitorDecimal> {
    monitor_decimal_from_i128(value).ok_or_else(|| RuntimeError::LiveMarketData {
        message: format!("{context} overflowed"),
    })
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Copy)]
struct FundingArbExitCycleDecisionInput<'a> {
    private_position_matched: bool,
    private_position_reason: Option<&'a str>,
    settlement_matched: bool,
    settlement_observed_complete: bool,
    settlement_observed_mismatch: bool,
    rollover_allowed: bool,
    close_required_count: usize,
    runtime_risk: Option<&'a FundingArbExitRuntimeRiskSummary>,
    financial_risk: Option<&'a FundingArbExitFinancialRiskSummary>,
    unknown_recovery_exit: bool,
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_cycle_decision(
    input: FundingArbExitCycleDecisionInput<'_>,
    reason_codes: &mut Vec<String>,
    blocking_reasons: &mut Vec<String>,
) -> String {
    if !input.private_position_matched {
        reason_codes.push("private_position_unknown".to_owned());
        blocking_reasons.push(
            input
                .private_position_reason
                .unwrap_or("funding arb exit private position snapshot is not matched")
                .to_owned(),
        );
        return "blocked".to_owned();
    }
    if input.close_required_count == 0 {
        reason_codes.push("already_flat".to_owned());
        return "closed".to_owned();
    }
    if input.close_required_count != 2 {
        reason_codes.push("position_imbalance".to_owned());
        return "emergency_de_risk".to_owned();
    }
    if let Some(runtime_risk) = input.runtime_risk.filter(|risk| risk.is_triggered()) {
        reason_codes.extend(runtime_risk.reason_codes.iter().cloned());
        return "emergency_de_risk".to_owned();
    }
    if let Some(financial_risk) = input.financial_risk.filter(|risk| risk.is_triggered()) {
        reason_codes.extend(financial_risk.reason_codes.iter().cloned());
        return "close".to_owned();
    }
    if input.settlement_observed_mismatch {
        reason_codes.push("funding_settlement_observed_mismatch".to_owned());
    }
    if input.settlement_observed_complete {
        if input.rollover_allowed {
            reason_codes.push("rollover_next_funding_still_profitable".to_owned());
            return "rollover".to_owned();
        }
        if input.settlement_matched {
            reason_codes.push("funding_settlement_matched".to_owned());
        } else {
            reason_codes.push("funding_settlement_observed_complete".to_owned());
        }
        return "close".to_owned();
    }
    if input.settlement_matched {
        reason_codes.push("funding_settlement_matched".to_owned());
        return "close".to_owned();
    }
    if input.unknown_recovery_exit {
        reason_codes.push("unknown_recovery_settlement_bypass".to_owned());
        return "emergency_de_risk".to_owned();
    }
    reason_codes.push("waiting_for_funding_settlement".to_owned());
    "hold".to_owned()
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_runtime_risk_summary(
    row: &FundingArbMarketRow,
    position_snapshot: &FundingPrivatePositionSnapshot,
    leg_a: &FundingArbExitLegSnapshot,
    leg_b: &FundingArbExitLegSnapshot,
    private_accounts: &FundingPrivateAccountReconciliationSummary,
) -> RuntimeResult<FundingArbExitRuntimeRiskSummary> {
    let mut reason_codes = Vec::new();
    let mut reasons = Vec::new();
    let mut warning_codes = Vec::new();
    let mut warnings = Vec::new();
    let mut min_liquidation_buffer_bps: Option<i128> = None;
    let mut max_adl_rank_indicator: Option<i128> = None;

    for leg in [leg_a, leg_b] {
        if !leg.close_required {
            continue;
        }
        let Some(entry) =
            funding_arb_private_position_entry_for_leg(row, &leg.leg, position_snapshot)
        else {
            funding_arb_push_unique_reason_code(
                &mut reason_codes,
                "private_position_runtime_missing",
            );
            reasons.push(format!(
                "{} {} active leg is missing from private position snapshot",
                leg.leg.venue_family, leg.leg.role
            ));
            continue;
        };

        match funding_arb_exit_liquidation_buffer_bps(row, &leg.leg, entry)? {
            Some(buffer) => {
                min_liquidation_buffer_bps = Some(match min_liquidation_buffer_bps {
                    Some(current) if current <= buffer => current,
                    _ => buffer,
                });
                if buffer <= FUNDING_ARB_EXIT_DEFAULT_MIN_LIQUIDATION_BUFFER_BPS {
                    funding_arb_push_unique_reason_code(
                        &mut reason_codes,
                        "liquidation_buffer_too_thin",
                    );
                    reasons.push(format!(
                        "{} {} liquidation buffer {} bps is at or below minimum {} bps",
                        leg.leg.venue_family,
                        leg.leg.role,
                        buffer,
                        FUNDING_ARB_EXIT_DEFAULT_MIN_LIQUIDATION_BUFFER_BPS
                    ));
                }
            }
            None => {
                funding_arb_push_unique_reason_code(
                    &mut warning_codes,
                    "liquidation_buffer_missing",
                );
                warnings.push(format!(
                    "{} {} liquidation buffer is unavailable from current private/public snapshots",
                    leg.leg.venue_family, leg.leg.role
                ));
            }
        }

        if let Some(rank) = funding_arb_exit_adl_rank(entry)? {
            max_adl_rank_indicator = Some(match max_adl_rank_indicator {
                Some(current) if current >= rank => current,
                _ => rank,
            });
            if rank >= FUNDING_ARB_EXIT_ADL_WARNING_RANK {
                funding_arb_push_unique_reason_code(&mut warning_codes, "adl_warning");
                warnings.push(format!(
                    "{} {} ADL rank {} is at or above warning rank {}",
                    leg.leg.venue_family, leg.leg.role, rank, FUNDING_ARB_EXIT_ADL_WARNING_RANK
                ));
            }
        }
        if let Some(adl_state) = entry
            .adl_state
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
        {
            let normalized = adl_state.to_ascii_lowercase();
            if normalized.contains("deleveraging") || normalized.contains("liquidat") {
                let code = if normalized.contains("liquidat") {
                    "liquidation_state"
                } else {
                    "adl_deleveraging"
                };
                funding_arb_push_unique_reason_code(&mut reason_codes, code);
                reasons.push(format!(
                    "{} {} risk state is `{adl_state}`",
                    leg.leg.venue_family, leg.leg.role
                ));
            } else if normalized.contains("warning") || normalized.contains("adl") {
                funding_arb_push_unique_reason_code(&mut warning_codes, "adl_warning");
                warnings.push(format!(
                    "{} {} ADL state is `{adl_state}`",
                    leg.leg.venue_family, leg.leg.role
                ));
            }
        }
    }

    let position_imbalance_bps =
        funding_arb_exit_position_imbalance_bps(leg_a.signed_quantity, leg_b.signed_quantity)?;
    if let Some(imbalance) = position_imbalance_bps {
        if imbalance > FUNDING_ARB_EXIT_DEFAULT_MAX_POSITION_IMBALANCE_BPS {
            funding_arb_push_unique_reason_code(&mut reason_codes, "position_imbalance");
            reasons.push(format!(
                "funding arb leg quantity imbalance {} bps exceeds maximum {} bps",
                imbalance, FUNDING_ARB_EXIT_DEFAULT_MAX_POSITION_IMBALANCE_BPS
            ));
        }
    }

    if private_accounts.status != "Matched" {
        let code = if private_accounts.status == "Insufficient" {
            "private_margin_buffer_too_thin"
        } else {
            "private_margin_buffer_unavailable"
        };
        funding_arb_push_unique_reason_code(&mut warning_codes, code);
        warnings.push(private_accounts.reason.clone().unwrap_or_else(|| {
            format!(
                "private account runtime margin status is {}",
                private_accounts.status
            )
        }));
    }

    Ok(FundingArbExitRuntimeRiskSummary {
        status: if !reason_codes.is_empty() {
            "Triggered"
        } else if !warning_codes.is_empty() {
            "Warning"
        } else {
            "Matched"
        }
        .to_owned(),
        reason_codes,
        reason: (!reasons.is_empty()).then(|| reasons.join("; ")),
        warning_codes,
        warning: (!warnings.is_empty()).then(|| warnings.join("; ")),
        min_liquidation_buffer_bps,
        min_margin_buffer_usd: private_accounts.min_margin_buffer_usd.clone(),
        position_imbalance_bps,
        max_adl_rank_indicator,
    })
}

#[cfg(feature = "live-exec")]
fn funding_arb_push_unique_reason_code(reason_codes: &mut Vec<String>, code: &str) {
    if !reason_codes.iter().any(|existing| existing == code) {
        reason_codes.push(code.to_owned());
    }
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_liquidation_buffer_bps(
    row: &FundingArbMarketRow,
    leg: &FundingArbPositionLegState,
    entry: &FundingPrivatePositionEntry,
) -> RuntimeResult<Option<i128>> {
    let Some(mark_raw) = entry
        .mark_price
        .as_deref()
        .filter(|value| !value.trim().is_empty())
        .or_else(|| funding_arb_row_mark_price(row, leg))
    else {
        return Ok(None);
    };
    let Some(liquidation_raw) = entry
        .liquidation_price
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    else {
        return Ok(None);
    };
    let mark = MonitorDecimal::parse("funding_arb_exit.mark_price", mark_raw)?;
    let liquidation = MonitorDecimal::parse("funding_arb_exit.liquidation_price", liquidation_raw)?;
    if mark.raw <= 0 || liquidation.raw <= 0 {
        return Ok(None);
    }
    let diff = if funding_arb_exit_leg_is_short(leg, entry)? {
        liquidation.raw.checked_sub(mark.raw)
    } else {
        mark.raw.checked_sub(liquidation.raw)
    }
    .ok_or_else(|| RuntimeError::LiveMarketData {
        message: "funding arb liquidation buffer calculation overflowed".to_owned(),
    })?;
    if diff <= 0 {
        return Ok(Some(0));
    }
    diff.checked_mul(10_000)
        .and_then(|value| value.checked_div(mark.raw))
        .map(Some)
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "funding arb liquidation buffer bps calculation overflowed".to_owned(),
        })
}

#[cfg(feature = "live-exec")]
fn funding_arb_row_mark_price<'a>(
    row: &'a FundingArbMarketRow,
    leg: &FundingArbPositionLegState,
) -> Option<&'a str> {
    let family = normalize_venue_family(&leg.venue_family);
    let raw = if family == normalize_venue_family(&row.venue_a_family) {
        row.venue_a_mark_price.as_str()
    } else if family == normalize_venue_family(&row.venue_b_family) {
        row.venue_b_mark_price.as_str()
    } else {
        ""
    };
    (!raw.trim().is_empty()).then_some(raw)
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_leg_is_short(
    leg: &FundingArbPositionLegState,
    entry: &FundingPrivatePositionEntry,
) -> RuntimeResult<bool> {
    let signed_quantity = funding_private_position_entry_signed_quantity(entry)?;
    if let Some(position_side) =
        funding_private_position_direction_from_entry(entry, signed_quantity)
    {
        return Ok(position_side == FundingPrivatePositionSide::Short);
    }
    let role = leg.role.to_ascii_lowercase();
    if role.contains("short") {
        return Ok(true);
    }
    if role.contains("long") {
        return Ok(false);
    }
    if leg.side == OrderSide::Sell {
        return Ok(true);
    }
    Ok(signed_quantity.raw < 0)
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_adl_rank(entry: &FundingPrivatePositionEntry) -> RuntimeResult<Option<i128>> {
    let Some(raw) = entry
        .adl_rank_indicator
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return Ok(None);
    };
    let parsed = MonitorDecimal::parse("funding_arb_exit.adl_rank_indicator", raw)?;
    let scale = 10_i128.pow(MonitorDecimal::SCALE_DIGITS as u32);
    Ok(Some(parsed.raw / scale))
}

#[cfg(feature = "live-exec")]
fn funding_arb_exit_position_imbalance_bps(
    left: MonitorDecimal,
    right: MonitorDecimal,
) -> RuntimeResult<Option<i128>> {
    let left_abs = left
        .raw
        .checked_abs()
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "funding arb left quantity absolute value overflowed".to_owned(),
        })?;
    let right_abs = right
        .raw
        .checked_abs()
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "funding arb right quantity absolute value overflowed".to_owned(),
        })?;
    let denominator = left_abs.max(right_abs);
    if denominator == 0 {
        return Ok(None);
    }
    let delta = left_abs
        .checked_sub(right_abs)
        .and_then(|value| value.checked_abs())
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "funding arb position imbalance calculation overflowed".to_owned(),
        })?;
    delta
        .checked_mul(10_000)
        .and_then(|value| value.checked_div(denominator))
        .map(Some)
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "funding arb position imbalance bps calculation overflowed".to_owned(),
        })
}

#[cfg(feature = "live-exec")]
fn funding_arb_monitor_row_includes_family(row: &FundingArbMarketRow, family: &str) -> bool {
    let family = normalize_venue_family(family);
    normalize_venue_family(&row.venue_a_family) == family
        || normalize_venue_family(&row.venue_b_family) == family
}

