fn build_public_basis_portfolio_state(
    spec: &BasisPipelineSpec,
    source_event_refs: &[String],
    as_of: UtcTimestamp,
) -> RuntimeResult<PortfolioState> {
    let portfolio_json = format!(
        r#"{{
  "schema_version": "1.0.0",
  "portfolio_state_id": {},
  "as_of": {},
  "source_event_refs": {},
  "balances": [],
  "positions": [],
  "reservations": [],
  "open_orders": [],
  "pending_transfers": [],
  "confidence": 0.5,
  "missing_data_flags": [
    "PRIVATE_BALANCE_UNAVAILABLE"
  ],
  "state_hash": {}
}}"#,
        json_string(&spec.portfolio_state_id),
        json_string(&as_of.to_string()),
        json_string_array(source_event_refs),
        json_string(&spec.portfolio_state_hash),
    );
    Ok(from_json_strict::<PortfolioState>(&portfolio_json)?)
}

fn build_public_funding_arb_portfolio_state(
    spec: &CrossExchangeFundingArbPipelineSpec,
    source_event_refs: &[String],
    as_of: UtcTimestamp,
) -> RuntimeResult<PortfolioState> {
    build_public_funding_arb_portfolio_state_with_missing_flags(
        spec,
        source_event_refs,
        as_of,
        funding_arb_public_missing_data_flags(false, false, false, false, false),
        &[],
    )
}

fn build_public_funding_arb_portfolio_state_with_missing_flags(
    spec: &CrossExchangeFundingArbPipelineSpec,
    source_event_refs: &[String],
    as_of: UtcTimestamp,
    missing_data_flags: Vec<String>,
    private_account_balances: &[FundingPrivatePortfolioBalance],
) -> RuntimeResult<PortfolioState> {
    let portfolio_json = format!(
        r#"{{
  "schema_version": "1.0.0",
  "portfolio_state_id": {},
  "as_of": {},
  "source_event_refs": {},
  "balances": {},
  "positions": [],
  "reservations": [],
  "open_orders": [],
  "pending_transfers": [],
  "confidence": 0.5,
  "missing_data_flags": {},
  "state_hash": {}
}}"#,
        json_string(&spec.portfolio_state_id),
        json_string(&as_of.to_string()),
        json_string_array(source_event_refs),
        funding_private_portfolio_balances_json(private_account_balances),
        json_string_array(&missing_data_flags),
        json_string(&spec.portfolio_state_hash),
    );
    Ok(from_json_strict::<PortfolioState>(&portfolio_json)?)
}

fn funding_private_portfolio_balances_from_reconciliation(
    spec: &CrossExchangeFundingArbPipelineSpec,
    private_accounts: &FundingPrivateAccountReconciliationSummary,
    observed_at: UtcTimestamp,
) -> Vec<FundingPrivatePortfolioBalance> {
    if !private_accounts.has_balance_snapshot()
        || !funding_private_snapshot_is_fresh(
            &private_accounts.status,
            private_accounts.snapshot_updated_at.as_deref(),
            observed_at,
        )
    {
        return Vec::new();
    }
    let Some(free_usd) = private_accounts
        .min_available_usd
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    else {
        return Vec::new();
    };
    let mut seen = BTreeSet::new();
    [
        spec.strategy_config.venues.venue_a.account_id.as_str(),
        spec.strategy_config.venues.venue_b.account_id.as_str(),
    ]
    .into_iter()
    .filter_map(|account_id| {
        if !seen.insert(account_id) {
            return None;
        }
        Some(FundingPrivatePortfolioBalance {
            account_id: account_id.to_owned(),
            free_usd: free_usd.to_owned(),
        })
    })
    .collect()
}

fn funding_private_snapshot_is_fresh(
    status: &str,
    updated_at: Option<&str>,
    observed_at: UtcTimestamp,
) -> bool {
    if status == "NotProvided" {
        return false;
    }
    let Some(updated_at) = updated_at.filter(|value| !value.trim().is_empty()) else {
        return false;
    };
    let Ok(snapshot_time) = UtcTimestamp::from_str(updated_at) else {
        return false;
    };
    utc_timestamp_abs_delta_ms(observed_at, snapshot_time)
        <= FUNDING_ARB_PRIVATE_SNAPSHOT_MAX_AGE_MS
}

fn funding_private_portfolio_balances_json(balances: &[FundingPrivatePortfolioBalance]) -> String {
    format!(
        "[{}]",
        balances
            .iter()
            .map(funding_private_portfolio_balance_json)
            .collect::<Vec<_>>()
            .join(",")
    )
}

fn funding_private_portfolio_balance_json(balance: &FundingPrivatePortfolioBalance) -> String {
    let account_component = basis_identifier_component(&balance.account_id);
    format!(
        "{{\"balance_id\":{},\"asset_id\":\"asset:USDT\",\"account_id\":{},\"custody_location_id\":{},\"free\":{},\"locked\":\"0\",\"reserved\":\"0\",\"pending\":\"0\",\"borrowed\":\"0\",\"lent\":\"0\",\"unsettled\":\"0\"}}",
        json_string(&format!("bal:funding-arb-{account_component}-usdt")),
        json_string(&balance.account_id),
        json_string(&format!("custody:funding-arb-{account_component}")),
        json_string(&balance.free_usd),
    )
}

fn funding_arb_public_missing_data_flags(
    _funding_settlement_reconciled: bool,
    private_balance_reconciled: bool,
    private_margin_reconciled: bool,
    private_positions_reconciled: bool,
    _private_execution_reconciled: bool,
) -> Vec<String> {
    let mut flags = Vec::new();
    // Funding settlement and private execution are lifecycle checks: settlement gates exit,
    // and private execution reconciliation exists only after a dispatch attempt.
    if !private_balance_reconciled {
        flags.push("PRIVATE_BALANCE_UNAVAILABLE".to_owned());
    }
    if !private_margin_reconciled {
        flags.push("PRIVATE_MARGIN_UNAVAILABLE".to_owned());
    }
    if !private_positions_reconciled {
        flags.push("PRIVATE_POSITION_UNAVAILABLE".to_owned());
    }
    flags
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct BinanceGuardedLiveQuote {
    event_id: String,
    observed_at: String,
    best_bid: String,
    best_ask: String,
    bid_size: String,
    ask_size: String,
}

#[derive(Clone, Debug, Eq, PartialEq)]
#[cfg(feature = "live-exec")]
struct BinanceBasisGuardedLiveSignalContext {
    symbol: String,
    symbol_slug: String,
    spot_instrument_id: String,
    perp_instrument_id: String,
    base_asset_id: String,
    spot_event_id: String,
    perp_event_id: String,
    premium_event_id: String,
    observed_at: String,
    spot_bid: String,
    spot_ask: String,
    spot_bid_size: String,
    spot_ask_size: String,
    perp_bid: String,
    perp_ask: String,
    perp_bid_size: String,
    perp_ask_size: String,
    last_funding_rate: String,
    mark_price: String,
    index_price: String,
    next_funding_time_ms: String,
    signal: SpotPerpBasisSignal,
}

fn load_binance_guarded_live_spot_quote(
    market_artifacts_dir: &Path,
) -> RuntimeResult<BinanceGuardedLiveQuote> {
    let path = market_artifacts_dir.join("stored_events.jsonl");
    let input = read_utf8(&path)?;
    for (index, line) in input.lines().enumerate() {
        if line.trim().is_empty() {
            continue;
        }
        let event = from_json_strict::<NormalizedEvent>(line).map_err(RuntimeError::from)?;
        let instrument_id = event
            .instrument_id
            .as_ref()
            .and_then(|value| value.as_ref())
            .map(|value| value.as_str());
        let venue_id = event
            .venue_id
            .as_ref()
            .and_then(|value| value.as_ref())
            .map(|value| value.as_str());
        if event.event_type == NormalizedEventType::NormalizedMarketDataEvent
            && instrument_id == Some(BINANCE_BASIS_SPOT_INSTRUMENT_ID)
            && venue_id == Some(BINANCE_BASIS_SPOT_VENUE_ID)
            && payload_string(&event, "kind")? == "BookTicker"
            && payload_string(&event, "venue_symbol")? == BASIS_SYMBOL
        {
            return Ok(BinanceGuardedLiveQuote {
                event_id: event.event_id.as_str().to_owned(),
                observed_at: event.timestamp_event.as_str().to_owned(),
                best_bid: payload_string(&event, "best_bid")?.to_owned(),
                best_ask: payload_string(&event, "best_ask")?.to_owned(),
                bid_size: payload_string(&event, "bid_size")?.to_owned(),
                ask_size: payload_string(&event, "ask_size")?.to_owned(),
            });
        }
        if index > 1000 {
            return Err(RuntimeError::Module {
                module: "arb-runtime",
                message: format!(
                    "{} contains too many events for a single preflight preview",
                    path.display()
                ),
            });
        }
    }
    Err(RuntimeError::MissingFixture { path })
}

fn write_binance_guarded_live_auto_market_artifacts(
    raw_spot_book: &str,
    raw_response_ref: &str,
    ingested_at: UtcTimestamp,
    output_dir: &Path,
) -> RuntimeResult<BinanceGuardedLiveQuote> {
    fs::create_dir_all(output_dir).map_err(|error| RuntimeError::Io {
        path: output_dir.to_path_buf(),
        message: error.to_string(),
    })?;
    let mut adapter = BinancePublicBookTickerAdapter::new(
        VenueId::new(BINANCE_BASIS_SPOT_VENUE_ID)?,
        binance_basis_instrument(BASIS_SYMBOL, BINANCE_BASIS_SPOT_INSTRUMENT_ID)?,
        BinancePublicMarket::Spot,
        ingested_at,
        MARKET_DATA_MAX_AGE_MS,
    )?;
    let batch = adapter.ingest_book_ticker_json(raw_spot_book, raw_response_ref, ingested_at)?;
    let quote = BinanceGuardedLiveQuote {
        event_id: batch.normalized_event.event_id.as_str().to_owned(),
        observed_at: batch.normalized_event.timestamp_event.as_str().to_owned(),
        best_bid: payload_string(&batch.normalized_event, "best_bid")?.to_owned(),
        best_ask: payload_string(&batch.normalized_event, "best_ask")?.to_owned(),
        bid_size: payload_string(&batch.normalized_event, "bid_size")?.to_owned(),
        ask_size: payload_string(&batch.normalized_event, "ask_size")?.to_owned(),
    };
    write_utf8(
        output_dir.join("stored_events.jsonl"),
        &jsonl_from_lines(vec![
            to_canonical_json(&batch.raw_event),
            to_canonical_json(&batch.normalized_event),
        ]),
    )?;
    write_utf8(
        output_dir.join("spot_book_ticker.raw.json"),
        &format!("{raw_spot_book}\n"),
    )?;
    Ok(quote)
}

#[cfg(feature = "live-exec")]
fn write_binance_basis_guarded_live_auto_market_artifacts(
    inputs: BinanceBasisRawInputs<'_>,
    ingested_at: UtcTimestamp,
    min_net_bps: i128,
    output_dir: &Path,
) -> RuntimeResult<BinanceBasisGuardedLiveSignalContext> {
    let symbol = normalize_cex_usdt_basis_symbol(inputs.symbol, "Binance")?;
    let spot_instrument_id = binance_basis_spot_instrument_id(&symbol)?;
    let perp_instrument_id = binance_basis_perp_instrument_id(&symbol)?;
    let base_asset_id = basis_base_asset_id_from_cex_symbol(&symbol)?;
    fs::create_dir_all(output_dir).map_err(|error| RuntimeError::Io {
        path: output_dir.to_path_buf(),
        message: error.to_string(),
    })?;
    let events = ingest_binance_basis_public_json(inputs, ingested_at)?;
    write_utf8(
        output_dir.join("stored_events.jsonl"),
        &canonical_jsonl(&events),
    )?;
    write_utf8(
        output_dir.join("spot_book_ticker.raw.json"),
        &format!("{}\n", inputs.raw_spot_book),
    )?;
    write_utf8(
        output_dir.join("perp_book_ticker.raw.json"),
        &format!("{}\n", inputs.raw_perp_book),
    )?;
    write_utf8(
        output_dir.join("premium_index.raw.json"),
        &format!("{}\n", inputs.raw_premium_index),
    )?;

    let spot =
        find_binance_basis_book_event(&events, BINANCE_BASIS_SPOT_VENUE_ID, &spot_instrument_id)?;
    let perp =
        find_binance_basis_book_event(&events, BINANCE_BASIS_PERP_VENUE_ID, &perp_instrument_id)?;
    let premium = find_basis_premium_event(
        &events,
        BINANCE_BASIS_PERP_VENUE_ID,
        &perp_instrument_id,
        "Binance basis premium index",
    )?;
    let (spot_depth, perp_depth) = if basis_raw_refs_use_fixture_depth(&[
        inputs.spot_book_ref,
        inputs.perp_book_ref,
        inputs.premium_index_ref,
    ]) {
        (
            public_order_book_depth_from_top_of_book(
                payload_string(spot, "best_bid")?,
                payload_string(spot, "bid_size")?,
                payload_string(spot, "best_ask")?,
                payload_string(spot, "ask_size")?,
            ),
            public_order_book_depth_from_top_of_book(
                payload_string(perp, "best_bid")?,
                payload_string(perp, "bid_size")?,
                payload_string(perp, "best_ask")?,
                payload_string(perp, "ask_size")?,
            ),
        )
    } else {
        (
            fetch_public_order_book_depth(PublicOrderBookDepthVenue::BinanceSpot, &symbol)?,
            fetch_public_order_book_depth(PublicOrderBookDepthVenue::BinanceUsdmPerp, &symbol)?,
        )
    };
    let signal = evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
        symbol: symbol.clone(),
        spot_best_bid: payload_string(spot, "best_bid")?.to_owned(),
        spot_best_ask: payload_string(spot, "best_ask")?.to_owned(),
        spot_ask_size: Some(payload_string(spot, "ask_size")?.to_owned()),
        spot_ask_depth: spot_depth.ask_depth.clone(),
        perp_best_bid: payload_string(perp, "best_bid")?.to_owned(),
        perp_best_ask: payload_string(perp, "best_ask")?.to_owned(),
        perp_bid_size: Some(payload_string(perp, "bid_size")?.to_owned()),
        perp_bid_depth: perp_depth.bid_depth.clone(),
        last_funding_rate: payload_string(premium, "last_funding_rate")?.to_owned(),
        notional_usd: BINANCE_GUARDED_LIVE_NOTIONAL_USDT.to_owned(),
        spot_taker_fee_bps: BINANCE_SPOT_TAKER_FEE_BPS.to_owned(),
        perp_taker_fee_bps: BINANCE_PERP_TAKER_FEE_BPS.to_owned(),
        slippage_buffer_bps: BASIS_MONITOR_DEFAULT_SLIPPAGE_BUFFER_BPS,
        min_net_bps,
    })
    .map_err(|message| RuntimeError::Module {
        module: "arb-strategies",
        message,
    })?;

    Ok(BinanceBasisGuardedLiveSignalContext {
        symbol: symbol.clone(),
        symbol_slug: basis_symbol_slug(&symbol),
        spot_instrument_id,
        perp_instrument_id,
        base_asset_id,
        spot_event_id: spot.event_id.as_str().to_owned(),
        perp_event_id: perp.event_id.as_str().to_owned(),
        premium_event_id: premium.event_id.as_str().to_owned(),
        observed_at: ingested_at.to_string(),
        spot_bid: payload_string(spot, "best_bid")?.to_owned(),
        spot_ask: payload_string(spot, "best_ask")?.to_owned(),
        spot_bid_size: payload_string(spot, "bid_size")?.to_owned(),
        spot_ask_size: payload_string(spot, "ask_size")?.to_owned(),
        perp_bid: payload_string(perp, "best_bid")?.to_owned(),
        perp_ask: payload_string(perp, "best_ask")?.to_owned(),
        perp_bid_size: payload_string(perp, "bid_size")?.to_owned(),
        perp_ask_size: payload_string(perp, "ask_size")?.to_owned(),
        last_funding_rate: payload_string(premium, "last_funding_rate")?.to_owned(),
        mark_price: payload_string(premium, "mark_price")?.to_owned(),
        index_price: payload_string(premium, "index_price")?.to_owned(),
        next_funding_time_ms: payload_scalar_text(premium, "next_funding_time_ms")?,
        signal,
    })
}

