impl FundingArbBlockingPathEntry {
    fn new(
        stage: impl Into<String>,
        blocker: impl Into<String>,
        reason: impl Into<String>,
    ) -> Self {
        Self {
            stage: stage.into(),
            blocker: blocker.into(),
            reason: reason.into(),
            pair_id: None,
            symbol: None,
            venue_a_family: None,
            venue_b_family: None,
            source_status: None,
            evidence: None,
        }
    }

    fn with_pair(mut self, pair_id: impl Into<String>, symbol: impl Into<String>) -> Self {
        self.pair_id = Some(pair_id.into());
        self.symbol = Some(symbol.into());
        self
    }

    fn with_venues(
        mut self,
        venue_a_family: impl Into<String>,
        venue_b_family: impl Into<String>,
    ) -> Self {
        self.venue_a_family = Some(venue_a_family.into());
        self.venue_b_family = Some(venue_b_family.into());
        self
    }

    fn with_source_status(mut self, source_status: impl Into<String>) -> Self {
        self.source_status = Some(source_status.into());
        self
    }

    fn with_evidence(mut self, evidence: impl Into<String>) -> Self {
        self.evidence = Some(evidence.into());
        self
    }

    fn to_json(&self) -> String {
        format!(
            "{{\"blocker\":{},\"evidence\":{},\"pair_id\":{},\"reason\":{},\"source_status\":{},\"stage\":{},\"symbol\":{},\"venue_a_family\":{},\"venue_b_family\":{}}}",
            json_string(&self.blocker),
            json_option_string(&self.evidence),
            json_option_string(&self.pair_id),
            json_string(&self.reason),
            json_option_string(&self.source_status),
            json_string(&self.stage),
            json_option_string(&self.symbol),
            json_option_string(&self.venue_a_family),
            json_option_string(&self.venue_b_family),
        )
    }
}

fn funding_arb_blocking_path_json(entries: &[FundingArbBlockingPathEntry]) -> String {
    format!(
        "[{}]",
        entries
            .iter()
            .map(FundingArbBlockingPathEntry::to_json)
            .collect::<Vec<_>>()
            .join(",")
    )
}

fn funding_arb_monitor_blocking_path(
    snapshot: &FundingArbMonitorSnapshot,
) -> Vec<FundingArbBlockingPathEntry> {
    let mut entries = funding_arb_monitor_root_blocking_path(snapshot);
    if snapshot.candidate_count == 0 {
        entries.extend(
            snapshot
                .rows
                .iter()
                .filter(|row| !row.is_candidate)
                .map(funding_arb_monitor_row_blocking_path_entry),
        );
    }
    entries
}

fn funding_arb_monitor_compact_blocking_path(
    snapshot: &FundingArbMonitorSnapshot,
) -> Vec<FundingArbBlockingPathEntry> {
    let mut entries = funding_arb_monitor_root_blocking_path(snapshot);
    if snapshot.candidate_count == 0 {
        entries.extend(funding_arb_monitor_row_blocking_path_groups(snapshot));
    }
    entries
}

fn funding_arb_monitor_root_blocking_path(
    snapshot: &FundingArbMonitorSnapshot,
) -> Vec<FundingArbBlockingPathEntry> {
    let mut entries = Vec::new();
    if snapshot.source_error_count > 0
        || snapshot.status != "healthy"
        || snapshot.last_error.is_some()
    {
        let blocker = if snapshot.source_error_count > 0 {
            "source_error_count>0"
        } else if snapshot.status != "healthy" {
            "snapshot_status!=healthy"
        } else {
            "last_error_present"
        };
        let mut entry = FundingArbBlockingPathEntry::new(
            "venue_status",
            blocker,
            "阻断原因：上游 venue status 不完整或 source 报错",
        )
        .with_evidence(format!(
            "status={} source_count={} source_error_count={} last_error={}",
            snapshot.status,
            snapshot.source_count,
            snapshot.source_error_count,
            snapshot.last_error.as_deref().unwrap_or("null")
        ));
        if let Some(reason) = &snapshot.last_error {
            entry.reason = format!("阻断原因：上游 venue status 不完整；{reason}");
        }
        entries.push(entry);
    }
    if snapshot.candidate_count == 0 {
        entries.push(
            FundingArbBlockingPathEntry::new(
                "opportunity_source",
                "candidate_count=0",
                funding_arb_candidate_count_zero_reason(snapshot),
            )
            .with_evidence(format!(
                "status={} total_rows={} source_count={} source_error_count={} min_net_funding_bps={}",
                snapshot.status,
                snapshot.total_rows,
                snapshot.source_count,
                snapshot.source_error_count,
                snapshot.min_net_funding_bps
            )),
        );
    }
    entries
}

#[derive(Clone, Debug)]
struct FundingArbBlockingPathGroup {
    blocker: String,
    reason: String,
    source_status: String,
    count: usize,
    sample_pairs: Vec<String>,
    venue_pairs: BTreeSet<String>,
}

impl FundingArbBlockingPathGroup {
    fn new(row: &FundingArbMarketRow) -> Self {
        Self {
            blocker: format!("{}:is_candidate=false", row.source_status),
            reason: funding_arb_monitor_row_blocking_summary(row).to_owned(),
            source_status: row.source_status.clone(),
            count: 0,
            sample_pairs: Vec::new(),
            venue_pairs: BTreeSet::new(),
        }
    }

    fn observe(&mut self, row: &FundingArbMarketRow) {
        self.count = self.count.saturating_add(1);
        if self.sample_pairs.len() < FUNDING_ARB_BLOCKING_PATH_GROUP_SAMPLE_LIMIT {
            self.sample_pairs
                .push(format!("{}:{}", row.pair_id, row.symbol));
        }
        self.venue_pairs
            .insert(format!("{}:{}", row.venue_a_family, row.venue_b_family));
    }

    fn into_entry(
        self,
        total_non_candidate_rows: usize,
        total_groups: usize,
        truncated: bool,
    ) -> FundingArbBlockingPathEntry {
        FundingArbBlockingPathEntry::new(
            "opportunity_row_group",
            self.blocker,
            format!("{}；同类 pair_count={}", self.reason, self.count),
        )
        .with_source_status(self.source_status)
        .with_evidence(format!(
            "pair_count={} total_non_candidate_rows={} group_count={} group_limit={} groups_truncated={} sample_pairs={} venue_pairs={}",
            self.count,
            total_non_candidate_rows,
            total_groups,
            FUNDING_ARB_BLOCKING_PATH_GROUP_LIMIT,
            truncated,
            self.sample_pairs.join("|"),
            self.venue_pairs.into_iter().collect::<Vec<_>>().join("|")
        ))
    }
}

fn funding_arb_monitor_row_blocking_path_groups(
    snapshot: &FundingArbMonitorSnapshot,
) -> Vec<FundingArbBlockingPathEntry> {
    let mut groups = BTreeMap::<(String, String), FundingArbBlockingPathGroup>::new();
    let mut total_non_candidate_rows = 0usize;
    for row in snapshot.rows.iter().filter(|row| !row.is_candidate) {
        total_non_candidate_rows = total_non_candidate_rows.saturating_add(1);
        let key = (
            row.source_status.clone(),
            funding_arb_monitor_row_blocking_summary(row).to_owned(),
        );
        groups
            .entry(key)
            .or_insert_with(|| FundingArbBlockingPathGroup::new(row))
            .observe(row);
    }
    let total_groups = groups.len();
    let truncated = total_groups > FUNDING_ARB_BLOCKING_PATH_GROUP_LIMIT;
    let mut groups = groups.into_values().collect::<Vec<_>>();
    groups.sort_by(|left, right| {
        right
            .count
            .cmp(&left.count)
            .then_with(|| left.blocker.cmp(&right.blocker))
            .then_with(|| left.reason.cmp(&right.reason))
    });
    groups
        .into_iter()
        .take(FUNDING_ARB_BLOCKING_PATH_GROUP_LIMIT)
        .map(|group| group.into_entry(total_non_candidate_rows, total_groups, truncated))
        .collect()
}

fn funding_arb_candidate_count_zero_reason(snapshot: &FundingArbMonitorSnapshot) -> String {
    if snapshot.source_error_count > 0
        || snapshot.status != "healthy"
        || snapshot.last_error.is_some()
    {
        return format!(
            "阻断点：candidate_count=0；阻断原因：上游 venue status 不完整；snapshot_status={}；source_error_count={}",
            snapshot.status, snapshot.source_error_count
        );
    }
    if snapshot.total_rows == 0 {
        return "阻断点：candidate_count=0；阻断原因：没有可比较的跨交易所 funding pair 行"
            .to_owned();
    }
    "阻断点：candidate_count=0；阻断原因：所有 funding-arb pair 均未通过候选门槛".to_owned()
}

fn funding_arb_monitor_row_blocking_path_entry(
    row: &FundingArbMarketRow,
) -> FundingArbBlockingPathEntry {
    FundingArbBlockingPathEntry::new(
        "opportunity_row",
        format!("{}:is_candidate=false", row.source_status),
        funding_arb_monitor_row_blocking_reason(row),
    )
    .with_pair(row.pair_id.clone(), row.symbol.clone())
    .with_venues(row.venue_a_family.clone(), row.venue_b_family.clone())
    .with_source_status(row.source_status.clone())
    .with_evidence(funding_arb_monitor_row_blocking_evidence(row))
}

fn funding_arb_monitor_row_blocking_reason(row: &FundingArbMarketRow) -> String {
    let summary = funding_arb_monitor_row_blocking_summary(row);
    match row
        .reason
        .as_deref()
        .filter(|reason| !reason.trim().is_empty())
    {
        Some(detail) => format!("{summary}；{detail}"),
        None => summary.to_owned(),
    }
}

fn funding_arb_monitor_row_blocking_summary(row: &FundingArbMarketRow) -> &'static str {
    match row.source_status.as_str() {
        "invalid_symbol" => "阻断原因：交易所原生符号校验失败",
        "source_not_ready" => "阻断原因：上游 venue status 不完整",
        "missing_perp_top_of_book" => {
            "阻断原因：上游 perp top-of-book、mark/index 或盘口数量字段缺失"
        }
        "invalid_perp_top_of_book" => "阻断原因：上游 perp top-of-book 价格或数量非法",
        "mark_index_divergence" => "阻断原因：mark/index 价格偏离超过阈值",
        "complete" => match row.reason.as_deref().unwrap_or_default() {
            reason if reason.contains("net_funding_bps=") => {
                "阻断原因：净 funding 收益低于最小阈值"
            }
            reason
                if reason.contains("insufficient top-of-book depth")
                    || reason.contains("insufficient order-book depth") =>
            {
                "阻断原因：盘口深度不足"
            }
            reason if reason.contains("entry_price_divergence_bps=") => {
                "阻断原因：入场价格偏离超过阈值"
            }
            _ => "阻断原因：策略信号未通过候选门槛",
        },
        _ => "阻断原因：该 pair 未通过 funding-arb 候选门槛",
    }
}

fn funding_arb_monitor_row_blocking_evidence(row: &FundingArbMarketRow) -> String {
    format!(
        "venue_a={} venue_b={} gross_funding_spread_bps={} total_cost_bps={} net_funding_bps={} entry_price_edge_bps={} expected_funding_usd={}",
        row.venue_a_family,
        row.venue_b_family,
        row.gross_funding_spread_bps.as_deref().unwrap_or("null"),
        row.total_cost_bps.as_deref().unwrap_or("null"),
        row.net_funding_bps.as_deref().unwrap_or("null"),
        row.entry_price_edge_bps.as_deref().unwrap_or("null"),
        row.expected_funding_usd.as_deref().unwrap_or("null")
    )
}

fn basis_monitor_blocking_path(
    snapshot: &BinanceBasisMonitorSnapshot,
) -> Vec<FundingArbBlockingPathEntry> {
    let mut entries = Vec::new();
    if snapshot.status != "healthy" {
        let mut entry = FundingArbBlockingPathEntry::new(
            "venue_status",
            "status!=healthy",
            "阻断原因：spot-perp-basis 上游状态不完整",
        )
        .with_evidence(format!(
            "status={} last_error={}",
            snapshot.status,
            snapshot.last_error.as_deref().unwrap_or("null")
        ));
        if let Some(error) = &snapshot.last_error {
            entry.reason = format!("阻断原因：spot-perp-basis 上游状态不完整；{error}");
        }
        entries.push(entry);
    }
    if snapshot.candidate_count == 0 {
        entries.push(
            FundingArbBlockingPathEntry::new(
                "opportunity_source",
                "candidate_count=0",
                basis_candidate_count_zero_reason(snapshot),
            )
            .with_evidence(format!(
                "status={} total_rows={} filtered_funding_count={} missing_spot_count={} missing_perp_count={} min_abs_funding_rate={} min_net_bps={}",
                snapshot.status,
                snapshot.total_rows,
                snapshot.filtered_funding_count,
                snapshot.missing_spot_count,
                snapshot.missing_perp_count,
                snapshot.min_abs_funding_rate,
                snapshot.min_net_bps
            )),
        );
        entries.extend(
            snapshot
                .rows
                .iter()
                .filter(|row| !row.is_candidate)
                .map(basis_monitor_row_blocking_path_entry),
        );
    }
    entries
}

fn basis_candidate_count_zero_reason(snapshot: &BinanceBasisMonitorSnapshot) -> String {
    if snapshot.status != "healthy" {
        return format!(
            "阻断点：candidate_count=0；阻断原因：spot-perp-basis 上游状态不完整；snapshot_status={}",
            snapshot.status
        );
    }
    if snapshot.total_rows == 0 && snapshot.filtered_funding_count > 0 {
        return "阻断点：candidate_count=0；阻断原因：funding rate 被 min_abs_funding_rate 过滤后没有可评估行"
            .to_owned();
    }
    if snapshot.total_rows == 0 {
        return "阻断点：candidate_count=0；阻断原因：没有可评估的 spot-perp-basis 行".to_owned();
    }
    if snapshot
        .rows
        .iter()
        .all(basis_row_has_incomplete_top_of_book)
    {
        if basis_snapshot_has_reason(snapshot, "MISSING_HYPERLIQUID_USDC_SPOT_CONTEXT") {
            if basis_snapshot_has_reason(snapshot, "MISSING_HYPERLIQUID_TOP_OF_BOOK_SIZE") {
                return "阻断点：candidate_count=0；阻断原因：Hyperliquid 多数永续合约没有 USDC 现货 context（现货上下文）；已有现货 context 的行缺少 perp WSS top-of-book 数量"
                    .to_owned();
            }
            return "阻断点：candidate_count=0；阻断原因：Hyperliquid 永续合约缺少 USDC 现货 context（现货上下文）"
                .to_owned();
        }
        return "阻断点：candidate_count=0；阻断原因：所有 spot-perp-basis 行的现货或永续 top-of-book 不完整"
            .to_owned();
    }
    if basis_snapshot_has_disabled_execution_profile(snapshot) {
        return "阻断点：candidate_count=0；阻断原因：该 venue 的 spot-perp-basis dry-run/execution profile 未启用；完整行情行按 fail closed，缺失行情行继续报告 top-of-book 缺失"
            .to_owned();
    }
    "阻断点：candidate_count=0；阻断原因：所有 spot-perp-basis 行均未通过候选门槛".to_owned()
}

fn basis_row_has_incomplete_top_of_book(row: &BinanceBasisMarketRow) -> bool {
    matches!(
        row.source_status.as_str(),
        "missing_spot" | "missing_perp" | "missing_spot_and_perp" | "missing_top_of_book_size"
    )
}

fn basis_snapshot_has_disabled_execution_profile(snapshot: &BinanceBasisMonitorSnapshot) -> bool {
    basis_snapshot_has_reason(snapshot, "DRY_RUN_NOT_SUPPORTED")
}

fn basis_snapshot_has_reason(snapshot: &BinanceBasisMonitorSnapshot, needle: &str) -> bool {
    snapshot.rows.iter().any(|row| {
        row.reason
            .as_deref()
            .is_some_and(|reason| reason.contains(needle))
    })
}

fn basis_monitor_row_blocking_path_entry(
    row: &BinanceBasisMarketRow,
) -> FundingArbBlockingPathEntry {
    FundingArbBlockingPathEntry::new(
        "opportunity_row",
        format!("{}:is_candidate=false", row.source_status),
        basis_monitor_row_blocking_reason(row),
    )
    .with_pair(
        format!("spot-perp-basis:{}", row.symbol),
        row.symbol.clone(),
    )
    .with_source_status(row.source_status.clone())
    .with_evidence(basis_monitor_row_blocking_evidence(row))
}

fn basis_monitor_row_blocking_reason(row: &BinanceBasisMarketRow) -> String {
    let summary = match row.source_status.as_str() {
        "missing_spot" => "阻断原因：现货 top-of-book 缺失",
        "missing_perp" => "阻断原因：永续 top-of-book 缺失",
        "missing_spot_and_perp" => "阻断原因：现货和永续 top-of-book 均缺失",
        "missing_funding" => "阻断原因：资金费率缺失",
        "missing_spot_and_funding" => "阻断原因：现货 top-of-book 和资金费率缺失",
        "missing_top_of_book_size" => "阻断原因：盘口数量缺失",
        "invalid_quote" => "阻断原因：报价非法",
        "complete" => {
            basis_complete_row_blocking_summary(row.reason.as_deref().unwrap_or_default())
        }
        _ => "阻断原因：该 spot-perp-basis 行未通过候选门槛",
    };
    match row
        .reason
        .as_deref()
        .filter(|reason| !reason.trim().is_empty())
    {
        Some(detail) => format!("{summary}；{detail}"),
        None => summary.to_owned(),
    }
}

fn basis_complete_row_blocking_summary(reason: &str) -> &'static str {
    if reason.contains("expected_profit_bps=") || reason.contains("below minimum") {
        "阻断原因：预期收益低于最小阈值"
    } else if reason.contains("insufficient top-of-book depth")
        || reason.contains("insufficient order-book depth")
    {
        "阻断原因：盘口深度不足"
    } else if reason.contains("DRY_RUN_NOT_SUPPORTED") {
        "阻断原因：该 venue 的 spot-perp-basis dry-run/execution profile 未启用"
    } else {
        "阻断原因：策略信号未通过候选门槛"
    }
}

fn basis_monitor_row_blocking_evidence(row: &BinanceBasisMarketRow) -> String {
    format!(
        "symbol={} gross_basis_bps={} total_cost_bps={} net_basis_bps={} expected_profit_usd={} last_funding_rate={}",
        row.symbol,
        row.gross_basis_bps.as_deref().unwrap_or("null"),
        row.total_cost_bps.as_deref().unwrap_or("null"),
        row.net_basis_bps.as_deref().unwrap_or("null"),
        row.expected_profit_usd.as_deref().unwrap_or("null"),
        row.last_funding_rate
    )
}

fn write_funding_arb_guarded_dry_run_artifacts(
    output_dir: &Path,
    snapshot: &FundingArbMonitorSnapshot,
    snapshot_json: &str,
    row: &FundingArbMarketRow,
    spec: &CrossExchangeFundingArbPipelineSpec,
    report: &FundingArbGuardedDryRunReport,
) -> RuntimeResult<()> {
    fs::create_dir_all(output_dir).map_err(|error| RuntimeError::Io {
        path: output_dir.to_path_buf(),
        message: error.to_string(),
    })?;
    let full_debug_artifacts = funding_arb_full_debug_artifacts_enabled()?;
    let artifact_mode = if full_debug_artifacts {
        "full_debug_snapshot"
    } else {
        "compact_guarded_dry_run_candidate"
    };
    let opportunities_snapshot_json = if full_debug_artifacts {
        snapshot_json.to_owned()
    } else {
        funding_arb_monitor_snapshot_compact_json(
            snapshot,
            std::slice::from_ref(row),
            artifact_mode,
        )
    };
    let retained_rows = if full_debug_artifacts {
        snapshot.rows.len()
    } else {
        1
    };
    write_utf8(
        output_dir.join("funding_arb_opportunities_snapshot.json"),
        &opportunities_snapshot_json,
    )?;
    write_utf8(
        output_dir.join("funding_arb_opportunities_snapshot_meta.json"),
        &funding_arb_opportunities_snapshot_meta_json(
            snapshot_json,
            snapshot,
            row,
            opportunities_snapshot_json.len(),
            retained_rows,
            artifact_mode,
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_candidate_row.json"),
        &format!("{}\n", row.to_json()),
    )?;
    write_utf8(
        output_dir.join("funding_arb_guarded_dry_run_report.json"),
        &format!(
            "{}\n",
            funding_arb_guarded_dry_run_report_json(row, spec, report)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_live_readiness.json"),
        &format!(
            "{}\n",
            funding_arb_live_readiness_json(&report.live_readiness)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_execution_preflight.json"),
        &format!(
            "{}\n",
            funding_arb_execution_preflight_json(&report.execution_preflight)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_private_execution_reconciliation.json"),
        &format!(
            "{}\n",
            funding_private_execution_reconciliation_json(&report.private_execution)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_venue_execution_capability.json"),
        &format!(
            "{}\n",
            funding_arb_venue_execution_capability_json(&report.venue_execution_capability)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_execution_constraints.json"),
        &format!(
            "{}\n",
            funding_arb_execution_constraints_json(&report.execution_constraints)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_exit_readiness.json"),
        &format!(
            "{}\n",
            funding_arb_exit_readiness_json(&report.exit_readiness)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_snapshot_lineage.json"),
        &format!(
            "{}\n",
            funding_arb_snapshot_lineage_json(&report.snapshot_lineage)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_settlement_reconciliation.json"),
        &format!(
            "{}\n",
            funding_settlement_reconciliation_json(&report.funding_settlement)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_settlement_ingestion.json"),
        &format!(
            "{}\n",
            funding_settlement_ingestion_json(&report.funding_settlement_ingestion)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_private_position_reconciliation.json"),
        &format!(
            "{}\n",
            funding_private_position_reconciliation_json(&report.private_positions)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_private_account_reconciliation.json"),
        &format!(
            "{}\n",
            funding_private_account_reconciliation_json(&report.private_accounts)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_carry_minimal_preflight_report.json"),
        &format!(
            "{}\n",
            funding_carry_minimal_preflight_report_json(row, report)
        ),
    )?;
    write_utf8(
        output_dir.join("funding_arb_guarded_dry_run_report.md"),
        &funding_arb_guarded_dry_run_report_markdown(row, spec, report),
    )
}

fn funding_arb_opportunities_snapshot_meta_json(
    original_snapshot_json: &str,
    snapshot: &FundingArbMonitorSnapshot,
    row: &FundingArbMarketRow,
    artifact_snapshot_bytes: usize,
    retained_rows: usize,
    artifact_mode: &str,
) -> String {
    format!(
        "{{\"artifact_mode\":{},\"artifact_snapshot_bytes\":{},\"original_candidate_count\":{},\"original_snapshot_bytes\":{},\"original_total_rows\":{},\"pair_id\":{},\"retained_rows\":{},\"schema_version\":\"1.0.0\",\"symbol\":{},\"updated_at\":{}}}\n",
        json_string(artifact_mode),
        artifact_snapshot_bytes,
        snapshot.candidate_count,
        original_snapshot_json.len(),
        snapshot.total_rows,
        json_string(&row.pair_id),
        retained_rows,
        json_string(&row.symbol),
        json_string(&snapshot.updated_at),
    )
}

#[cfg(feature = "live-exec")]
fn wallet_signer_preflight_summary_json(report: &WalletSignerPreflightReport) -> String {
    let summary_path = report
        .summary_path
        .as_ref()
        .map(|path| json_string(&path.display().to_string()))
        .unwrap_or_else(|| "null".to_owned());
    format!(
        "{{\"aster_status\":{},\"blocking_reasons\":{},\"checked_at\":{},\"hyperliquid_status\":{},\"mutable_execution_started\":{},\"summary_path\":{}}}",
        json_string(&report.aster_status),
        json_string_array(&report.blocking_reasons),
        json_string(&report.checked_at),
        json_string(&report.hyperliquid_status),
        report.mutable_execution_started,
        summary_path
    )
}

