fn current_utc_timestamp_string() -> String {
    current_utc_timestamp()
        .map(|timestamp| timestamp.to_string())
        .unwrap_or_else(|_| "timestamp-unavailable".to_owned())
}

fn write_http_json(stream: &mut TcpStream, status: u16, body: &str) -> std::io::Result<()> {
    write_http_response(stream, status, "application/json; charset=utf-8", body)
}

fn static_dashboard_gone_json(page: &str) -> String {
    format!(
        concat!(
            "{{\"error\":\"dashboard_migrated\",",
            "\"status\":\"gone\",",
            "\"page\":{},",
            "\"message\":\"HTML dashboard 已迁移到 Easy Tool；easy-arb 仅保留只读 JSON API。\"}}"
        ),
        json_string(page),
    )
}

fn write_http_response(
    stream: &mut TcpStream,
    status: u16,
    content_type: &str,
    body: &str,
) -> std::io::Result<()> {
    let reason = match status {
        200 => "OK",
        400 => "Bad Request",
        410 => "Gone",
        404 => "Not Found",
        405 => "Method Not Allowed",
        500 => "Internal Server Error",
        501 => "Not Implemented",
        503 => "Service Unavailable",
        _ => "OK",
    };
    write!(
        stream,
        "HTTP/1.1 {status} {reason}\r\nContent-Type: {content_type}\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        body.len(),
        body
    )
}

