        let bitget_raw = r#"{"action":"snapshot","arg":{"instType":"USDT-FUTURES","channel":"ticker","instId":"BTCUSDT"},"data":[{"instId":"BTCUSDT","bidPr":"101.00","bidSz":"1.2","askPr":"101.10","askSz":"1.3","ts":"1778630400000"}]}"#;
