        let bitget_default_scope_raw = r#"{"action":"snapshot","arg":{"instType":"SPOT","channel":"ticker","instId":"default"},"data":[{"instId":"ETHUSDT","bidPr":"51.00","bidSz":"1.2","askPr":"51.10","askSz":"1.3","ts":"1778630400000"}]}"#;
