        let bitget_metadata_only_raw = r#"{"action":"snapshot","arg":{"instType":"SPOT","channel":"ticker","instId":"BTCUSDT"},"data":[{"instId":"BTCUSDT","ts":"1778630400000","change24h":"0.01"}]}"#;
