    #[test]
    fn binance_wss_monitor_snapshot_exposes_health_quote_and_counters() {
        let mut snapshot = PublicTopOfBookMonitorSnapshot::empty(
            "BTCUSDT",
            BinancePublicMarket::Spot,
            "wss://example.test/ws/btcusdt@bookTicker",
        );
        snapshot.latest_quote = Some(PublicTopOfBookQuoteSnapshot {
            symbol: "BTCUSDT".to_owned(),
            venue_id: "venue:BINANCE-SPOT".to_owned(),
            instrument_id: "inst:BINANCE:BTCUSDT:SPOT".to_owned(),
            best_bid: Some("100.01".to_owned()),
            best_ask: Some("100.02".to_owned()),
            bid_size: Some("1.2".to_owned()),
            ask_size: Some("1.3".to_owned()),
            source_sequence: Some("42".to_owned()),
            source_event_id: Some("binance:wss:spot:BTCUSDT:42".to_owned()),
            observed_at: "2026-05-13T00:00:00.000000000Z".to_owned(),
            ingested_at: "2026-05-13T00:00:00.000000000Z".to_owned(),
            freshness_status: "Fresh".to_owned(),
        });
        snapshot.wss_update_count = 1;
        snapshot.record_failure("forced fail closed for test", true);
        snapshot.begin_rest_rebuild();

        let health = snapshot.health_json();
        let quote = snapshot.quote_json();
        let status = snapshot.to_json();

        assert!(health.contains("\"fail_closed\":true"));
        assert!(health.contains("\"disconnect_count\":1"));
        assert!(health.contains("\"rest_rebuild_count\":1"));
        assert!(health.contains("\"wss_update_count\":0"));
        assert!(health.contains("\"status\":\"fail_closed\""));
        assert!(health.contains("\"stream_status\":\"rebuilding\""));
        assert!(quote.contains("\"latest_quote\":null"));
        assert!(status.contains("\"last_error\":\"forced fail closed for test\""));
    }

    #[test]
    fn public_wss_disconnect_after_stream_is_reconnecting_not_offline() {
        let mut snapshot = PublicTopOfBookMonitorSnapshot::empty(
            "BTCUSDT",
            BinancePublicMarket::Spot,
            "wss://example.test/ws/btcusdt@bookTicker",
        );
        snapshot.total_rows = 1;
        snapshot.wss_update_count = 42;

        snapshot.record_wss_read_error("connection reset", true);

        let health = snapshot.health_json();
        let status = snapshot.to_json();
        assert!(health.contains("\"fail_closed\":false"));
        assert!(health.contains("\"disconnect_count\":1"));
        assert!(health.contains("\"status\":\"streaming\""));
        assert!(health.contains("\"stream_status\":\"reconnecting\""));
        assert!(status.contains("\"status\":\"streaming\""));
        assert!(status.contains("\"stream_status\":\"reconnecting\""));
        assert!(status.contains("\"last_error\":\"connection reset\""));

        snapshot.record_wss_read_error("subscribe failed", false);

        let failed_health = snapshot.health_json();
        assert!(failed_health.contains("\"fail_closed\":true"));
        assert!(failed_health.contains("\"disconnect_count\":2"));
    }

    #[test]
    fn public_wss_monitor_row_stale_keeps_global_streaming_status() {
        let observed_at = UtcTimestamp::from_str("2026-05-13T00:00:00Z").expect("observed at");
        let ingested_at = UtcTimestamp::from_str("2026-05-13T00:00:06Z").expect("ingested at");
        let venue_id = VenueId::new(BYBIT_BASIS_PERP_VENUE_ID).expect("venue id");
        let instrument_id =
            InstrumentId::new(BYBIT_BASIS_PERP_INSTRUMENT_ID).expect("instrument id");
        let mut coordinator = RestWssMarketDataCoordinator::new(
            venue_id.clone(),
            instrument_id.clone(),
            observed_at,
            MARKET_DATA_MAX_AGE_MS,
        )
        .expect("coordinator");
        let rest_quote = MarketQuote {
            venue_id: venue_id.clone(),
            instrument_id: instrument_id.clone(),
            last_price: None,
            best_bid: Some(Price::from_str("100.00").expect("rest bid")),
            best_ask: Some(Price::from_str("100.10").expect("rest ask")),
            mark_price: None,
            index_price: None,
            bid_size: Some(Quantity::from_str("1.0").expect("rest bid size")),
            ask_size: Some(Quantity::from_str("1.0").expect("rest ask size")),
            source_sequence: Some("rest".to_owned()),
            source_event_id: Some("test:rest".to_owned()),
            freshness: DataFreshness::new(observed_at, observed_at, MARKET_DATA_MAX_AGE_MS)
                .expect("rest freshness"),
        };
        coordinator
            .apply(HybridMarketDataInput::RestSnapshot { quote: rest_quote })
            .expect("rest snapshot");
        let update = coordinator
            .apply(HybridMarketDataInput::WssQuote {
                update: WssQuoteUpdate {
                    venue_id,
                    instrument_id,
                    last_price: None,
                    best_bid: Some(Price::from_str("100.01").expect("bid")),
                    best_ask: Some(Price::from_str("100.11").expect("ask")),
                    mark_price: None,
                    index_price: None,
                    bid_size: Some(Quantity::from_str("1.1").expect("bid size")),
                    ask_size: Some(Quantity::from_str("1.2").expect("ask size")),
                    source_sequence: 1,
                    source_event_id: Some("test:wss:stale".to_owned()),
                    observed_at,
                    ingested_at,
                },
            })
            .expect("stale wss update");
        assert!(update.fail_closed);
        assert!(update.reason_codes.iter().any(|code| code == "DATA_STALE"));

        let mut snapshot = PublicTopOfBookMonitorSnapshot::empty_with_market(
            "ALL_USDT",
            BybitPublicMarket::LinearPerpetual.as_str(),
            BYBIT_LINEAR_PUBLIC_WSS_BASE_URL,
        );
        snapshot.record_update_with_symbol(&update, Some("BTCUSDT"));

        assert_eq!(snapshot.status, "streaming");
        assert!(!snapshot.fail_closed);
        assert_eq!(snapshot.fail_closed_count, 1);
        assert_eq!(snapshot.last_error, None);
        assert_eq!(
            snapshot
                .latest_quote
                .as_ref()
                .map(|quote| quote.freshness_status.as_str()),
            Some("Stale")
        );
    }

