    #[test]
    fn funding_arb_monitor_uses_order_book_depth_levels_for_liquidity() {
        let binance_status = r#"{"status":"healthy","updated_at":"2026-05-13T00:00:00Z","rows":[{"symbol":"BTCUSDT","perp_bid":"99.95","perp_ask":"100.00","perp_bid_qty":"0.5","perp_ask_qty":"0.5","perp_bid_depth_levels":[{"price":"99.95","size":"0.5"},{"price":"99.80","size":"1.0"}],"perp_ask_depth_levels":[{"price":"100.00","size":"0.5"},{"price":"100.25","size":"1.0"}],"mark_price":"100.00","index_price":"100.00","last_funding_rate":"0.00010000","next_funding_time_ms":"1778659200000","source_status":"complete"}]}"#;
        let bybit_status = r#"{"status":"healthy","updated_at":"2026-05-13T00:00:00Z","rows":[{"symbol":"BTCUSDT","perp_bid":"100.05","perp_ask":"100.10","perp_bid_qty":"0.5","perp_ask_qty":"0.5","perp_bid_depth_levels":[{"price":"100.05","size":"0.5"},{"price":"99.95","size":"1.0"}],"perp_ask_depth_levels":[{"price":"100.10","size":"0.5"},{"price":"100.30","size":"1.0"}],"mark_price":"100.05","index_price":"100.00","last_funding_rate":"0.00600000","next_funding_time_ms":"1778659200000","source_status":"complete"}]}"#;
        let binance = funding_arb_test_venue_snapshot("binance", binance_status);
        let bybit = funding_arb_test_venue_snapshot("bybit", bybit_status);
        let options = FundingArbMonitorOptions {
            sources: vec![
                FundingArbVenueSource {
                    venue_family: "binance".to_owned(),
                    status_url: "http://127.0.0.1/binance/status".to_owned(),
                },
                FundingArbVenueSource {
                    venue_family: "bybit".to_owned(),
                    status_url: "http://127.0.0.1/bybit/status".to_owned(),
                },
            ],
            ..FundingArbMonitorOptions::default()
        };

        let snapshot =
            build_funding_arb_monitor_snapshot_from_sources(vec![binance, bybit], vec![], &options)
                .expect("funding arb snapshot");

        assert_eq!(snapshot.candidate_count, 1);
        let row = &snapshot.rows[0];
        assert_eq!(row.long_venue_family.as_deref(), Some("binance"));
        assert_eq!(row.short_venue_family.as_deref(), Some("bybit"));
        assert!(row.reason.is_none());
        assert_eq!(row.venue_a_ask_depth.len(), 2);
        assert_eq!(row.venue_b_bid_depth.len(), 2);
        assert!(row.to_json().contains("venue_a_ask_depth_levels"));

        let spec =
            CrossExchangeFundingArbPipelineSpec::binance_bybit_btcusdt().expect("funding spec");
        let events = funding_arb_monitor_snapshot_candidate_events(
            &spec,
            &snapshot,
            UtcTimestamp::from_str("2026-05-13T00:00:00Z").expect("time"),
        )
        .expect("funding candidate events");
        let first_event = events.first().expect("book event");
        assert!(matches!(
            first_event.payload.get("ask_depth_levels"),
            Some(JsonValue::Array(levels)) if levels.len() == 2
        ));
    }

    #[test]
    fn funding_arb_depth_backfill_can_promote_top_of_book_depth_rejection() {
        let binance = funding_arb_test_venue_snapshot(
            "binance",
            &funding_arb_basis_status_json(
                "BTCUSDT",
                "0.00010000",
                "complete",
                Some("0.5"),
                Some("0.5"),
            ),
        );
        let bybit = funding_arb_test_venue_snapshot(
            "bybit",
            &funding_arb_basis_status_json(
                "BTCUSDT",
                "0.00600000",
                "complete",
                Some("0.5"),
                Some("0.5"),
            ),
        );
        let options = FundingArbMonitorOptions {
            sources: vec![
                FundingArbVenueSource {
                    venue_family: "binance".to_owned(),
                    status_url: "http://127.0.0.1/binance/status".to_owned(),
                },
                FundingArbVenueSource {
                    venue_family: "bybit".to_owned(),
                    status_url: "http://127.0.0.1/bybit/status".to_owned(),
                },
            ],
            ..FundingArbMonitorOptions::default()
        };
        let snapshot =
            build_funding_arb_monitor_snapshot_from_sources(vec![binance, bybit], vec![], &options)
                .expect("funding arb snapshot");
        assert_eq!(snapshot.candidate_count, 0);
        assert!(snapshot.rows[0]
            .reason
            .as_deref()
            .is_some_and(|reason| reason.contains("insufficient order-book depth")));

        let (requests, target_pair_ids, warnings) =
            funding_arb_depth_backfill_requests(&snapshot.rows, 1);
        assert!(warnings.is_empty());
        assert!(target_pair_ids.contains("binance:bybit:BTCUSDT:BTCUSDT"));
        assert!(requests.binance.contains("BTCUSDT"));
        assert!(requests.bybit.contains("BTCUSDT"));

        let mut depths = FundingArbDepthBackfillMaps::default();
        depths.binance.insert(
            "BTCUSDT".to_owned(),
            PublicOrderBookDepth {
                bid_depth: vec![
                    SignalDepthLevel {
                        price: "99.95".to_owned(),
                        size: "0.5".to_owned(),
                    },
                    SignalDepthLevel {
                        price: "99.90".to_owned(),
                        size: "0.6".to_owned(),
                    },
                ],
                ask_depth: vec![
                    SignalDepthLevel {
                        price: "100.00".to_owned(),
                        size: "0.5".to_owned(),
                    },
                    SignalDepthLevel {
                        price: "100.02".to_owned(),
                        size: "0.6".to_owned(),
                    },
                ],
            },
        );
        depths.bybit.insert(
            "BTCUSDT".to_owned(),
            PublicOrderBookDepth {
                bid_depth: vec![
                    SignalDepthLevel {
                        price: "100.05".to_owned(),
                        size: "0.5".to_owned(),
                    },
                    SignalDepthLevel {
                        price: "100.03".to_owned(),
                        size: "0.6".to_owned(),
                    },
                ],
                ask_depth: vec![
                    SignalDepthLevel {
                        price: "100.10".to_owned(),
                        size: "0.5".to_owned(),
                    },
                    SignalDepthLevel {
                        price: "100.12".to_owned(),
                        size: "0.6".to_owned(),
                    },
                ],
            },
        );

        let backfilled =
            funding_arb_row_with_backfilled_depth(&snapshot.rows[0], &depths, &options)
                .expect("backfilled row");
        assert!(backfilled.is_candidate, "{:?}", backfilled.reason);
        assert_eq!(backfilled.venue_a_ask_depth.len(), 2);
        assert_eq!(backfilled.venue_b_bid_depth.len(), 2);
        assert!(backfilled.reason.is_none());
    }

    #[test]
    fn funding_arb_depth_backfill_warnings_do_not_create_source_errors() {
        let row = funding_arb_test_row("0.00010000", "0.00600000");
        let mut snapshot =
            funding_arb_test_snapshot(vec![row.clone()], "2026-05-13T00:00:00Z".to_owned());

        append_funding_arb_depth_backfill_warnings(
            &mut snapshot,
            vec!["funding arb depth backfill: OKX depth unavailable".to_owned()],
        );

        assert_eq!(snapshot.source_error_count, 0);
        assert_eq!(snapshot.last_error, None);
        assert!(funding_arb_monitor_root_blocking_path(&snapshot)
            .iter()
            .all(|entry| entry.blocker != "source_error_count>0"));

        snapshot.source_error_count = 1;
        snapshot.status = "degraded".to_owned();
        append_funding_arb_depth_backfill_warnings(
            &mut snapshot,
            vec!["funding arb depth backfill: Bybit depth unavailable".to_owned()],
        );

        assert!(snapshot
            .last_error
            .as_deref()
            .is_some_and(|error| error.contains("Bybit depth unavailable")));
        assert_eq!(
            funding_arb_monitor_root_blocking_path(&snapshot)
                .first()
                .map(|entry| entry.blocker.as_str()),
            Some("source_error_count>0")
        );

        let mut last_error_snapshot =
            funding_arb_test_snapshot(vec![row], "2026-05-13T00:00:00Z".to_owned());
        last_error_snapshot.last_error = Some("poll warning".to_owned());
        assert_eq!(
            funding_arb_monitor_root_blocking_path(&last_error_snapshot)
                .first()
                .map(|entry| entry.blocker.as_str()),
            Some("last_error_present")
        );
    }

