    #[cfg(feature = "live-exec")]
    #[test]
    fn resident_entry_cycle_retries_readonly_market_data_errors() {
        let market_data = RuntimeError::LiveMarketData {
            message: "Public WSS monitor status is fail_closed, not streaming".to_owned(),
        };
        let public_rest = RuntimeError::LiveMarketData {
            message:
                "public market data GET failed after 3 attempts: curl returned exit status: 28"
                    .to_owned(),
        };
        let invalid_top_of_book = RuntimeError::LiveMarketData {
            message: "top-of-book prices must be greater than zero".to_owned(),
        };
        let okx_rate_limit = RuntimeError::LiveMarketData {
            message: "OKX returned code=50011, msg=Rate limit reached. Please refer to API documentation and throttle requests accordingly.".to_owned(),
        };
        let private_timestamp_skew = RuntimeError::Module {
            module: "arb-venue-data",
            message: "venue data query field `freshness.ingested_at` is invalid: ingested timestamp must be greater than or equal to observed timestamp".to_owned(),
        };
        let stale_funding_arb_candidate = RuntimeError::Module {
            module: "arb-runtime",
            message: "funding arb monitor row is not a candidate: forward=net_funding_bps=-4.37885 below minimum 5; reverse=insufficient order-book depth".to_owned(),
        };
        let private_http = RuntimeError::LiveMarketData {
            message: "curl failed before a reliable Bitget private HTTP response was available"
                .to_owned(),
        };
        let unsafe_config = RuntimeError::UnsafeConfig {
            message: "invalid live signing config".to_owned(),
        };
        let unsafe_leverage_config = RuntimeError::UnsafeConfig {
            message: "target_leverage cannot be applied to spot market".to_owned(),
        };
        let venue_exec_config = RuntimeError::Module {
            module: "arb-venue-exec",
            message: "invalid mutable execution request: target_leverage cannot be applied to spot"
                .to_owned(),
        };

        assert!(resident_entry_cycle_error_can_retry(&market_data));
        assert!(resident_entry_cycle_error_can_retry(&public_rest));
        assert!(resident_entry_cycle_error_can_retry(&invalid_top_of_book));
        assert!(resident_entry_cycle_error_can_retry(&okx_rate_limit));
        assert!(resident_entry_cycle_error_can_retry(
            &private_timestamp_skew
        ));
        assert!(resident_entry_cycle_error_can_retry(
            &stale_funding_arb_candidate
        ));
        assert_eq!(
            resident_retryable_error_class(&stale_funding_arb_candidate),
            "stale_funding_arb_candidate"
        );
        assert!(!resident_entry_cycle_error_can_retry(&private_http));
        assert!(!resident_entry_cycle_error_can_retry(&unsafe_config));
        assert!(!resident_entry_cycle_error_can_isolate_venue(
            &unsafe_config
        ));
        assert!(resident_entry_cycle_error_can_isolate_venue(
            &unsafe_leverage_config
        ));
        assert!(resident_entry_cycle_error_can_isolate_venue(
            &venue_exec_config
        ));
        assert!(!resident_entry_cycle_error_can_isolate_venue(&private_http));
        assert_eq!(
            resident_retryable_error_class(&market_data),
            "wss_monitor_unavailable"
        );
        assert_eq!(
            resident_retryable_error_class(&public_rest),
            "public_rest_unavailable"
        );
        assert_eq!(
            resident_retryable_error_class(&private_timestamp_skew),
            "private_snapshot_timestamp_skew"
        );
        assert_eq!(
            resident_retryable_error_class(&private_http),
            "non_retryable"
        );
    }

