    #[cfg(feature = "live-exec")]
    #[test]
    fn append_jsonl_rotation_moves_current_file_and_keeps_limit() {
        let temp = RuntimeTempDir::new().expect("tempdir");
        let path = temp.path().join("resident_live_events.jsonl");
        let first = rotated_append_jsonl_path(&path, 1);
        let second = rotated_append_jsonl_path(&path, 2);

        write_utf8(path.clone(), "line-one\n").expect("write current");
        write_utf8(first.clone(), "line-old\n").expect("write first");
        write_utf8(second.clone(), "line-drop\n").expect("write second");

        rotate_append_jsonl_if_needed_with_limits(&path, 4, 2).expect("rotate");

        assert!(!path.exists());
        assert_eq!(read_utf8(&first).expect("read first rotated"), "line-one\n");
        assert_eq!(
            read_utf8(&second).expect("read second rotated"),
            "line-old\n"
        );

        append_line_to_jsonl(path.clone(), "{\"event\":\"new\"}").expect("append new current");
        assert_eq!(
            read_utf8(&path).expect("read current"),
            "{\"event\":\"new\"}\n"
        );
    }

    #[cfg(feature = "live-exec")]
    #[test]
    fn append_jsonl_rotation_accounts_for_pending_line_bytes() {
        let temp = RuntimeTempDir::new().expect("tempdir");
        let path = temp.path().join("resident_live_events.jsonl");
        let first = rotated_append_jsonl_path(&path, 1);

        write_utf8(path.clone(), "1234567\n").expect("write current");

        rotate_append_jsonl_for_pending_line_with_limits(&path, 3, 10, 2).expect("rotate");

        assert!(!path.exists());
        assert_eq!(read_utf8(&first).expect("read first rotated"), "1234567\n");
    }

    #[cfg(all(feature = "live-exec", unix))]
    #[test]
    fn private_curl_failure_message_reports_status_code_and_stderr() {
        use std::os::unix::process::ExitStatusExt;

        let output = std::process::Output {
            status: std::process::ExitStatus::from_raw(28 << 8),
            stdout: b"\n__ARB_BITGET_HTTP_STATUS__:000".to_vec(),
            stderr: b"curl: (28) Operation timed out after 30000 milliseconds".to_vec(),
        };

        let message =
            private_curl_failure_message("Bitget", "\n__ARB_BITGET_HTTP_STATUS__:", &output);

        assert!(message.starts_with(
            "curl failed before a reliable Bitget private HTTP response was available"
        ));
        assert!(message.contains("curl_status="));
        assert!(message.contains("http_code=000"));
        assert!(message.contains("stderr=curl: (28) Operation timed out"));
    }

    #[cfg(all(feature = "live-exec", unix))]
    #[test]
    fn private_curl_retry_classification_includes_tls_transport_failures() {
        use std::os::unix::process::ExitStatusExt;

        let tls_failure = std::process::Output {
            status: std::process::ExitStatus::from_raw(35 << 8),
            stdout: b"\n__ARB_BYBIT_HTTP_STATUS__:000".to_vec(),
            stderr: b"curl: (35) LibreSSL SSL_connect: SSL_ERROR_SYSCALL".to_vec(),
        };
        let config_failure = std::process::Output {
            status: std::process::ExitStatus::from_raw(3 << 8),
            stdout: Vec::new(),
            stderr: b"curl: (3) URL rejected".to_vec(),
        };

        assert!(private_curl_output_can_retry(&tls_failure));
        assert!(!private_curl_output_can_retry(&config_failure));
    }

