    #[test]
    fn binance_basis_monitor_snapshot_reports_missing_spot_without_failing_open() {
        let spot = r#"[]"#;
        let perp = r#"[
          {"symbol":"BTCUSDT","bidPrice":"101.00","bidQty":"1.5","askPrice":"101.10","askQty":"2.5","time":1778584221117}
        ]"#;
        let premium = r#"[
          {"symbol":"BTCUSDT","markPrice":"101.00","indexPrice":"100.00","lastFundingRate":"0.00010000","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000}
        ]"#;
        let options = BinanceBasisMonitorOptions {
            once: true,
            ..BinanceBasisMonitorOptions::default()
        };

        let snapshot =
            build_binance_basis_monitor_snapshot_from_json(spot, perp, premium, &options)
                .expect("snapshot");

        assert_eq!(snapshot.total_rows, 1);
        assert_eq!(snapshot.candidate_count, 0);
        assert_eq!(snapshot.missing_spot_count, 1);
        assert_eq!(snapshot.rows[0].source_status, "missing_spot");
        assert_eq!(
            snapshot.rows[0].reason.as_deref(),
            Some("MISSING_SPOT_BOOK_TICKER")
        );
        let status_json = snapshot.to_json();
        assert!(status_json.contains("\"blocking_path\""));
        assert!(status_json.contains("candidate_count=0"));
        assert!(status_json.contains("现货 top-of-book 缺失"));
        let opportunities_json = snapshot.opportunities_json();
        assert!(opportunities_json.contains("\"blocking_path\""));
        assert!(opportunities_json.contains("\"rows\":[]"));
        assert!(opportunities_json.contains("MISSING_SPOT_BOOK_TICKER"));
    }

    #[test]
    fn aster_basis_monitor_snapshot_scans_all_symbols_and_filters_tiny_funding() {
        let spot = r#"[
          {"symbol":"BTCUSDT","bidPrice":"99.90","bidQty":"1.0","askPrice":"100.00","askQty":"2.0","time":1778584221117},
          {"symbol":"ETHUSDT","bidPrice":"49.90","bidQty":"3.0","askPrice":"50.00","askQty":"4.0","time":1778584221117},
          {"symbol":"TESTUSDT","bidPrice":"1.00","bidQty":"1.0","askPrice":"1.01","askQty":"1.0","time":1778584221117}
        ]"#;
        let perp = r#"[
          {"symbol":"BTCUSDT","bidPrice":"101.00","bidQty":"1.5","askPrice":"101.10","askQty":"2.5","time":1778584221117},
          {"symbol":"ETHUSDT","bidPrice":"50.10","bidQty":"3.5","askPrice":"50.20","askQty":"4.5","time":1778584221117},
          {"symbol":"TESTUSDT","bidPrice":"2.00","bidQty":"1.0","askPrice":"2.01","askQty":"1.0","time":1778584221117}
        ]"#;
        let premium = r#"[
          {"symbol":"BTCUSDT","markPrice":"101.00","indexPrice":"100.00","lastFundingRate":"0.00010000","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000},
          {"symbol":"ETHUSDT","markPrice":"50.10","indexPrice":"50.00","lastFundingRate":"0.00000001","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000},
          {"symbol":"TESTUSDT","markPrice":"2.00","indexPrice":"1.00","lastFundingRate":"0.01000000","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000}
        ]"#;
        let options = AsterBasisMonitorOptions {
            min_abs_funding_rate: "0.00000100".to_owned(),
            once: true,
            ..AsterBasisMonitorOptions::default()
        };

        let snapshot = build_aster_basis_monitor_snapshot_from_json(spot, perp, premium, &options)
            .expect("snapshot");

        assert_eq!(snapshot.total_rows, 1);
        assert_eq!(snapshot.filtered_funding_count, 1);
        assert_eq!(snapshot.candidate_count, 0);
        assert_eq!(snapshot.rows[0].symbol, "BTCUSDT");
        assert_eq!(snapshot.rows[0].source_status, "complete");
        assert_eq!(
            snapshot.rows[0].reason.as_deref(),
            Some("ASTER_SPOT_PERP_BASIS_DRY_RUN_NOT_SUPPORTED")
        );
        assert_eq!(snapshot.rows[0].net_basis_bps.as_deref(), None);
        assert!(!snapshot.rows[0].is_candidate);
        let status_json = snapshot.to_json();
        assert!(status_json.contains("dry-run/execution profile 未启用"));
        assert!(status_json.contains("完整行情行按 fail closed"));
    }

    #[test]
    fn aster_basis_monitor_uses_funding_info_symbol_intervals() {
        let spot = r#"[
          {"symbol":"PRLUSDT","bidPrice":"0.1000","bidQty":"1000","askPrice":"0.1010","askQty":"1000","time":1778584221117},
          {"symbol":"BLESSUSDT","bidPrice":"0.2000","bidQty":"1000","askPrice":"0.2010","askQty":"1000","time":1778584221117}
        ]"#;
        let perp = r#"[
          {"symbol":"PRLUSDT","bidPrice":"0.1020","bidQty":"1000","askPrice":"0.1030","askQty":"1000","time":1778584221117},
          {"symbol":"BLESSUSDT","bidPrice":"0.2020","bidQty":"1000","askPrice":"0.2030","askQty":"1000","time":1778584221117}
        ]"#;
        let premium = r#"[
          {"symbol":"PRLUSDT","markPrice":"0.1020","indexPrice":"0.1000","lastFundingRate":"-0.00041200","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000},
          {"symbol":"BLESSUSDT","markPrice":"0.2020","indexPrice":"0.2000","lastFundingRate":"0.00005000","interestRate":"0.00010000","nextFundingTime":1778601600000,"time":1778584220000}
        ]"#;
        let funding_info = r#"[
          {"symbol":"PRLUSDT","fundingIntervalHours":1},
          {"symbol":"BLESSUSDT","fundingIntervalHours":4}
        ]"#;
        let options = AsterBasisMonitorOptions {
            min_abs_funding_rate: "0".to_owned(),
            once: true,
            ..AsterBasisMonitorOptions::default()
        };

        let snapshot = build_aster_basis_monitor_snapshot_from_optional_spot_json_with_depth(
            Some(spot),
            perp,
            premium,
            Some(funding_info),
            &options,
            &BTreeMap::new(),
            &BTreeMap::new(),
            Vec::new(),
        )
        .expect("snapshot");

        let prl = snapshot
            .rows
            .iter()
            .find(|row| row.symbol == "PRLUSDT")
            .expect("PRL row");
        let bless = snapshot
            .rows
            .iter()
            .find(|row| row.symbol == "BLESSUSDT")
            .expect("BLESS row");
        assert_eq!(prl.funding_interval_hours, "1");
        assert_eq!(bless.funding_interval_hours, "4");
    }

